INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (1, 28, 27, 'パーカッショニスト', 'パーカッショニストは、打楽器の演奏を専門とする音楽家です。彼らは様々な種類の打楽器を駆使してリズムを生み出し、音楽の中で重要な役割を果たします。主にオーケストラ、バンド、ソロでの演奏活動を行い、ドラマーと同様にライブパフォーマンスや録音セッションでも活躍します。音楽のジャンルによって使用する楽器の種類が変わるため、幅広い音楽的知識と技術が求められます。さらに、リズム感覚や協調性も重要な要素となります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (2, 28, 27, 'サックスプレイヤー', 'サックスプレイヤーは、サクソフォンを演奏する音楽家です。サクソフォンはジャズ、クラシック、ポップスなど様々な音楽ジャンルで重要な役割を果たす楽器です。サックスプレイヤーは技術的な演奏能力だけでなく、音楽の表現力や創造性を高めるための感性も必要とされます。演奏活動はソロやバンドの一員として行われることが多く、音楽イベントや録音スタジオでの活動も含まれます。また、教職として音楽教育に携わることもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (3, 28, 27, 'トランペッター', 'トランペッターは主にトランペットという金管楽器を演奏する音楽家です。クラシック音楽、ジャズ、ポップス、オーケストラやバンドなど、さまざまな音楽ジャンルとサウンドにおいて重要な役割を果たします。演奏のみならず楽譜の読解や音楽理論への理解も必要です。また、演奏技術の向上には日々の練習が不可欠です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (4, 28, 26, '校正者', '校正者は、文章や出版物に含まれる誤字脱字や文法ミス、レイアウトの不備などをチェックし、修正する職業です。印刷前の最終確認として重要な役割を果たし、文書の質を高めるために注意深く作業を行います。語学能力が求められることが多く、細部へのこだわりや集中力も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (5, 28, 37, 'ミュージカル俳優', 'ミュージカル俳優は、舞台上で歌、ダンス、演技を通して物語を表現するアーティストです。彼らは通常、多様なスキルセット、特に声楽、ダンス、演技の技術を必要とし、複雑な舞台パフォーマンスをこなします。ミュージカル俳優は劇場での公演を主要な活動の場としており、リハーサルや公演のために長時間の練習やトレーニングが求められます。観客に感情を伝える能力が重要で、表現力豊かなパフォーマンスを披露することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (6, 30, 37, 'スポーツ審判員', 'スポーツ審判員は、競技のルールを監督し、公正な試合運営を確保する役割を担っています。彼らは試合の進行中にルール違反を判定し、必要に応じてペナルティを課します。審判員は特定のスポーツに特化しており、そのスポーツの規則や流れに精通しています。正確な判断力と高い集中力が求められ、多くの場合、試合の結果に直接影響を与えるため、公正さと誠実さが重要な特性です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (7, 29, 27, 'ディスプレイデザイナー', 'ディスプレイデザイナーは、商品の魅力を引き立てるために店舗や展示会などの空間をデザインする職業です。彼らは商品プレゼンテーションの方法を考え、店舗のディスプレイやイベントの展示ブースを設計します。この職業には、店舗のテーマに基づいた装飾や照明、レイアウトの構造化が求められます。クリエイティブな視点や細部への注意力、空間デザインに関する知識が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (8, 28, 16, '映画バイヤー', '映画バイヤーは、映画館や配信サービス等のメディアに映画を提供する役割を担います。彼らは世界中の映画祭や市場で映画を選定し、ライセンス交渉を通じてこれらの映画を自社に提供します。映画の選定には、視聴者の好み、市場のトレンド、費用対効果など様々な要素が考慮されます。プロモーションやマーケティングの戦略立案にも関与することがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (9, 28, 18, '舞台機構調整技能士', '舞台機構調整技能士は、コンサートホールや劇場、テレビスタジオなどで使用される舞台装置の設置、操作、保守を行う専門職です。具体的な仕事には、照明機材の設置や調整、舞台装置の組み立て、音響機器の操作、舞台設備のメンテナンスが含まれます。この職業は、舞台芸術やイベントの成功に欠かせない重要な役割を果たします。技術的な知識と実務経験が求められ、問題発生時の迅速な対応能力も必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (10, 28, 27, 'ローディー', 'ローディーとは、音楽業界で楽器や音響機材の運搬、設置、調整などを行うサポートスタッフのことです。バンドやアーティストのコンサートやツアーに同行し、ステージの準備や撤収、機材の保守管理などを担当します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (11, 28, 7, 'マニピュレーター', 'マニピュレーターは、特定の専門知識を持ち、その知識を利用して他者の行動や信念を巧妙に操る人物を指します。一般的には、心理学やコミュニケーションに関する深い理解が求められます。実務には、交渉、広告、政治戦略などの分野が含まれることがありますが、倫理的な問題を伴うこともあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (12, 28, 37, 'ニュースキャスター', 'ニュースキャスターとは、テレビやラジオのニュース番組でニュースを伝える役割を担うアナウンサーのことです。ニュースの原稿を読み上げるだけでなく、時には現場からのリポートやインタビューも行います。発音や表現力が求められ、正確で迅速なニュース報道が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (13, 28, 27, 'ボーカリスト', 'ボーカリストは、音楽の歌唱部分を担当する職業です。主に楽曲やライブパフォーマンスでの歌唱を通じて、聴衆に感動を与える役割を担います。歌唱技術だけでなく、表現力やパフォーマンススキルも必要です。自身の声を楽器として使い、ジャンルに応じた様々なスタイルでの歌唱が求められます。スタジオでの録音やステージでの演奏など、活動の場は多岐にわたります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (14, 28, 26, '小説家', '小説家はフィクションの書き手で、自分の想像力や創造力を駆使して物語を作り上げます。作品は長編小説から短編集、あるいはジャンル小説や文学小説まで多岐にわたります。ユニークなアイデアを形にして、言葉を選び、テーマやキャラクターを巧みに描き出す力が求められます。また、出版社とのやりとりや出版プロセスへの理解も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (15, 35, 32, 'メイクセラピスト', 'メイクセラピストは、美容と心理学を組み合わせた専門職で、化粧やメイクアップを通じて顧客の心と体を整え、リフレッシュさせることを目的としています。メイクセラピストは、化粧品やスキンケア商品の使用方法を顧客に説明しながら、外見の変化を通じて心理的な安定感と自信を提供します。また、顧客の悩みやストレスを聴き、それに合ったメイクアップのアドバイスを行うことで、内面的な悩みの解消も目指します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (16, 28, 15, 'アシスタントテレビディレクター', 'アシスタントテレビディレクターは、テレビ番組の製作に関わるディレクターを補佐する役割を担います。具体的な業務内容には、撮影日のスケジュール管理、撮影現場での機材やセットアップの準備、出演者やスタッフとの調整、台本の管理などがあります。アシスタントの役割は多岐にわたり、チーム内で効率的にコミュニケーションを取りながら、番組制作をスムーズに進める重要なポジションです。クリエイティブな感性と柔軟な対応力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (17, 28, 27, 'テレビディレクター', 'テレビディレクターは、テレビ番組の制作において指揮を執る役割を担い、番組のコンセプト開発、脚本作成、撮影計画の策定、キャストやスタッフの選定、撮影および編集など、全体のプロセスを管理し、番組の完成に導く仕事です。クリエイティブなビジョンを具現化し、視聴者に届けるための責任を持ちます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (18, 28, 26, '編集者', '編集者とは、書籍、雑誌、ウェブコンテンツなどの情報媒体の内容を企画し、執筆、校正、及び出版に関与する専門職です。編集者は記事のテーマを決定し、ライターやデザイナーと協力してコンテンツを作り上げます。また、原稿のチェックや修正、事実確認を行い、読者にとって魅力的で正確な情報を提供する役割を担います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (19, 29, 27, 'フラワーデザイナー', 'フラワーデザイナーは、花や植物を使って美しいアレンジメントやデザインを作成する専門職です。結婚式、イベント、葬儀、店舗装飾など様々なシーンで活躍します。色彩センスや創造力、植物に関する知識が求められ、顧客の要望に応じたカスタムメイドのデザインを提供します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (20, 30, 37, 'プロ野球選手', 'プロ野球選手とは、野球が職業であるアスリートのことで、プロの野球リーグでチームに所属し、公式試合でプレーします。彼らはトレーニングや試合を通じて身体能力を高め、他の選手と競い合います。プロ野球選手は、試合のパフォーマンスや人気に応じて給与や契約が異なり、日本の場合、NPB（日本野球機構）においてプレーすることが主流です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (21, 18, 17, 'ゲームクリエイター', 'ゲームクリエイターは、ゲームの企画や開発、設計を行う職業です。ストーリーの構築、キャラクターデザイン、ゲームメカニクスの設定、ビジュアルや音楽の選択など、ゲームの全体的なコンセプトを形作る役割を担います。プログラマーやデザイナー、プロデューサーと連携してプロジェクトを推進し、プレイヤーに楽しさを提供することを目指します。技術的な知識に加え、クリエイティブな感性やチームでのコミュニケーション能力が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (22, 28, 26, '漫画原作者', '漫画原作者は、漫画のストーリーやキャラクターを考案し、台詞やシーンを作成する職業です。漫画家と組んで作品を制作することが一般的で、マンガの土台となるプロットやシナリオを提供します。ストーリー性だけでなく、キャラクターの個性や関係性、物語のテーマなど幅広い要素を考慮しながら、読者を引き込む魅力あるコンテンツを生み出す役割を担います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (23, 5, 27, 'ファッションデザイナー', 'ファッションデザイナーは、衣服やアクセサリーのデザインを行う職業です。市場のトレンドを研究し、コンセプトやアイデアを練り、それを具体的なデザインとして描き出します。さらに、生地の選定やサンプル作成、最終的な製品化に至るまでのプロセスを管理します。クリエイティブなセンスとトレンドの把握が求められる仕事で、しばしばコレクションやショーのために作品を発表します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (24, 28, 26, '童話作家', '童話作家は、子供向けの物語を創作する職業です。主に子供たちの想像力を刺激し、教育的、娯楽的要素を含んだストーリーを書きます。物語は一般的に、動物や空想上のキャラクター、魔法などを登場させ、読み手を魅了する内容になります。創作した作品は、本や絵本として出版されることが多く、作家は出版社と契約を結ぶこともあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (25, 29, 27, '書道家', '書道家は、書道の技術を駆使して作品を創作し、指導や展示などの活動を行う職業です。日本の伝統文化である書道を通じて、美しい文字や表現を追求し、多くの場合、美術館やギャラリーにおいて作品を展示したり、公演やワークショップを通じてその技術を広めたりします。また、書道の歴史や文化に関する知識も必要とされるほか、作品の制作においては独自のスタイルや表現を磨くことが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (26, 12, 21, 'ビデオ組立工', 'ビデオ組立工は、ビデオ機器や関連機器を組み立てる専門職です。作業は、電気部品や機械部品を正確に組み合わせて、機器が正常に作動するように組み立てることに含まれます。この職種には、高度な技術能力と精密さが求められており、時には設計図や技術仕様に基づいて作業を行う必要があります。また、製造ラインでの作業が一般的で、チームで協力して効率よく生産を進めることが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (27, 28, 27, '絵本作家', '絵本作家は、子供を対象とした絵本を企画・執筆・イラストを手掛ける職業です。物語のアイデアを考え、子供にも理解できるようにストーリーを構成し、さらにその物語を視覚的に表現するためにイラストを描くことが求められます。題材の選定、文章の作成、イラストの作成まで一貫して行うことができる、クリエイティブで多才な役割です。市場や対象年齢に応じて、テーマや表現方法を工夫することも必要です。出版に関しては、出版社と連携して作品を完成させる場合が多いです。フリーランスで活動する人もいますし、出版社専属で働く場合もあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (28, 28, 26, '作詞家', '作詞家は、音楽作品の歌詞を創作する職業です。メロディに合わせて詩を作り、リズムや曲のテーマに沿った内容を考える必要があります。詩の内容は感情を伝えたり、物語を構築したりする要素を持つことが多いです。作詞家は、アーティストや音楽プロデューサーと密接に協力し、特定の視聴者の感情に訴えかけるような作品を目指します。クリエイティブで表現力豊かであり、音楽や詩に対する深い理解が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (29, 28, 27, 'レコーディングエンジニア', 'レコーディングエンジニアは、音楽や音声コンテンツを録音・編集する専門職です。音楽スタジオや放送局などで、アーティストや音楽プロデューサーと協力しながら、音源の録音、ミキシング、マスタリングを行います。技術的な知識と優れた音感が求められ、音響機材の操作やソフトウェアの利用に精通していることが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (30, 28, 12, '放送エンジニア', '放送エンジニアは、テレビやラジオの放送局において、音声や映像の送出と管理を担当する職業です。スタジオや制御室での機器の操作、音声・映像のトラブル対応、放送機器のメンテナンスと修理、番組素材の送出準備、そして中継の技術サポートなどを行います。技術の進化に対応するため、新しいシステムや機器の導入、運用方法の改善にも関与します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (31, 28, 27, 'ドラマー', 'ドラマーは音楽のバンドやオーケストラで打楽器を演奏する専門家です。通常はドラムセットを使い、リズムとビートを提供します。他の楽器と協調しながら、音楽のタイミングをキープし、アンサンブルの一貫性を保つ役割があります。ライブパフォーマンスやレコーディングで活躍することが多く、ジャンルによって異なるスタイルや技術が求められます。また、リズムの正確さと独自のパフォーマンススタイルが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (32, 18, 16, 'ゲームディレクター', 'ゲームディレクターは、ゲーム開発プロジェクト全体を指揮する役職です。ゲームのコンセプト作成、デザイン、開発、マーケティング戦略に至るまで、プロジェクトのあらゆる側面に関与します。開発チームを管理し、クリエイティブなビジョンを効果的に具現化する責任があります。プレイヤーの体験を最大化し、プロジェクトを予定通りに完了させるためのリーダーシップが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (33, 28, 26, '詩人', '詩人は、言葉を使って美的または感情的な表現を作り出す職業です。彼らは詩の形式、韻律、リズムを駆使して、個人的な感情や社会的なテーマを伝えます。詩人はしばしば文学誌や自身の作品集を通じて作品を発表し、文学イベントや詩の朗読会に参加することがあります。表現力と創造力が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (34, 28, 16, '音楽プロデューサー', '音楽プロデューサーは、音楽制作のプロジェクトを指揮し、全体の方向性や音の仕上がりを調整する役割を担います。アーティストや作曲家と協力して、楽曲のアレンジ、ミキシング、録音における技術的・創造的な側面を管理します。作品のコンセプトやビジョンの明確化に貢献し、しばしば予算管理やスケジュール調整も行います。音楽業界での経験や広範な知識が求められ、専門的な技術スキルはもちろん、コミュニケーション能力も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (35, 28, 27, '美術スタッフ', '美術スタッフは、映画、テレビドラマ、舞台、イベントなどの制作現場で美術関連の作業を担当します。具体的には、セットデザイン、衣装、照明、小道具などを計画・準備し、撮影や公演がスムーズに行われるようサポートします。芸術的センスや美的感覚が求められ、チームでのコミュニケーション能力も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (36, 28, 15, '映像編集者', '映像編集者は、フィルム、ビデオ、デジタルメディアなどの映像素材を編集して完成品に仕上げる職業です。編集者は、ストーリーテリングを強化するために映像のカット、トランジション、ビジュアルエフェクト、音楽の選択や調整を行います。編集ソフトウェアを使用して、ディレクターやプロデューサーのビジョンを具現化し、映画、テレビ番組、音楽ビデオ、広告など多様なメディアの編集に携わります。映像の構成力とクリエイティブな視点が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (37, 28, 15, '映像カメラマン', '映像カメラマンはテレビや映画、ドキュメンタリー、広告映像などの映像制作で、カメラを操作して撮影を行う専門職です。撮影の技術だけでなく、構図や光の使い方、被写体の動きを捉えるセンスも求められます。また、クライアントやディレクターと協力して、映像作品のビジョンを実現するためのクリエイティブな提案を行うことも重要です。撮影機材や照明機材、編集ソフトウェアなどの技術的な知識も必要とされる職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (38, 30, 1, 'イベントプランナー', 'イベントプランナーは、結婚式や企業の会議、パーティー、セミナー、展示会など、多岐にわたるイベントを企画し、管理する職業です。イベントのテーマ設定や日程調整、予算管理、会場の選定、集客計画など、多くの要素を考慮しながらイベントの成功を目指します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (39, 28, 37, 'アナウンサー', 'アナウンサーは、ラジオやテレビなどのメディアでニュース、スポーツ、エンターテインメントの番組を放送する際に、情報を視聴者や聴取者に伝える役割を果たします。彼らは通常、文章を読み上げたり、インタビューを行ったり、ライブイベントを報道します。アナウンサーは、明瞭かつ説得力のある話し方を持っていることが求められ、視聴者にとってわかりやすく、魅力的なコンテンツを提供することが重要です。また、突発的な出来事やライブ放送にも迅速に対応できる柔軟性と高いコミュニケーション能力が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (40, 28, 26, '放送作家', '放送作家は、ラジオやテレビ番組の企画立案や脚本を手掛ける職業です。番組のコンセプト作成から、トーク番組の台本作成、バラエティ番組のネタ考案など、その役割は多岐にわたります。しばしば、プロデューサーやディレクターと協力して、視聴者を引き込む番組を作り上げる重要なポジションです。創造性とコミュニケーション能力が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (41, 28, 27, 'ベーシスト', 'ベーシストは、主に音楽バンドやオーケストラでベースギターやコントラバスを演奏するミュージシャンです。ベースは音楽のリズムセクションを担当し、他の楽器との調和を図りつつ、曲の骨格を支える重要な役割を果たします。通常、ベーシストはバンドの他のメンバーと協力して演奏し、セッションやライブパフォーマンス、レコーディングにも参加します。ジャンルはロック、ジャズ、ポップ、クラシックなど幅広い音楽スタイルに対応します。プレイヤーによっては即興演奏や作曲、編曲も行います。技術的なスキルだけでなく、他のミュージシャンとのコミュニケーション能力や音楽理論の知識も求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (42, 18, 17, 'ゲームデザイナー', 'ゲームデザイナーは、ビデオゲームのコンセプトを考案し、ゲームプレイ、ルール、ストーリー、キャラクターを設計する役割を担います。現代のゲーム開発には、アイデアの創出からプロトタイプの作成、最終的なゲームのバランス取りまで、多岐にわたる創造的および技術的なスキルが求められます。ゲームデザイナーは、他の開発チームメンバー、特にプログラマーやアーティストと密接に協力し、ビジョンを具体化していきます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (43, 28, 15, 'テレビカメラマン', 'テレビカメラマンは、テレビ番組やニュース、ドキュメンタリー、スポーツイベントなどで使用される映像を撮影する職業です。基本的な業務には、カメラの操作、フレーミング、照明や音声の調整が含まれます。他のスタッフやディレクターと協力して、視聴者に伝えたいストーリーやシーンを効果的に記録する役割を担います。時には素早く要求に応じてアングルや位置を変更する柔軟性も求められます。撮影技術だけでなく、映像を通して伝えたいメッセージや感情を理解し、それを視覚的に表現する能力が重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (44, 28, 27, '作曲家', '作曲家は、音楽作品を作るプロフェッショナルです。彼らは通常、音楽理論、楽器の演奏技術、作曲技法などを使用して新しい音楽を創造します。作曲家はクラシック音楽、ポップス、映画音楽、テレビ番組、ゲーム音楽など、さまざまなジャンルの音楽を手掛けることができます。作曲家は自身で楽曲をプロデュースしたり、他のアーティストやメディアプロジェクトのために楽曲を提供したりすることもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (45, 18, 10, 'サウンドプログラマー', 'サウンドプログラマーは、ビデオゲーム、映画、テレビ、アプリケーションなどで使用される音楽や効果音のプログラミングを担当します。具体的には、音響エンジンの開発、音楽や効果音の実装、リアルタイムでの音声処理、サウンドデザインの技術的な側面を管理します。また、新しい音声技術の開発や、既存のオーディオシステムの最適化も行います。音楽理論やデジタル音響技術、プログラミング言語に関する深い知識が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (46, 18, 16, 'WEBプロデューサー', 'WEBプロデューサーは、WebサイトやWebサービスの企画・制作・運営を総合的に管理する職業です。目的に応じたコンテンツの企画や情報設計、プロジェクトの進行管理、外部との調整、予算管理などを担当し、Webサイトの成功に向けた戦略を立案・実行します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (47, 28, 7, '広告プランナー', '広告プランナーは、広告キャンペーンの企画、戦略立案、実行を担当する職業です。市場調査を行い、ターゲットオーディエンスを定義し、効果的な広告メッセージを設計します。クライアントの目標に基づいて広告予算を管理し、広告媒体の選定や広告の効果測定を行い、キャンペーンの最適化を図ります。クリエイティブチームやメディアバイイング担当者と協力して最適な広告戦略を提供します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (48, 30, 36, '動物園飼育スタッフ', '動物園の飼育スタッフは、動物の世話や健康管理を行う専門職です。彼らの主な任務には、動物に餌を与え、清掃し、健康状態を観察することが含まれます。動物の安全と健康を維持するために、また訪れる人々に動物の情報を提供するため、必要に応じて専門的な知識が求められます。さらに、動物の自然な行動を引き出すための環境を整えたり、教育プログラムを実施したりすることもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (49, 30, 37, 'キャディ', 'キャディはゴルフプレーヤーに付き添い、プレーをサポートする職業です。ゴルフクラブの選択やコースのアドバイス、ボールの位置確認などを行い、プレイヤーがベストなパフォーマンスを発揮できるようにします。また、ラウンド中の距離計測や風の向き、天候などの情報提供も行います。対人スキルやゴルフの知識が求められ、プレイヤーのニーズを理解しきめ細やかなサポートを提供することが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (50, 21, 32, '玩具店店員', '玩具店店員は、顧客に玩具や関連商品を提供し、販売活動を行う職業です。仕事内容には、商品の陳列や在庫管理、顧客対応、レジ業務、そしてプレゼント包装などが含まれます。実店舗では商品を実際に手に取って確認できるため、顧客に対して適切な商品の提案を行うことが重要です。また、新商品の入荷や特別なイベント情報を顧客に伝えることで、リピーターを増やすことも目指します。子供やその家族とのコミュニケーション能力が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (51, 28, 37, '芸能マネージャー', '芸能マネージャーは、芸能人やアーティストのスケジュール管理やメディア対応、プロモーション活動のサポートを行う職業です。彼らの知名度や人気を高めるために、イベントやコンサート、テレビ出演などを企画し、実行します。また、クライアントとメディアやプロデューサーとの橋渡し役としての役割も果たし、契約交渉やビジネス面でのサポートも行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (52, 28, 27, 'モデル', '製品やサービスのプロモーション戦略を提案し、ブランドの認知向上や売上増加を図るためにさまざまな広告媒体を利用します。創造力や分析力が求められ、クライアントや市場のニーズを理解することが重要です。多くの場合、プロジェクト管理やチームリーダーとしての役割を担うこともあります。 ファッション、アニメ、CG、建築など、多岐にわたる分野で活動することができ、創造力と表現力が求められます。特に新しいトレンドを追求したり、自分のスタイルを確立することが重要です。また、プレゼンテーション能力や他者とのコミュニケーション力も不可欠です。 機械学習アルゴリズムやAIモデルを設計、開発、評価します。データの前処理やモデルの最適化、結果の解釈が求められ、PythonやRといったプログラミング言語を使用します。データ分析力や問題解決能力が重要で、最新の技術動向を追い続けることが必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (53, 28, 16, '映像プロデューサー', '映像プロデューサーは、映画、テレビ番組、CM、ウェブコンテンツなどの制作全般を担当する職業です。企画から予算の管理、キャスティング、撮影スケジュールの調整、制作進行の管理、そして完成後の宣伝や配信まで、プロジェクトのすべての段階に関与します。クリエイティブなビジョンを形にするために必要なリソースを集め、チームを指導してプロジェクトを円滑に進めることが主な役割です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (54, 30, 16, 'イベント制作スタッフ', 'イベント制作スタッフは、様々なイベント（コンサート、展示会、祭り、企業イベントなど）の計画、準備、運営を担当する職業です。具体的には、会場の選定、装飾や舞台設営、音響・照明の手配、スケジュール管理、当日の運営サポート、さらには出演者や出席者とのコミュニケーションなど多岐にわたります。細部に気を配る能力や、複数のタスクを同時に効率よく進めるスキルが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (55, 30, 37, 'プロスポーツ選手', 'プロスポーツ選手は特定のスポーツ競技において、トップレベルで競技を行い報酬を得る選手のことを指します。競技によって異なるが、日々のトレーニング、試合への参加、スポンサー活動やメディア出演などが主な業務となります。また、身体のコンディションを保つためのケアや栄養管理も重要です。競技結果に大きな影響を与えるため、高い技術力と精神力が求められます。キャリアの寿命が比較的短いため、現役を引退した後のキャリア設計も考慮する必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (56, 13, 18, 'レーシングエンジニア', 'レーシングエンジニアは、モータースポーツの現場で、車両の設計、製造、メンテナンス、性能向上を担当するエンジニアリングの専門家です。彼らの主な役割は、車両の速度、効率、安全性を高めるために最適なセットアップを見つけることで、データ解析やシミュレーション、テスト走行を通じて車両のパフォーマンスを最大化します。また、レース中はドライバーと密に連携し、戦略的なアドバイスを提供します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (57, 28, 27, '俳優', '俳優は、映画、テレビ、演劇などで演技を通じてキャラクターを表現する職業です。さまざまなスキルが必要で、台詞の暗記、感情の表現、キャラクターの解釈などが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (58, 28, 26, 'レポーター', 'レポーターは、ニュース、事件、スポーツ、エンターテイメントなどの情報を収集し、それを報告する役割を担います。通常、取材現場に赴き、インタビューや観察を通じて情報を集め、それをわかりやすく視聴者や読者に伝えることで社会に情報を提供します。時には現場のライブ報道を行うこともあります。ジャーナリズムの一部として、真実を追求し、公平な報道を心掛けることが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (59, 28, 26, '音楽評論家', '音楽評論家は、音楽作品やアーティストに対する批評や評論を書いたり話したりする職業です。彼らは新しい音楽のリリース、コンサート、音楽業界の動向などを分析・評価し、記事、レビュー、エッセイとして発表します。また、ラジオやテレビでの評論、オンラインプラットフォームでのレビュー投稿も行うことがあります。幅広い音楽知識と深い分析能力が求められ、読者やリスナーに対する影響力が大きい役割を担います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (60, 29, 27, 'フラワーコーディネーター', 'フラワーコーディネーターは、花や植物を使った装飾をデザインし、イベント、式典、店舗、または個人的な場面での装飾を提案する職業です。彼らは、クライアントの要望を聞き、イベントのテーマや目的に合った花の選択、色の組み合わせ、配置のデザインを行います。また、花の種類や季節感を考慮し、最適な花材を選ぶことも重要です。細やかなセンスとイメージを具体的な形にする能力が求められます。特に結婚式やパーティ、ショールームなどで、空間全体を華やかに演出する役割を担います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (61, 28, 37, 'ダンサー', 'ダンサーは、個人またはグループで音楽に合わせて様々なスタイルの踊りを披露する職業です。バレエ、ヒップホップ、ジャズ、コンテンポラリーなど、幅広いジャンルがあります。ダンサーは、ステージ、公演、テレビ、映画、音楽ビデオなど、さまざまな場でパフォーマンスを行います。振付師と協力して新しいダンスナンバーを創作することもあります。また、日々のトレーニングや練習を欠かさず行うことで、高度な技術と表現力を維持します。仕事には厳しい競争が伴う一方、成功すれば観客への感動を与えることができる魅力的な職業でもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (62, 29, 27, '修復家', '修復家は、古い建物や美術品、歴史的な遺物などを元の状態または最適な保存状態に戻すための専門職です。彼らは、保存科学、建築技術、歴史や芸術の知識を活かし、各素材の特性を理解しながら修復を行います。修復家は、店舗やドキュメント、写真、織物、家具、絵画、彫刻など様々なオブジェクトの回復に携わります。また、劣化を防ぐための予防保存や保護対策を施すことも重要な業務の一部です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (63, 28, 26, '放送記者', '放送記者はテレビ、ラジオ、オンラインメディアなどでニュースを報道する職業です。主な業務には、ニュースの取材、インタビューの実施、原稿の執筆、そして報道番組でのニュースの伝達が含まれます。情報の正確さを保ち、公正かつバランスの取れた報道を行うことが求められます。また、事件や現場にいち早く駆けつけて状況を報告する能力や、複雑な情報を一般視聴者に分かりやすく伝えるスキルも重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (64, 28, 37, '声優', '声優は、アニメ、映画、ドラマ、ゲームなどでキャラクターの声やナレーションを担当する職業です。台本をもとにキャラクターの感情や性格を声で表現し、作品に命を吹き込みます。また、吹き替え作業も行い、海外作品を日本語にローカライズする役割も担います。声の特技や表現力に加えて、表情や動きも重要で、キャラクターがどのように見えるかを想像しながら演技する能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (65, 18, 17, 'ゲームサウンドクリエイター', 'ゲームサウンドクリエイターは、ビデオゲームの音楽やサウンドエフェクトを作成する職業です。この職業では、ゲームのテーマやストーリーに合わせて音楽を作成したり、アクションに対応する効果音を追加したりします。通常、デジタルオーディオワークステーション（DAW）を使用して作業し、作曲、録音、編集、ミキシングなどのスキルが求められます。ゲーム開発チームと協力して、プレイヤーの没入感を高めるためのサウンドデザインを行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (66, 28, 37, 'タレント', 'タレントは、テレビやラジオ、インターネット、イベントなどでエンターテイメントを提供することを職業とする人物を指します。彼らは俳優、歌手、司会者、コメディアンなど多岐にわたるジャンルで活動し、主に視聴者や観客を楽しませることを目的としています。タレントは通常、個人の特技やキャラクターを活かしてパフォーマンスを行い、巨大なファンベースを築くこともあります。また、メディアに出演して影響力を持つことで、広告やプロモーションなど様々なビジネスにも携わります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (67, 27, 37, '学芸員', '学芸員は博物館、美術館、図書館などで働き、文化財や資料の収集、管理、展示、教育活動を行う専門職です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (68, 28, 27, '指揮者', '指揮者は、オーケストラや合唱団などの音楽団体を指導し、音楽作品の演奏をまとめる役割を担う。楽曲の解釈や演奏の表現を決定し、リハーサルを通じて団員を指導する。また、演奏の際には指揮棒や手の動きでタイミングを示し、全体のパフォーマンスを調整する。音楽に対する深い知識と人間関係のスキルが求められる職業である。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (69, 30, 27, 'ブライダルプレイヤー', 'ブライダルプレイヤーとは、結婚式や披露宴において、音楽の演奏を担当するミュージシャンのことです。結婚式場やチャペル、披露宴会場でのLive演奏を通じて、新郎新婦やゲストに感動を与える重要な役割を担っています。楽器演奏やボーカルが求められるため、高い演奏技術と音楽のセンスが必要です。また、イベントの進行に合わせた柔軟な対応力も求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (70, 30, 37, '騎手', '騎手は、競馬において馬に騎乗し、レースに参加する専門職です。馬の能力を最大限に引き出し、勝利を目指して競技場を駆け抜けます。騎手は、身体能力や馬とのコミュニケーション能力が必要であり、レースの戦略を理解し、状況に応じた判断力も求められます。体重や技術、経験などが重要視されるため、厳しいトレーニングと学びを通じて経験を積む必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (71, 28, 27, 'ピアニスト', 'ピアニストは、ピアノを演奏する職業の音楽家です。さまざまなジャンルの音楽を演奏し、ソロコンサートやオーケストラとの協演、レコーディングセッションなどで活動します。音楽教育機関での指導や、個人レッスンを行うこともあります。高度な技術と豊かな表現力が求められ、舞台でのパフォーマンスに対して観客を感動させる役割も果たします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (72, 28, 27, 'ナレーター', 'ナレーターは、映像作品、ラジオ、オーディオブック、広告などで文章を声に出して読み上げる仕事を担当します。明確で感情豊かな発音、リズム感、そして適切な間を取る技術が重要です。聞き手に情報を伝えたり、感動を与える力が求められます。音声録音の専門スタジオで働くことが多いですが、フリーランスとして活動する人もいます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (73, 28, 27, 'スポーツカメラマン', 'スポーツカメラマンは、スポーツイベントやアスリートの写真を撮影する専門職です。主に、ライブイベントや試合中の瞬間を捉えることに専念し、選手の動きや試合の流れをリアルタイムで記録します。迅速な行動力と確かな技術が求められ、カメラやレンズの選択、撮影の角度、照明条件に対応する能力が必要です。一般的には、新聞社やスポーツ雑誌、オンラインメディア、またはフリーランスとして活動し、それらのコンテンツを提供します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (74, 29, 27, 'カラーコーディネーター', 'カラーコーディネーターとは、色に関する専門知識を持ち、衣類やインテリア、広告、商品パッケージなど、さまざまな分野での色彩の選定や提案を行う職業です。ファッション業界やインテリアデザイン、グラフィックデザインなど、色彩の重要性が高い分野で活躍することが多いです。カラーコーディネーターは、色彩心理学や色彩の基本的なルールを理解し、クライアントのニーズに応じた調和のとれた色の組み合わせを提案します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (75, 28, 26, '脚本家', '脚本家とは、映画、テレビドラマ、舞台、アニメーションなどの作品の脚本（シナリオ）を執筆する職業です。物語の筋書き、キャラクター、対話、場面設定などを創造し、視聴者や観客に感動や興奮を与えるストーリーを作り上げます。多くの場合、脚本家はプロデューサーや監督、その他のクリエイティブチームと密接に連携し、作品のコンセプトに沿ったシナリオを開発します。優れた脚本家は独自の視点やスタイルを持ち、物語を豊かに表現することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (76, 28, 27, 'DJ', 'DJは、音楽を選曲し、曲と曲をミックスして、聴衆を楽しませる役割を担う職業です。クラブ、イベント、ラジオ、バーなどで活動し、選曲のセンスや技術的なスキルが求められます。また、観客の反応を常に観察しながら、適切な音楽を選ぶ能力も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (77, 29, 15, 'グラフィックデザイナー', 'グラフィックデザイナーは、視覚的なコンテンツを作成およびデザインする専門家です。広告、印刷媒体、デジタルメディア、ウェブサイト、ロゴ、プロダクトデザインなど、多岐にわたるプロジェクトに携わります。デザインソフトウェアを使用し、クライアントの要望やプロジェクトの目的に応じて、視覚的に効果的で魅力的なデザインを作成します。クリエイティビティと技術的スキルが求められ、色彩理論やタイポグラフィなどに関する知識も必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (78, 18, 10, 'アプリケーションエンジニア', 'アプリケーションエンジニアは、ソフトウェアアプリケーションの開発、設計、実装、テストを行う専門家です。主にプログラミングによって、ユーザーの要件を満たすためのアプリケーションを作成します。加えて、技術的な問題の解決や、システムの最適化も行います。通常、業務はプロジェクトチームとして行われ、他のエンジニアやデザイナーと協力して効果的なソフトウェアソリューションを提供します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (79, 30, 36, '厩務員', '厩務員は、競馬場や厩舎で馬の世話をする専門職です。主な業務には、馬の給餌、世話、厩舎の清掃、馬の健康管理、乗馬訓練の補助などが含まれます。馬の性格や行動を理解し、安全に扱うための知識と技術が求められます。体力が必要な仕事で、長時間労働や休日勤務も一般的です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (80, 4, 33, '和菓子職人', '和菓子職人は、日本の伝統的なお菓子である和菓子を手作りする専門家です。彼らは材料の選定から始まり、餡（あん）やもち米、生地の調合といった製造過程を精密にコントロールし、美しい見た目と味わいを両立させる技術を持っています。伝統的な技法を守りつつも、新しいアイデアを取り入れることも求められ、季節感を重視した作品を作り出します。和菓子職人は、長い修行と経験を重ねることによって、高度な技術を習得し、その職人技を次世代へと伝えていきます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (81, 33, 9, '中小企業診断士', '中小企業診断士は、中小企業の経営や改善に関するコンサルティングを行う専門家です。彼らは企業の経営戦略、財務、マーケティング、人事管理などの分野でアドバイスを提供し、企業の成長と発展を支援します。国家資格であり、試験は経済学や経営学、法学、情報システムなど幅広い科目からなり、相当の知識と実務経験が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (82, 25, 23, '救急救命士', '救急救命士は、事故や急病の現場で最初に対応し、患者の命を救うための専門的な医療処置を行う職業です。主に救急車などの緊急医療機関で働き、心肺蘇生法、AEDの使用、創傷処置、薬剤の投与などを行います。日本では、資格を取得するためには専門の教育課程を修了し、国家試験に合格する必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (83, 9, 27, 'ガラス工芸家', 'ガラス工芸家は、ガラスを素材として用い、装飾品、工芸品、実用的なガラス製品を製作する職業です。彼らは、溶けたガラスを操作するために吹きガラス、切削、研磨、ステンドグラスなどの技術を駆使します。伝統的な手法と現代的なデザインを融合させ、独自の作品を生み出します。耐熱性、透明度、色彩効果など、ガラスの特性を活かして、芸術的あるいは実用的価値のある作品を創り出します。ガラス工芸家は、通常、芸術家としての視点だけでなく、技術的なスキルや素材に関する深い知識も要求されます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (84, 28, 37, 'スーツアクター', 'スーツアクターは、特撮やアニメーション映画、テーマパークのパフォーマンスなどで、特殊なコスチュームやスーツを着用してキャラクターを演じる俳優です。彼らの役割は、しばしばキャラクターの個性を体全体で表現し、スーツ内での動きを通じて物語を進行させることにあります。また、スーツアクターは演技だけでなく、体力的な要求も非常に高く、コスチュームが重く動きづらい場合も多いため、身体能力や持久力、そして高度なアクションスキルが求められます。日本では特に「スーパーヒーロー」や「怪獣」映画、テレビシリーズで重要な役割を担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (85, 28, 37, 'スタントマン', 'スタントマンは、映画、テレビ、舞台、またはその他のメディアにおいて、危険を伴うシーンを演じる役割を担っています。通常、俳優が行うにはリスクが高すぎるアクションやシーンを演じます。スタントマンの仕事には、高所からの飛び降り、火を使ったシーン、激しいアクションシーンの実施などが含まれます。高度な技術や訓練が求められ、身体的な制約に対する耐性や危険を管理する能力が必要です。また、安全第一で行動し、プロフェッショナルなチームの一員として働くことが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (86, 28, 26, '音楽雑誌記者', '音楽雑誌記者は、音楽関連の情報を収集し、それを元に記事を書く職業です。主要な業務として、アーティストのインタビュー、ライブや音楽イベントの取材、アルバムや楽曲のレビュー、音楽業界の動向を調査するなどがあります。音楽ファンや一般読者に向けて興味深い記事を提供するために、常に最新の音楽トレンドを把握し、音楽シーンにおける新たな動きや注目されているアーティストを追うことが求められます。文章力はもちろん、音楽に対する深い知識と情熱が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (87, 29, 15, 'イラストレーター', 'イラストレーターは、商業的または芸術的な目的でイラストを作成する職業です。デジタルや手描きの技術を用いて、書籍、雑誌、広告、ビデオゲーム、ウェブサイト、アニメーションなどさまざまなメディアのイラストを制作します。クライアントの要望をもとに、視覚的なコンセプトを考え出し、それを具体的な作品として具現化します。クリエイティブな表現力と技術的なスキルが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (88, 11, 18, 'メカトロニクス技術者', 'メカトロニクス技術者は、機械工学と電子工学を統合して設計や製造を行う専門職です。自動化システム、ロボット工学、制御システムの開発に携わり、多くの場合、プログラミングやシステムの設計からテストまでを担当します。現代の製造業や開発環境では不可欠な役割を担っており、高度な技術力と広範囲な知識が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (89, 23, 32, 'ツアープランナー', 'ツアープランナーは、旅行や観光ツアーの企画および手配を行う職業です。具体的には、顧客の要望や興味に応じて旅行プランを立案し、宿泊施設や交通機関の予約、現地ガイドの手配などを行います。また、旅行日程の作成やコストの見積もり、顧客対応なども担当します。旅行業界や観光地についての知識が求められ、顧客の満足度を高めるために創造力や企画力も重要な要素とされます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (90, 26, 25, '楽器インストラクター', '楽器インストラクターは音楽教育の専門家であり、特定の楽器（例：ピアノ、ギター、バイオリンなど）の演奏技術を学生に教える仕事です。彼らは楽器の基本から高度なテクニックまで幅広い知識を持ち、新しい生徒への楽器の紹介からプロフェッショナルレベルの演奏スキルの指導まで行ないます。また、生徒の進捗を評価し、個々のニーズに応じたカリキュラムを作成し、モチベーションを高めるサポートを提供します。音楽学校、個別レッスンスタジオ、または独立してプライベートレッスンを提供する場合もあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (91, 28, 27, '照明スタッフ', '照明スタッフは、ステージやイベント、映画、テレビ番組などのシーンに照明を設置・操作する職業です。彼らはシーンのムードや雰囲気を効果的に演出するために、技術的な知識とアーティスティックな感覚を駆使して、ライトの配置や角度、色彩を調整します。また、機材の準備やメンテナンス、電力供給の管理も行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (92, 28, 26, '新聞記者', '新聞記者は、ニュースを取材し、記事を執筆する職業です。取材対象は政治、経済、社会、文化、スポーツなど多岐にわたり、正確かつ迅速な情報を提供することが求められます。記者は現場での取材だけでなく、資料調査やインタビューを通じて情報を集め、それをもとに読者にわかりやすく伝える記事を作成します。長時間労働が求められることもあり、緊急のニュースには即時対応が必要です。多くの場合、新聞社やニュース媒体に所属しますが、フリーランスとして独立して活動することもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (93, 28, 16, 'コンサートプロモーター', 'コンサートプロモーターは、音楽イベントの企画、運営、宣伝を担当する職業です。主な役割としては、アーティストやそのマネージメントと協力しながら、コンサートのスケジュールを立て、会場の選定、チケット価格の設定、広告キャンペーンの実施、そして各種必要な手配を行います。また、イベントがスムーズに進行するよう、当日の運営を監督することも重要な業務の一つです。交渉力やマルチタスク能力、音楽業界のトレンドに対する洞察力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (94, 28, 27, 'ギタリスト', 'ギタリストはギターを演奏し、曲やメロディを生み出す音楽家です。彼らは音楽バンドや個々のアーティストとして活動し、様々なジャンルでライブ演奏や録音を行います。ギタリストは技術的な演奏能力と音楽的な表現力が求められ、時には作曲や編曲も行うことがあります。新しい楽曲を創作する場合も、既存の曲をカバーする場合もあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (95, 23, 33, 'ベルパーソン', 'ベルパーソンは、ホテルやリゾートなどの宿泊施設で、お客様の荷物を運んだり、チェックインやチェックアウトの際にサポートを行う役割を担います。お客様の出迎えや見送り、館内の設備案内なども含まれ、多岐にわたる接客業務を行います。対面での接客スキルや相手をもてなす心が重要となります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (96, 28, 27, '音響スタッフ', '音響スタッフは、音楽ライブ、演劇、テレビ番組や映画などで音の質を管理し、最適な音響効果を提供する職業です。具体的には、マイクやスピーカーのセッティング、音響機器の操作、録音作業、音声のバランス調整などを行います。また、現場での音響トラブルに対処し、常に最高の音質を提供できるように準備と保守作業も担当します。豊富な専門知識と現場経験が求められる職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (97, 18, 17, 'ゲームプランナー', 'ゲームプランナーとは、ゲーム開発プロジェクトにおいて、企画・設計を担当する職種です。ゲームのコンセプトを考え、それに基づいたストーリーやキャラクター、ルール、システム、ゲーム内のレベルデザインなどを具体的に設計します。チームメンバーと協力して、ゲーム全体の構成をまとめ、スケジュール管理や進行管理も行うことがあります。また、新しいゲームのアイデアを提案し、プロトタイプを作成してゲームのビジョンを形にする役割も担います。ゲームの成功に大きく影響するため、創造性やコミュニケーション能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (98, 30, 37, '調教師', '調教師は、動物の行動を訓練し調整する職業です。動物園、サーカス、レース業界などで働き、動物の安全と健康を考慮しながら特定の行動を引き出すよう訓練します。動物の種類やトレーニングの目的に応じて、適切なトレーニング手法を用いる必要があります。また、動物のケアや環境の維持、トレーニング計画の作成など、多岐にわたる業務も担当します。さらに、動物の身体的・精神的な健康管理も重要な役割となります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (99, 28, 26, 'スポーツジャーナリスト', 'スポーツジャーナリストは、主にスポーツイベントや大会、選手の取材を行い、その内容を記事やリポートとして報道する職業です。試合の実況、選手・チームのインタビュー、スポーツの最新情報やトレンド分析など、幅広い活動を行います。また、新聞、雑誌、テレビ、インターネットなど、さまざまなメディアを通じて情報を発信し、スポーツの魅力を伝える役割を担っています。専門知識や分析力、取材力が求められ、そのために頻繁にスポーツ現場に足を運ぶことも少なくありません。コミュニケーション能力や文章力も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (100, 28, 16, 'CMプランナー', 'CMプランナーは、広告主や企業が伝えたいメッセージを適切にターゲットオーディエンスに届けるためのテレビコマーシャル（CM）を企画・制作する専門家です。彼らは、クライアントの製品やサービスの特徴を把握し、それを元に効果的なストーリーテリングやビジュアルコンセプトを作成します。また、広告の目的やターゲット層に応じたメディア戦略を立て、どのメディアでCMを流すのが最も効果的であるかを考慮します。さらに、制作チームやディレクターと協力して撮影や編集を進行管理し、完成したCMが広告の目標を達成できるような内容であるか確認します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (101, 28, 27, '演出家', '演出家は、映画、演劇、テレビ番組などの芸術的な作品の制作において、全体のコンセプトを考案し、キャストやスタッフと協力しながら作品を具現化する役割を担う職業です。演出家はビジョンを具体的な形にするために、脚本を研究し、オーディションを主催してキャストを選び、リハーサルを指導し、撮影や公演の各段階でクリエイティブな決定を下します。演出家は芸術的なセンスとリーダーシップ能力が求められ、しばしば高いレベルのコミュニケーション能力とプロジェクト管理能力も必要とされます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (102, 23, 36, '水族館スタッフ', '水族館スタッフは、水族館で様々な業務を担当する職業です。主な業務内容には、飼育している水生生物の管理・世話、来館者へのガイドや教育プログラムの運営、展示水槽の清掃やメンテナンス、イベントの企画運営などが含まれます。また、安全管理や水質管理を行い、水生生物が快適に暮らせる環境を維持することも重要です。対人コミュニケーションスキルや生物に関する知識が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (103, 30, 32, 'テーマパークスタッフ', 'テーマパークスタッフは、テーマパークや遊園地で働く職業で、ゲストの接客やアトラクションの運営、イベントのサポート、清掃、安全管理など多岐にわたる業務を担当します。主な役割には、入場ゲートでのチケット確認やガイド、アトラクションの操作と説明、園内の案内とサポート、パレードやショーの運営補助などが含まれます。ゲストに楽しい体験を提供するために、常に笑顔でのコミュニケーションが求められ、接客スキルやチームワークが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (104, 28, 15, '映像ディレクター', '映像ディレクターは、映画、テレビ番組、コマーシャルなどの映像作品の制作を指揮する職業です。彼らは、脚本の解釈、演技指導、撮影のスタイル決定、編集の監督など、作品を完成させるためのすべてのクリエイティブおよび技術的な側面を管理します。ディレクターは、視聴者に訴えるビジュアルストーリーを作成するためのビジョンを持ち、チームと協力してそのビジョンを実現します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (105, 28, 27, '漫画家', '漫画家は、ストーリーやキャラクターを絵と文章で描写し、漫画という形式で読者に提供する職業です。通常、アイデアを練り上げ、ネーム（ストーリーのアウトライン）を作成し、それに基づいて作画を行います。週刊や月刊の雑誌、単行本などの形式で作品が発表されることが多いです。独創性が必要で、締め切りのある厳しいスケジュール管理能力も求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (106, 30, 16, 'イベントプロデューサー', 'イベントプロデューサーは、イベントの企画から実施までを総合的に管理し、成功裏に終了させる役割を担います。クライアントの要望を基にアイデアを提案し、予算の管理、会場の選定、必要なスタッフの手配、そして舞台や広告の準備などを行います。優れたコミュニケーション能力、組織力、問題解決能力が求められます。様々なイベント、例えばコンサート、ビジネス会議、展示会などを取り仕切ります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (107, 21, 6, 'カーアドバイザー', 'カーアドバイザーは、自動車販売店やショールームでお客様に車の情報を提供し、購入をサポートする職業です。顧客のニーズに合わせた車選びのアドバイス、試乗のサポート、購入の手続きなどに加え、車に関する様々な質問に答えます。また、顧客との良好な関係を築き、再来店を促進する役割も担います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (108, 28, 26, '作家', '作家はフィクションやノンフィクションの作品を執筆する職業です。小説、短編、小論文などを通じて、自身の創造力やアイデアを文章化します。出版やオンラインプラットフォームを通じて、読者に作品を届けることを目的としています。作家として成功するには、文章力、創造力、自己管理能力が重要です。また、出版業界やマーケティングの知識も有益です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (109, 28, 15, 'アニメーター', 'アニメーターは、アニメーション作品やキャラクターデザインを創り出す職業です。例えば、テレビアニメや映画、ゲームにおけるキャラクターの動きを作成し、動きや表情を通して物語を表現します。アニメーターは、キャラクターの意図や性格を視覚的に伝え、ストーリーの中で感情やドラマを引き立てる役割を担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (110, 27, 9, '気象予報士', '気象予報士は、気象データを用いて天気予報や気候に関する情報を提供する専門職です。彼らは、気象衛星や地上観測データを分析し、天候の変化や傾向を予測します。その情報をもとに、一般向けに天気予報を作成したり、特定の業界（例えば農業や航空業界）へのアドバイスを行ったりします。気象予報士になるためには、国家試験に合格する必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (111, 33, 37, '占い師', '占い師は、占星術やタロットカード、手相占い、サイコメトリーなど、さまざまな占いの手法を用いて、クライアントの悩みや質問に対してアドバイスを提供する職業です。彼らの目的は、個人の問題を解決し、未来に向けた指針を示すことができるようサポートすることです。信頼と共感を築くことで、長期的な関係を維持することが目指されます。占い師は、対面やオンラインでのセッションを通じてクライアントと対話し、彼らの人生の改善を手伝います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (112, 28, 27, '映画監督', '映画監督は、映画製作の中核を担う役割を果たし、映画の全体のビジョンを監督し、脚本、撮影、演技、編集などの各要素を統括します。監督は俳優やスタッフを指導し、映画のスタイル、ペース、トーンを決定します。映画の製作工程全体でのクリエイティブなリーダーシップを提供し、映画の出来上がりに対する最終的な責任を負います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (113, 28, 37, 'コメディアン', 'コメディアンは、ユーモアやジョークを通じて観客を楽しませるエンターテイナーです。彼らはテレビ、インターネット、ラジオ、ライブコメディイベントなどでパフォーマンスを行うことができます。多くのコメディアンは、自らの経験や時事、文化のトピックをもとに、自分のスタイルでユーモアを作り上げます。即興やスケッチコメディから漫談まで、様々な形式のコメディを演じることがあります。観客とのコミュニケーション能力とタイミングが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (114, 30, 32, 'ブライダルプランナー', 'ブライダルプランナーは、結婚式の計画と実行を担当する専門家です。カップルの希望や予算に応じて、会場の選定、装飾、ケータリング、音響、写真撮影など、全体のプランニングを行います。また、当日の進行管理やトラブルシューティングも含まれ、カップルにとって最高の日を作り出すために細部にまで注意を払います。創造性が求められる一方で、顧客対応や交渉能力も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (115, 28, 27, 'ミュージシャン', 'ミュージシャンとは、音楽を専門に演奏、作曲、編曲、または楽器を演奏する職業です。彼らは様々なジャンルで活動し、ソロでの活動やバンド、オーケストラなど集団での演奏を行うことがあります。楽器を使ってライブパフォーマンスを行ったり、音楽をレコーディングしてリリースしたりするのが主な業務です。クリエイティブで技術的な能力が求められ、時には作詞やプロデューサーとしての役割を果たすこともあります。さらにコンサートツアーや新しい音楽の制作など、協働やプロジェクト管理も仕事の一部です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (116, 21, 1, 'ショップオーナー', 'ショップオーナーは、店舗の管理、運営、戦略的な意思決定を行う職業です。商品の仕入れ管理、販売促進、スタッフの採用とトレーニング、顧客サービスの質向上など、店舗運営に関わる全ての側面を監督します。オーナーはビジネスの方向性を決定し、売上の最大化と効率的な経費管理を追求します。また、地元コミュニティとの関係構築や、オンラインマーケティングなどのデジタルプラットフォームの活用も含まれることがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (117, 20, 1, '会社経営者', '会社を経営する者であり、全体の方針や戦略を決定して事業を成功に導く役割を担う。事業のビジョンを設定し、経営資源を効果的に運用し、ビジネスモデルを構築するなど、多岐にわたる責任がある。経営者は業績の目標を設定し、経済的リスクを管理することが求められる。スタッフの指揮を執り、関係者との信頼関係を構築し、企業の成長を促進するために必要な意思決定を行う。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (118, 25, 23, '医療情報管理者', '医療情報管理者は、医療機関において患者の医療情報を正確かつ効率的に管理する役割を担う。電子カルテや医療記録の管理、情報の保護、データの分析などを行い、医療の質を向上させる。特に、プライバシーやセキュリティの確保が重要な課題となる。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (119, 21, 32, '駅構内売店販売員', '駅構内売店販売員は、鉄道駅内の売店で商品の販売や接客を行う職業です。主に新聞、雑誌、お菓子、飲料などの一般的な商品を取り扱います。顧客対応や商品の陳列整理、在庫管理、売上処理といった業務を行い、駅を利用するお客様に快適で便利な買い物体験を提供する役割を担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (120, 17, 31, '管理業務主任者', '管理業務主任者は、主にマンション管理に関する業務を行う専門家です。彼らは、マンションの管理組合と協力して、建物や設備の維持管理、予算編成、経理管理、住民の生活環境の改善を図るなどの業務を行います。この職種は、いわゆるプロパティマネージャーに近く、専門的な知識と資格が必要とされます。また、居住者とのコミュニケーション能力や、法的知識も求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (121, 25, 24, '福祉住環境コーディネーター', '福祉住環境コーディネーターとは、高齢者や障がい者が安全かつ快適に生活できる住環境を整えるための専門家です。住宅改修のアドバイスや、バリアフリー設備の設置、生活動線の見直しなどを行い、利用者の身体状況や生活スタイルに適した環境づくりをサポートします。医療や介護の知識を持ち、建築や福祉に関する法律にも詳しいことが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (122, 17, 35, 'ビル施設管理者', 'ビル施設管理者は、建物や施設の運営、保守、修繕を担当する職業です。具体的には、設備の点検や修理、清掃管理、オフィス設備の利用状況の管理、必要に応じたリノベーションの手配などが含まれます。また、エネルギー効率の最適化や安全基準の遵守も重要です。施設の快適さと安全性を維持するために、管理者はスタッフや外部業者との連携を図り、効率的な運営管理を行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (123, 16, 20, '建築構造設計技術者', '建築構造設計技術者は、建物の構造を設計する専門家です。彼らは建物が安全かつ耐久性のあるものであることを保証するために、構造的な図面や仕様を作成し、強度計算を行います。また、地震や風などの自然災害に耐えられるように設計を行うほか、建築基準法や他の関連法規を遵守することを重視します。さらに、プロジェクトの進行に応じた構造設計の調整や修正を行うことも重要な業務です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (124, 31, 2, '政治家秘書', '政治家秘書は、政治家のサポートを行う職業で、日常業務の管理や調整を担当します。具体的には、スケジュールの管理、会議やイベントの準備、資料の作成、政策立案の補助、選挙活動の支援、内外のコミュニケーションの調整など、多岐にわたる業務があります。政治家の意図を理解し、迅速かつ正確に行動する能力が求められます。機密情報を扱う場合もあるため、高い信頼性と倫理観が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (125, 17, 31, 'マンション管理士', 'マンション管理士は、マンションの管理運営に関する専門知識を持つプロフェッショナルです。マンションの居住者や管理組合に対して、法律、経済、建築、環境に関する助言やサポートを行います。彼らの主な役割には、管理規約の作成や改訂、建物の保守・修繕計画の策定、管理費の適正な使用管理、さらには居住者間のトラブル解決の支援などがあります。マンションの資産価値を維持・向上させるために重要な役割を果たします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (126, 21, 32, '電器店員', '電器店員は、家電製品の販売、接客、及び関連するサービスを提供する職業です。店舗における接客業務が主な内容で、商品の特徴や使い方の説明、顧客のニーズに合わせた商品推薦などを行います。顧客からの質問に答え、購入決定のサポートをします。他には、在庫管理、商品の陳列、販売促進のためのイベント準備なども担当することがあります。コミュニケーション能力や商品知識が重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (127, 33, 30, '司法書士', '司法書士は、不動産登記や商業登記、裁判所に提出する書類の作成、簡易裁判所での代理業務などを行う法務の専門職です。クライアントの権利を守るために法律文書を作成し、手続きを適切かつ円滑に進める役割を担っています。また、成年後見業務や企業法務、相続関連の手続きなども担当します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (128, 12, 18, 'ハードウェア設計技術者', 'ハードウェア設計技術者は、電子機器やデジタルシステムの設計を専門とする技術者です。彼らは製品の仕様に基づいて、回路図の作成、部品選定、試作、検証、改良までのプロセスを担当します。主にICやプリント基板（PCB）のデザイン、マイクロプロセッサの設計、信号処理などの技術に関与します。また、設計仕様を満たすために、新しい技術の研究や既存技術の応用を行い、プロジェクトチームと協力しながら製品開発を行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (129, 18, 13, 'セキュリティ技術者', 'セキュリティ技術者は、組織の情報システムやネットワークを保護する役割を担います。彼らの主な職務には、セキュリティポリシーの策定、セキュリティシステムの構築・管理、セキュリティインシデントの検出と対応があります。また、定期的なセキュリティ監査を行い、脆弱性を特定し、最新の脅威に対応するための技術的な対策を講じます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (130, 33, 5, '法務', '法務は、企業や組織の法律関連の業務を担当する職種であり、法律に基づいたリスクマネジメント、契約書作成や審査、コンプライアンスの確保などを行います。法務部門は、企業活動が法律に違反しないように支援し、法的な問題を未然に防ぐ役割を果たします。弁護士資格が必要とされる場合もあり、法務担当者は専門的な法的知識や交渉力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (131, 18, 10, 'システムアナリスト', 'システムアナリストは、企業や組織のニーズに基づいて情報システムを評価、設計、実装する役割を担います。ビジネス要件を理解し、それを技術ソリューションに変換する作業を行い、効率的で効果的な情報システムの構築を支援します。プロジェクトマネージャーやソフトウェアエンジニアなどと協力しながら業務を進行させます。分析スキルやコミュニケーション能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (132, 31, 30, '検察官', '検察官は、犯罪捜査および起訴を担当する公務員であり、法廷での審理において国家を代表して訴追を行います。検察官の主な任務は、犯罪行為を行ったとされる人物に対して十分な証拠を集め、公正な審理が行われるように裁判所に起訴することです。また、場合によっては不起訴処分を決定する権限も持っています。日本では、法曹界の一部として重要な役割を果たし、国民の安全と正義の実現に貢献しています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (133, 25, 23, '言語聴覚士', '言語聴覚士は、言語、音声、聴覚、嚥下（えんげ）の障害を持つ人々に対し、診断、評価、治療を行う専門職です。話す、聞く、飲み込むといったコミュニケーションと摂食活動の改善を目指し、個別のニーズに合わせた療法を提供します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (134, 33, 2, '秘書', '秘書は、会社の役員や管理職の仕事を支援する職務です。日々のスケジュール管理、電話応対、文書作成、会議の準備といった業務をこなし、上司の効率的な業務遂行を助けます。また、来客の応対なども行います。優れたコミュニケーション能力と組織力、そして細部への注意力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (135, 18, 12, '電子計算機オペレーター', '電子計算機オペレーターは、コンピュータシステムや関連機器の操作や監視を行い、システムの効率的な稼働を確保する職業です。彼らの主な業務には、データ入力、ジョブスケジュールの管理、機器のメンテナンス、エラーの検出とトラブルシューティングが含まれます。また、定期的にシステムの性能を確認し、必要に応じて技術的な支援を行います。時には新しいソフトウェアやハードウェアのインストールにも関与することがあります。通常は、24時間体制の勤務が求められることが多く、夜勤や休日勤務も発生する場合があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (136, 35, 35, '清掃作業員', '清掃作業員は、建物や施設などの清潔を保つために掃除や清掃を行う職業です。日常的には床の拭き掃除、掃除機掛け、ゴミの収集と廃棄、トイレやキッチンの清掃などを行うことが含まれます。また、定期的なワックス掛けやカーペット清掃、ガラスの拭き掃除なども担当することがあります。清掃作業員は、家庭やオフィスビル、病院、学校など、さまざまな場所で働くことができ、清潔で快適な環境を提供する役割を担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (137, 21, 8, '通信販売受付スタッフ', '通信販売受付スタッフは、顧客からの注文や問い合わせに応じて、製品やサービスの注文処理を担当する職人です。主な業務には、電話やメールでの注文受付、商品の在庫確認、発送手配、お客様への対応などがあります。顧客対応力、コミュニケーション能力、問題解決能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (138, 25, 10, '医療情報管理士', '医療情報管理士は、病院やクリニックなどの医療機関で、患者情報の管理、医療記録の整備、データの分析や統計処理を行う職種です。電子カルテの活用や個人情報の保護、安全な情報管理システムの構築など、デジタル化が進む医療現場で非常に重要な役割を担っています。また、医療情報の標準化や品質向上、法令遵守などの業務も行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (139, 4, 16, '商品開発部員', '商品開発部員は、新しい製品やサービスを企画・開発する職種です。この職種では市場調査を行い、顧客ニーズやトレンドを分析した上で商品コンセプトを構築します。企画した商品を実現するために、デザインや試作品の作成、製造プロセスの管理なども担当することがあります。また、プロジェクトの進捗を管理し、社内外の関係者と連携を取りながら商品化までをサポートします。クリエイティビティや市場分析力、プロジェクト管理能力が求められる職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (140, 31, 28, '労働基準監督官', '労働基準監督官は、労働条件や労働環境が法律に準拠しているかを監督し、労働者の権利を保護する役割を担っています。主な職務には、企業や事業所への立ち入り調査、労働条件の改善の指導、労働基準法等に基づく勧告や是正指導の実施、労働紛争の解決に向けた取り組みが含まれます。また、労働災害や長時間労働に関する問題にも対応し、労働者の安全と健康の確保に努めます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (141, 25, 23, '薬剤師', '薬剤師は、医薬品の調剤や販売、医薬品の品質管理などを行う専門家です。また、患者に対して薬の適切な使用方法や副作用についての説明を行います。病院や薬局、製薬会社など、さまざまな場所で活躍することができ、医療チームの一員として重要な役割を担っています。さらに、薬の開発や研究に携わる機会もあります。薬剤師になるためには、大学で薬学を専攻し、国家試験に合格することが必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (142, 22, 2, '郵便事務員', '郵便事務員は、主に郵便物の仕分け、配送の手配、郵便料金の計算、切手の販売、郵便窓口での接客などを行います。業務内容には、郵便物を指定のエリアに振り分ける作業や、発送される郵便物の集荷手配、運送会社との連絡調整、顧客の問い合わせ対応なども含まれます。基本的にはオフィス内でのデスクワークが中心ですが、窓口対応や時には軽作業が伴うこともあります。チーム内で協力して業務を進める場合が多く、コミュニケーション能力や協調性が求められる職種です。
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (143, 33, 2, '英文速記者', '英文速記者は、会議やセミナー、裁判所の審議などで発言をリアルタイムで記録していく職業です。通常、特殊な速記技術を用いて話の内容を素早く記録し、必要に応じて書き起こしを行います。英語のリスニング能力や速記技術が求められ、高度な集中力が必要とされます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (144, 16, 20, '建築積算技術者', '建築積算技術者は、建築プロジェクトの設計図や仕様書をもとに、工事に必要な材料や労働力の数量を算出し、コストを見積もる専門職です。具体的には、設計図を詳細に分析し、各工程で必要となる材料や作業のリストを作成し、それらの市場価格を考慮して全体の工事費用を算出します。また、予算管理やコスト削減の提案も行い、プロジェクトの全体的な予算を効率的に管理する役割を担っています。この職業には、建築に関する深い知識とともに、正確な計算能力やデータ分析能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (145, 18, 9, 'インターネットコンサルタント', 'インターネットコンサルタントは、企業や個人がオンラインでのビジネス活動を最適化するためのアドバイスや戦略を提供する専門家です。彼らはウェブサイトの改善、SEO対策、オンラインマーケティング、ソーシャルメディア活用、デジタル広告戦略など、幅広いインターネット関連の知識と技術を駆使してクライアントのニーズに応えていきます。クライアントがオンラインプレゼンスを向上させ、トラフィックやコンバージョン率を増加させることを目標とします。また、業界の最新トレンドを把握し、適切なデジタル戦略を計画し実行するスキルが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (146, 11, 18, 'ロボット設計技術者', 'ロボット設計技術者は、機械工学、電子工学、コンピュータサイエンスの知識を活用して、ロボットの設計と開発を行います。彼らは新しいロボットシステムの設計、既存のシステムの改善、プロトタイプの作成、実験やテスト、性能の評価など、多岐にわたる業務を担当します。ロボットの用途は様々で、製造業、自動車産業、医療など、幅広い分野で使用されるため、専門的な知識と技術が求められる職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (147, 20, 6, '営業マン', '営業マンは、企業の商品やサービスを顧客に提案・販売する役割を担う職業です。顧客のニーズを理解し、適切な商品やサービスを提案することで、売上を上げることが主な目的です。効果的なコミュニケーション能力と交渉スキルが求められ、顧客との信頼関係を築くことが重要です。また、新規顧客の開拓や既存顧客のフォローアップも重要な業務の一部です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (148, 25, 23, '臨床工学技士', '臨床工学技士は、医療現場で使用される高度な医療機器の操作、維持管理、修理を行う専門職です。彼らは、透析装置、人工心肺装置、人工呼吸器などの生命維持装置を適切に運用し、患者の健康を支援します。また、医療機関での技術アドバイザーとしても働き、安全で効率的な医療提供をサポートします。専門的な知識と技術が求められる職種で、医療スタッフと協力しながらチーム医療の一員として活動します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (149, 19, 3, '経理・財務', '経理・財務は、企業や組織の財務管理を担当します。これには、予算の策定、資金調達、会計帳簿の維持、財務分析、税務申告の準備などが含まれます。経理は通常、日々の会計業務を担当し、財務はより戦略的な財務計画や管理を行います。正確なデータ処理能力と分析力が求められます。また、金融市場や法律に関する知識も重要です。企業の財務健康を維持し、効率的に資本を運用する役割を担います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (150, 18, 39, 'ネットサーファー', '『ネットサーファー』とは、一般的な職業ではなく、インターネットをブラウジングして様々な情報を収集したり、新しいウェブサイトやコンテンツを探索する活動を指すスラングです。趣味として楽しむ人が多く、その中で特定のジャンルやトピックに関する知識を深めることもあります。ただし、これが収入を得るための職業となる場合、ブログやコンテンツの作成、IT関連の業務に役立つ情報の収集など、他の創造的な活動やスキルと組み合わせる必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (151, 22, 34, '郵政外務職員', '郵政外務職員は、主に郵便局において外勤活動を行う職業です。主な業務には郵便物や小包の配達、集荷、郵便局と顧客間のコミュニケーションが含まれます。また、外務職員は配達区域の効率的な管理や、地域コミュニティとの関与も求められることがあります。勤務は基本的に屋外で行われるため、季節や天候の変化に対応する能力も必要です。業務の特性上、顧客対応能力と体力が重要とされる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (152, 6, 15, '電算写植オペレーター', '電算写植オペレーターは、電算写植機を用いて、テキストや画像を印刷物に定着させるための作業を担当します。この職業は、デジタルデータをもとにレイアウトや文字組みを行い、製品として印刷できる形に仕上げることが主な業務です。また、印刷業界における生産工程の一部として、校正や確認作業なども行うことがあります。高度な技術と正確さが求められ、特に細かい文字の調整や画像の配置などの細部に注力する必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (153, 18, 12, 'ネットワークエンジニア', 'ネットワークエンジニアは、組織や会社のコンピュータネットワークの設計、構築、管理、メンテナンスを担当します。ネットワークのパフォーマンスを最適化し、セキュリティを確保するための技術的な支援を行い、故障や問題のトラブルシューティングも行います。クラウドサービスやワイヤレスネットワークを含む多様なネットワークインフラの導入・管理にも携わることが多く、最新のセキュリティプロトコルやネットワーク技術に精通していることが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (154, 29, 27, 'カラーリスト', 'カラーリストは、色を専門に扱う職業であり、主にファッション、インテリアデザイン、美容業界などで活躍します。彼らは色の特性や心理的効果を理解し、クライアントの希望に合わせた色の提案や組み合わせを行います。カラーリストは、色彩検定や色彩に関する専門知識を必要とし、視覚的なセンスも求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (155, 29, 27, '空間デザイナー', '空間デザイナーは、建築、インテリア、展示空間、商業施設など、様々な場所のデザインを担当する職業です。空間の機能性と美観を両立させ、人々が快適に過ごせる環境を作り上げます。使用目的やターゲット層、ブランドのコンセプトなどに応じて空間のデザインを行い、多くの場合、建築士やインテリアコーディネーターと連携してプロジェクトを進めます。設計図の作成、素材の選定、3Dモデルの作成などの技術的なスキルも求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (156, 18, 8, 'ヘルプデスク', 'ヘルプデスクは、組織内外のユーザーからの技術的な問題や質問に対応する役割を担います。主にIT関連のサポートを提供し、電話、メール、チャットなどを通じ、トラブルシューティングや問題解決に当たります。顧客サービスの向上を目指し、迅速かつ的確なサポートを提供することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (157, 26, 25, '図書館司書', '図書館司書は、図書館での資料の収集、整理、保存、及び利用者への情報提供を行う専門職です。主要な業務には、図書や雑誌などの資料の選定と購入、資料の分類と整理、データベースの管理、カウンターでの利用者対応、資料の検索支援やレファレンスサービスの提供が含まれます。司書はまた、図書館のイベントやプログラムの計画と実施も担当することがあります。広範な情報リテラシーや、リサーチスキル、コミュニケーション能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (158, 29, 27, 'インテリアデザイナー', 'インテリアデザイナーは、建物内部の空間を美しく、かつ機能的にデザインする職業です。家庭、オフィス、店舗や公共施設など様々な空間のデザインを手掛け、顧客のニーズやライフスタイルに合わせて最適なインテリアを提案します。カラーコーディネーション、家具やアクセサリーの選択、空間のレイアウトプランニングを通じて空間の雰囲気を演出します。仕事は顧客との打ち合わせ、デザイン案の作成、工事管理など多岐にわたります。技術的な知識と芸術的なセンスが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (159, 29, 27, 'パッケージデザイナー', 'パッケージデザイナーは、商品を保護し、消費者に製品を魅力的に見せるパッケージを設計する職業です。彼らは、素材、形状、色、締め方、印刷技術などを駆使し、商品ブランドに合ったデザインを作ります。また、マーケティング戦略の一環として、パッケージデザインが購買者の心を掴む役割を担います。デザインソフトウェアの使用や、特定の業界規制の知識も求められることが多い職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (160, 22, 30, '通関士', '通関士は、輸出入貨物の通関手続きを専門的に行う国家資格を持つ職業です。主に貿易会社や物流会社、通関業者などで働き、関税や輸入税の計算、必要書類の作成、提出、関係当局との調整を行います。この職務は、国際貿易の円滑な進行をサポートし、法律や規制を遵守することが求められます。通関士は、貿易の法令や規制に関して高度な知識を持ち、常に最新の情報をアップデートしなければなりません。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (161, 33, 9, '消費生活アドバイザー', '消費生活アドバイザーは、消費者の不安や疑問を解消し、暮らしの向上を支援する専門家です。消費に関する情報提供や相談対応、消費者トラブルの解決支援などを行います。また、行政機関や企業、団体などで働き、消費者の声を企業の製品・サービス改善に反映させる役割も担います。消費生活に関わる法律の知識や消費者心理への理解が求められ、消費生活アドバイザー資格の取得が推奨されます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (162, 20, 9, '外資系スタッフ', '外資系スタッフとは、外国資本の会社または外資系企業で働くスタッフのことを指します。主に、英語をはじめとする外国語のスキル、異文化理解能力、グローバルなビジネス感覚が求められる職種です。外資系企業では、その国独自の企業文化やビジネスルールに基づいて業務が進められることが多いため、柔軟な対応力も重要です。待遇や給与の面では一般的に日本企業よりも高めの場合が多いですが、成果主義が強調されることも多いです。具体的な職務内容は企業の業種や規模によって異なりますが、一般的には営業、マーケティング、経理、人事、ITなどの一般職や専門職が該当します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (163, 25, 2, '医療秘書', '医療機関で働き、医師や看護師をサポートする職業です。医療秘書の主な業務には、患者の予約管理、カルテの整理、医師のスケジュール管理、電話応対、診療報酬請求業務などがあります。医療現場での円滑な運営を支える重要な役割を担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (164, 33, 4, '人事', '人事（Human Resources）とは、企業や組織における人材の管理や育成、採用活動、労働環境の整備などを担当する部門です。主な業務には、社員の採用プロセスの企画・実施、評価制度や報酬制度の構築・運用、労働法や労働条件の遵守、社内研修や育成プログラムの設計、コミュニケーションの活性化、人材の異動や配置の計画などがあります。従業員が快適かつ効率的に働ける環境を整えることで、企業全体の生産性を高める役割を担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (165, 28, 15, 'エディトリアルデザイナー', 'エディトリアルデザイナーは、雑誌、新聞、書籍、デジタルメディアなどの編集物のデザインを担当する職業です。編集物の内容に合わせたレイアウトや視覚的な要素を考慮し、読者にとって見やすく、理解しやすいデザインを作成します。字体の選定、写真やイラストの配置、色の選択など、ビジュアルコミュニケーションを主とした作業を行います。クリエイティブなセンスに加えて、編集者や著者と協力しながら効果的なビジュアルを生み出すコミュニケーション能力も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (166, 18, 10, 'WEBプログラマー', 'WEBプログラマーは、WebサイトやWebアプリケーションの設計、開発、保守を行う専門職です。フロントエンドとバックエンドの知識が求められ、HTML、CSS、JavaScriptといった言語や、PHP、Python、Rubyなどのサーバーサイド言語を用います。ユーザー体験の向上や、機能の実装、パフォーマンスの最適化を目的として作業します。また、クライアントやデザインチームと連携し、プロジェクトを成功に導く役割も担います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (167, 19, 31, 'アクチュアリー', 'アクチュアリーは、主に保険や年金などの金融分野で働く専門家で、リスク分析と財務モデリングを通じて、将来的な不確実性を評価し、適切な保険料率や積立金の設定を行います。数学や統計、金融理論の深い知識を活かして、クライアントや企業がリスクに対応するための意思決定をサポートします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (168, 31, 30, '家庭裁判所調査官', '家庭裁判所調査官は、家庭裁判所に所属し、家庭内問題に関する事案を調査する役割を担います。主に離婚、親権、養育費、家庭内暴力などに関連する事件での事実関係を明らかにし、裁判官が適切な判断を下せるようサポートします。また、調停や面接調査を通じて家族問題の解決を図ることもあります。法律や心理学の知識が求められる専門職です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (169, 25, 24, '児童相談員', '児童相談員は、家庭内で虐待やネグレクトを受けている子ども、家族問題を抱える子ども、または福祉サービスを必要とする子どもを支援する専門職です。彼らの役割は、問題の評価、介入策の提案、サポートの調整、ケース管理を行い、子どもの安全と福祉を守ることです。行政機関や施設で働き、専門家や関連組織と協力しながら、必要な法的手続きも含めた包括的な支援を提供します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (170, 18, 16, 'WEBディレクター', 'WEBディレクターは、ウェブサイトやウェブプロジェクトの全体的なディレクションを担当する職業です。プロジェクトの計画、デザイン、開発、運用までの各段階を監督し、クライアントやチームメンバーとのコミュニケーションを通じて、プロジェクトを円滑に進行させます。また、ユーザーエクスペリエンスや使いやすさを考慮しながら、最終的なアウトプットのクオリティを保つために、クリエイティブな提案や問題解決を行うことも求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (171, 33, 30, '公認会計士', '公認会計士は、企業や組織の財務情報を監査し、経理業務全般を管理する専門職です。この職業では、経済や税務の知識が求められ、法律に従って正確な財務報告書を作成することが重要です。公認会計士は、外部監査、税務相談、財務アドバイザリーなど幅広い業務を行い、企業の信頼性と透明性を向上させる役割を果たします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (172, 33, 5, '弁理士', '弁理士は、特許、商標、意匠、著作権などの知的財産権に関する専門家です。主に特許庁への申請書類の作成や、権利の取得手続きを代行する業務を行います。法律知識に基づき、クライアントの発明やブランドを法的に保護する役割を担い、特許紛争の調停や裁判の支援も行うことがあります。技術的な背景と法的知識が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (173, 25, 23, '視能訓練士', '視能訓練士は、視覚に関する専門的な医療職で、視力測定、眼鏡やコンタクトレンズの処方補助、視覚機能のリハビリテーションなどを行います。彼らは眼科医と協力して働き、視覚障害のある患者や、眼鏡やコンタクトレンズが必要な患者のケアをサポートします。また、視覚機能の改善や視覚訓練を通じて患者の生活の質を向上させる役割を担っています。視能訓練士になるためには、指定された専門学校や大学での学位が必要で、多くの場合、国家試験を合格する必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (174, 18, 14, 'ＷＥＢクリエイター', 'WEBクリエイターは、ウェブサイトやウェブアプリケーションのデザイン、開発、およびコンテンツ作成を行う職業です。これには、HTML、CSS、JavaScriptなどのプログラミング言語を使ったコーディングや、Photoshopなどを利用したグラフィックデザインが含まれます。また、ユーザーエクスペリエンス（UX）やユーザーインターフェース（UI）の設計にも関与し、クライアントのニーズに合わせた魅力的なウェブプロジェクトを作成します。クリエイティブな思考力とテクノロジーの知識が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (175, 32, 29, '海上保安官', '海上保安官は、海上保安庁に所属する職員として、海洋の安全・治安維持を目的とした業務を行います。主な業務内容には、海難救助、不法入国や密輸の取り締まり、海洋汚染の防止、航行安全の確保が含まれます。彼らは海上での監視・パトロールを行い、自国の領海を守る重要な役割を果たします。海上保安官はまた、海洋に関するあらゆる事態に迅速かつ適切に対応するため、高度な訓練と知識が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (176, 17, 32, '駐車場管理人', '駐車場管理人は、駐車場の運営と管理を担当する職業です。主な業務内容には、駐車場の利用者への案内やサポート、駐車エリアの監視、精算機の点検や現金管理、駐車場内の安全確保、必要に応じて車両誘導を行うことが含まれます。また、駐車場の清掃や設備のメンテナンスを行い、常に快適で安全な環境を提供する責任があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (177, 18, 8, 'テレフォンオペレーター', 'テレフォンオペレーターは、主に電話を通じて顧客とコミュニケーションを取る職業です。企業のカスタマーサポートやテクニカルサポート、その他の顧客サービス部門で働くことが多いです。電話による問い合わせの対応、情報提供、技術サポート、または問題の解決を行います。良いコミュニケーション能力と、迅速かつ正確に情報を処理する能力が求められる重要な役割です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (178, 32, 25, '法務教官', '法務教官は、刑務所や少年院、保護観察所などの矯正施設で受刑者や非行少年に対して教育や指導を行う専門職です。法務教官は、専門知識を駆使して、受刑者の更生を促すプログラムを企画・実施し、彼らが社会復帰できるようサポートします。また、心理的なケアやカウンセリングを通じて、受刑者が抱える問題や課題を理解し、改善に向けた支援を行います。法務教官は、法律知識だけではなく、教育・心理学の知識も必要とされる重要な職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (179, 16, 20, '造園技術者', '造園技術者は、庭園や公園、都市緑化などの設計、施工、維持管理を行う職業です。自然環境と調和した美しい景観を創出することを目的としています。植物に関する知識はもちろん、デザインのセンスや環境保護についての理解も求められます。また、施工管理や資材調達、関連する法律の知識も必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (180, 20, 2, '営業事務', '営業事務は、主に営業部門をバックアップする役割を担っています。具体的な業務内容としては、受発注管理、契約書作成、顧客データの管理、電話やメールでの問い合わせ対応などがあります。営業スタッフの活動をスムーズに進めるために、効率的で正確な事務処理が求められます。一般的に、コミュニケーションスキルや事務処理能力が重要とされる職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (181, 21, 7, 'マーチャンダイザー', 'マーチャンダイザーは、小売業や商品流通業で商品を消費者に効率的に届けるための戦略を策定・実施する専門職です。この職業には、市場調査、商品計画、在庫管理、販売促進、価格設定などが含まれます。マーチャンダイザーは、トレンド分析を行い、その結果をもとに商品の選定や価格設定を行って利益を最大化する役割を担います。また、店舗の陳列方法やキャンペーンの企画立案を通じて売上向上を目指します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (182, 18, 10, 'プログラマー', 'プログラマーは、コンピュータープログラムを設計、作成、デバッグ、および保守する専門家です。プログラミング言語を用いてソフトウェアやアプリケーションを開発し、仕様に基づいてコードを書くことが求められます。プログラムの効率化、改良、および新機能の追加も担当します。また、必要に応じてチームで協力し合いながらプロジェクトを進めます。最新の技術トレンドやプログラミング技術の継続的な学習が重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (183, 17, 31, '住宅・不動産会社営業部員', '住宅・不動産会社の営業部員は、主に不動産の売買や賃貸に関連する業務を担当します。顧客の要望に基づいて、適切な物件を紹介し、その成約に向けて交渉や調整を行います。また、物件の市場調査、競合分析、価格設定、契約手続きのサポートなども行います。顧客との信頼関係を構築し、長期的な関係を維持することも重要です。これには、顧客とのコミュニケーション能力や交渉力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (184, 20, 34, '貿易スタッフ', '貿易スタッフは、国際的なビジネス取引において、商品の輸出入を担当します。彼らは取引先との交渉、輸出入手続きの管理、必要な書類の準備、発送や受け取りのコーディネート、在庫管理、そして関税や規制の遵守をサポートします。また、新しい貿易市場のリサーチや、為替レートの動向に基づくコスト管理も行うことがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (185, 18, 16, 'トレーサー', 'トレーサーは、製品やプロジェクトの進捗を追跡し、確実にスケジュール通りに進めるための役割を担当する職業です。プロジェクトの各フェーズで設定された目標や締め切りを記録し、チームやマネージャーに進捗状況を報告します。トレーサーは、問題点や遅延が発生した場合にその原因を特定し、適切な解決策を提案する能力が求められます。また、品質管理やドキュメント管理も担当するケースが多く、プロジェクト全体の見通しを把握する必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (186, 18, 10, 'システムエンジニア', 'システムエンジニア（SE）は、企業や組織の情報システムの計画、設計、開発、運用、保守を担当する技術者です。システムの要件を分析し、必要な技術やリソースを把握した上で、効果的なシステム設計を行います。プロジェクトマネジメントの役割を担うこともあり、顧客やチームとのコミュニケーションを通じてプロジェクトを成功に導きます。最新技術の追求やトラブルシューティングの能力も求められる重要な職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (187, 33, 30, '税理士', '税理士は、個人や企業の税務に関する専門家です。具体的には、税務相談、税務申告書の作成、税務調査の対応などを行います。また、税務戦略の立案や節税アドバイスを提供し、顧客が法律に基づいた最適な税務処理を行うのをサポートします。 税理士の資格取得には、一定の学歴や実務経験が求められ、さらに国家試験に合格する必要があります。資格取得後は、顧客の信頼を得て様々な税務業務に従事し、法律の変更にも常に対応していく必要があります。 また、独立して開業することも可能で、顧客のニーズに応じて法人や個人の税務をトータルでサポートすることができます。顧客との良好な関係構築や新規顧客の獲得も重要な業務の一環です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (188, 18, 10, 'デバッガー', 'デバッガーは、ソフトウェアやアプリケーションの開発過程で発生する不具合や問題を特定し、修正するためのツールのことを指します。また、デバッガーを使用して作業を行う職業も存在し、その場合にはプログラムのコードを解析し、エラーの原因を見つけ出すことが求められます。一般的には、プログラマーやシステムエンジニアがデバッガーの役割を担うことが多いです。デバッガーの使用により、プログラムの効率的なデバッグと品質向上が図れます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (189, 28, 26, '翻訳家', '翻訳家は、文書や会話をある言語から別の言語に翻訳する専門家です。彼らは、テキストの意味を忠実に伝えるために、言語間の文化的および文脈的な差異を考慮しなければなりません。翻訳家は、文学、技術マニュアル、法律文書、医療記録など、多岐にわたる分野で活動しています。通常、優れた言語スキルと専門分野に関する深い知識が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (190, 18, 9, 'サーチャー', 'サーチャーは、情報を検索、収集、分析する専門家です。主にインターネットやデータベースを使用して、顧客や組織のニーズに応じた正確で関連性の高い情報を提供します。市場調査、競争分析、学術研究など、さまざまな目的で情報を集めることがあります。論理的思考力やリサーチスキルが求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (191, 33, 7, 'マーケットリサーチャー', 'マーケットリサーチャーは、消費者の嗜好や市場の動向を分析する専門家です。企業が新製品を開発したり、販売戦略を立てたりする際に必要な情報を提供します。データ収集、アンケート調査、統計分析を通じて、顧客のニーズや市場のトレンドを理解し、それを基に提案や報告書を作成します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (192, 22, 34, 'タクシー配車オペレーター', 'タクシー配車オペレーターとして働く場合、主な業務はお客様からの配車依頼に基づいてタクシーを手配することです。多くの場合、電話やオンラインシステムを通じて依頼を受け、適切なドライバーへ迅速に配車指示を送る必要があります。加えて、運行管理システムを使用して車両の位置管理や、乗務員の稼働状況をモニターし、お客様に迅速かつ正確なサービスを提供することが求められます。また、時には顧客からの苦情対応や特別なリクエストにも対応することがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (193, 18, 7, 'WEBコンテンツプランナー', 'WEBコンテンツプランナーは、ウェブサイトやオンラインメディアのコンテンツを企画・計画する職種です。市場動向や顧客のニーズを分析し、それに基づいたコンテンツ戦略を立案します。また、コンテンツの品質管理や進行管理、新たなコンテンツの創出、SEO対策なども担当します。クリエイティブな発想力と高いコミュニケーション能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (194, 28, 15, 'ブックデザイナー／装丁家', 'ブックデザイナー（装丁家）は、本の表紙や外観をデザインする職業です。本の内容やテーマを反映するカバーを作成し、読者の目を引くデザインを追求します。印刷技術や素材選びにも精通し、出版社や著者と緊密に連携して一貫したデザインを提供します。クリエイティブなセンスとグラフィックデザインのスキルが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (195, 27, 38, '研究員', '研究員は、特定の分野において調査や実験を行い、新しい知識や技術の発展を目指す職業です。通常、大学や研究所、企業などで組織的に研究プロジェクトに従事し、この過程でデータの収集や分析、実験の計画と実施、成果の報告などを行います。また、学会や論文発表を通じて研究成果を共有し、新たな研究の基礎を築く役割を担っています。研究の分野は非常に多岐にわたり、科学技術、人文科学、社会科学など様々な領域があります。研究員は高度な専門知識と、継続的な学習能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (196, 17, 30, '土地家屋調査士', '土地家屋調査士は、土地や建物の測量・調査を行い、その結果を基に不動産の登記をする専門職です。具体的には、土地の境界線の確認や建物の配置測量、分割や合併に伴う測量などを行い、そのデータを使って法務局に申請を行います。建物の新築や改築、土地の売買や相続などの場面で必要とされる専門知識を活かします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (197, 28, 7, '広報スタッフ', '広報スタッフは、企業や団体のイメージを向上させるために、さまざまな媒体を通じて情報を発信します。主な業務には、プレスリリースの作成や配信、メディアとの関係構築、イベントの企画や運営、ソーシャルメディアの管理などが含まれます。広報の役割は、組織のブランド力を高め、業績をサポートすることです。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (198, 18, 10, 'WEBマスター', 'WEBマスターは、ウェブサイトの管理や維持を担当する職種です。具体的な業務には、ウェブサイトの更新やコンテンツの管理、ユーザーアクセスの分析、サイトのセキュリティ対策、トラブルシューティング、サーバー管理などが含まれます。WEBマスターは、サイトのパフォーマンスを最適化し、ユーザーエクスペリエンスを向上させる役割を果たします。また、新しい技術やトレンドを取り入れ、サイトの改善や新しい機能の提案も行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (199, 33, 30, '行政書士', '行政書士は、日本の法律に基づき、官公署に提出する許認可や届出の書類の作成を行う専門職です。主な業務として、企業や個人から依頼を受けて、官公署へ提出する書類の作成や相談を受け付けます。また、法律や制度の知識を活かして、顧客の法的な手続きを支援します。建設業許可や入管手続き、会社設立など広範な分野での業務があり、法律や倫理に関する深い知識が求められます。国家資格であり、各都道府県の行政書士会に登録し、独立して業務を行うことができるのが特徴です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (200, 11, 18, 'CADオペレーター', 'CADオペレーターは、コンピュータ支援設計（CAD）ソフトウェアを使って、建築、機械部品、電気回路などの設計図を作成・修正する職業です。図面をもとに精密な設計を行い、設計者やエンジニアと協力してプロジェクトを進めます。正確さと詳細さが求められ、多くの場合、専門的な知識とスキルが必要とされます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (201, 18, 25, 'OA機器インストラクター', 'OA機器インストラクターは、オフィスオートメーション（OA）機器、例えばコンピューターやプリンター、ファクシミリ、スキャナーなどの使用方法を指導する仕事です。これには、機器の操作だけでなく、ソフトウェアの使い方、メンテナンスの方法、トラブルシューティングなども含まれます。顧客や企業の要望に応じたトレーニングプログラムを作成し、実際の操作指導を行います。技術的な知識はもちろんのこと、指導力やコミュニケーション能力も必要とされる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (202, 31, 28, '地方公務員', '地方公務員とは、地方自治体に勤務し、行政サービスの提供や地域の発展に貢献する職員を指します。具体的には、市町村や都道府県の役所で働くことが一般的で、業務内容は多岐にわたり、住民のための窓口業務、都市計画、社会福祉、教育、環境政策などがあります。給料や福利厚生が安定していることが特徴で、地域社会の一員として公共の利益に寄与することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (203, 25, 2, '医療事務', '医療事務は、医療機関での受付業務、会計処理、診療報酬請求（レセプト）業務などを担当する職業です。患者の予約管理やカルテの整理、医師や看護師との連携を図り、円滑な診療のサポートを行います。専門的な知識を必要とし、正確かつ迅速な業務が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (204, 31, 28, '国家公務員Ⅰ種', '国家公務員�T種は、日本の国家公務員試験の一つで、国の行政機関や関連施設で高度な専門知識を要する職務に従事する職員を採用するための試験です。主に国の政策策定や行政運営における中核的な役割を担うポジションを目指す人向けの試験とされ、特に政策形成や法律、経済に関する知識を活かした職場での活躍が期待されます。この試験に合格すると、各省庁の幹部候補として採用されることが一般的です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (205, 18, 10, 'ソフトウェア開発技術者', 'ソフトウェア開発技術者は、コンピュータープログラムやアプリケーションの設計、開発、テスト、保守を行う専門家です。プログラミング言語や開発ツールを駆使して、クライアントやユーザーのニーズに応じたソフトウェアソリューションを提供します。また、プロジェクトマネージメントスキルや、チームでの協調力が求められることが多い職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (206, 33, 2, '一般事務', '一般事務は、企業や組織の日常業務を円滑にするためのサポート役を担います。典型的な業務には、文書作成、ファイリング、電話応対、来客対応、メールの管理、データ入力、スケジュール管理などがあります。業務内容は勤務先によって異なる場合がありますが、基本的にはオフィス内でのサポート業務が中心です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (207, 4, 33, 'ショコラティエ', 'ショコラティエは、チョコレートを専門に取り扱う菓子職人のことです。チョコレートの原料を選び、加工し、多種多様なチョコレート製品を製作します。レシピの開発やデザインにも関与し、バレンタインデーやクリスマスなどの特別なイベントに向けた製品も手掛けます。味だけでなく、見た目にもこだわり、芸術的な要素を取り入れた商品を提供します。通常、製菓学校での訓練や経験を積むことでスキルを磨きます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (208, 24, 27, 'テーブルコーディネーター', 'テーブルコーディネーターは、食事の際のテーブルの装飾や配置を担当する職業です。美しい食卓を演出することで、食事の雰囲気をより一層引き立て、視覚的な楽しみを提供します。イベントやパーティー、レストランでのサービスなどで、特定のテーマやスタイルに合わせたテーブルセッティングを行います。顧客の希望に応じて、食器、カトラリー、グラス、ナプキン、センターピース、花の配置などを選択し、統一感のある空間を作り上げます。美的センスと調整能力が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (209, 29, 18, 'レストア技術者', 'レストア技術者は、古い機械や車両、オブジェ、建築物などをもとの状態に戻すための修理や保存を行う専門家です。彼らは、歴史的価値のあるアイテムを修復し、その独自性と美しさを回復させる役割を担っています。多くの場合、技術者は部品の交換や補修、塗装の再現、素材の保護処理などを行います。動力機械から美術品まで多岐に渡る対象とし、幅広い知識とスキルを駆使します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (210, 4, 33, 'パン職人', 'パン職人は、さまざまな種類のパンや焼き菓子を作る専門技術を持つ職業です。主に小麦粉、イースト、砂糖、塩、乳製品などの原材料を使用し、生地を練り、発酵させ、焼成する一連の工程を管理して、美味しく焼き上げることを目指します。パン職人は製造技術だけでなく、レシピ開発や職場の衛生管理にも精通している必要があります。また、顧客の好みや需要に応じて、新しいパンの種類を試行錯誤しながら提供するクリエイティブな側面も求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (211, 33, 30, '標題書士', '標題書士は、日本における不動産の登記や供託などを専門に行う法律専門職です。土地や建物の所有権を法的に正確に記録するための手続きを行い、権利の保護に寄与します。また、会社設立に関わる登記や成年後見業務も手がけることがあります。必要な司法登記手続きを迅速かつ正確に行うことで、不動産売買や相続に伴う紛争を未然に防ぐ役割を果たします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (212, 6, 27, '漆器製造工', '漆器製造工は、伝統的な手法で漆器を製造する職人です。漆器は、木や竹などの天然素材を下地とし、その上に漆という天然の樹液を塗布して作られます。作業は通常、下地作り、漆塗り、装飾といった複数の工程に分かれ、非常に細かい技術と経験が必要とされます。漆器はその美しい光沢と耐久性が特徴であり、日本の伝統工芸品として高く評価されています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (213, 10, 21, '金属プレス工', '金属プレス工は、金属を加工するための専用のプレス機械を操作し、金属板を希望の形に整える職業です。具体的には、金属板を機械にセットし、プレスをかけることで、曲げや型抜き、穴あけなどの加工を行います。多くの場合、製造業や加工業の工場で勤務し、安全に機械を操作するスキルと、作業の精度を高める能力が求められます。安全装置の使用や、機械のメンテナンスも重要な業務の一部です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (214, 11, 21, '機械組立工', '機械組立工は、工場や製造現場で機械や装置の組み立てを行う職業です。手作業や工具、場合によっては専用の機械を使用して部品を接合し、最終的な機械製品を完成させます。工程では図面を参照しながら作業を進め、品質や安全に対する厳しい基準に従います。熟練した技術が求められ、しばしばチームでの協力が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (215, 16, 20, '内装工', '内装工は、建物の内装に関する工事を行う職業です。具体的には、壁や天井のクロス貼り、床の張替えや設置、照明や家具の取り付けなど、インテリアに関連する作業を担当します。専門的な技術とセンスが要求されるため、経験や資格があると有利です。住宅だけでなく、オフィスや商業施設の内装工事も行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (216, 10, 21, '金型工', '金型工は、製品を製造するための金型を作成し、保守・管理する仕事です。金型はプラスチック、金属、ゴムなどの材料を一定の形状に成形するための型枠として機能します。金型工は、設計図を基に金属などの素材を機械で加工し、精密な金型を作り上げます。金型の正確さや耐久性は生産効率に大きく影響するため、高度な技能や精密な作業が求められます。また、金型の修理や改造も行い、製品の品質維持に貢献します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (217, 16, 20, '鉄骨工', '鉄骨工とは、主に建設現場で鉄骨を使った構造物の組み立てや設置を行う作業員のことです。仕事内容には、鉄骨の加工、溶接、設置、そして建物の骨組みを組み立てる業務が含まれます。高所での作業も多く、安全対策が非常に重要です。体力と技術が求められる職業であり、施工計画に基づき正確かつ迅速に作業を行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (218, 10, 21, 'ＮＣフライス盤工', 'NCフライス盤工は、数値制御装置（NC）を使用してフライス盤を操作し、金属やその他の素材を加工する職業です。主に、自動車部品や機械部品の製造に関わることが多く、高精度の加工を行うためにNCプログラムの設定や機械の調整、メンテナンスが求められます。また、加工された製品の品質チェックや生産効率の向上に努めることも重要な仕事です。技術的な知識と経験が必要で、プログラミングスキルも持っていると有利です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (219, 16, 20, 'タイル工・レンガ工', 'タイル工は、建物の内外装にタイルを貼り付ける専門職です。具体的な作業は壁や床の下地を平らにし、適切な接着剤を用いてタイルを正確に配置します。この職業は美観を追求するための視覚的なセンスと、持続する質感を提供するための技術力が求められます。耐久性のある仕上がりを実現するため、細心の注意を払ってタイルを貼る必要があります。
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (220, 10, 21, '圧延工', '圧延工は製鉄所やその他の製造業において金属を薄く延ばしたり、形状を整えたりするために、熱や圧力を用いて金属の板や棒を加工する職種です。通常、大きな圧延機を操作し、材料の温度や厚み、形状を正確に管理しながら作業を行います。安全管理と精密な操作が求められるため、専門知識や技術が必要とされます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (221, 36, 20, '浄化槽設備士', '浄化槽設備士は、建物や施設の浄化槽システムの設計、設置、保守管理を行う専門職です。この職業は、浄化槽を適切に設置し、正常に機能させることで、環境への影響を最小限に抑えることを目的としています。浄化槽設備士は、環境保護に関心がある人にとって魅力的な職業といえます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (222, 16, 20, '左官', '左官職人は、建築物の壁や床などに塗り材を塗布する専門職です。セメント、石膏、漆喰などの材料を使用し、美しい仕上がりを追求します。日本では伝統的な家屋の壁塗りや現代建築の内装仕上げなど、幅広い作業を行います。細かな技術と美的センスが求められますが、手に職をつけることができる職業です。また、独立して自営業を営むことも可能です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (223, 16, 20, '建築ブロック工', '建築ブロック工は、建築現場で使用するコンクリートブロックの製造や組み立てを行う職人です。この職業は、建築の基礎から外構工事に至るまで、さまざまな工程で重要な役割を担います。具体的な作業内容としては、ブロックの成形、順序良く組み上げる作業、耐久性を確保するための補強などがあります。精度の高い作業が求められ、建物の安全性や品質に直接影響を与えるため、注意深さと経験が重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (224, 16, 20, '建築大工', '建築大工は、建物の建設や改修に関与する職業です。具体的には、木材を使った構造体の組み立て、屋根や壁の設置、内装や外装の仕上げ作業を行います。大工は、図面を読み取り材料を選定し、工具を駆使して高精度に作業を進める能力が求められます。また、安全性を考慮した作業を行うことも重要です。この職業では、物理的な強靭さと細やかな技術力が要求されます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (225, 29, 27, '彫金家', '彫金家は金属を加工して美しいアートやジュエリーを制作する専門職です。さまざまな金属を用い、技術や創造力を駆使してデザインを形にします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (226, 16, 18, 'プラント設計技術者', 'プラント設計技術者は、発電所、石油化学工場、製薬工場などの産業プラントの設計、構築を専門に行う技術者です。彼らはプロジェクトの要求に基づいてプラントの構造、装置の配置、配管システム、電気システムなどを設計します。安全性、効率性、環境への影響を考慮しつつ、規制基準に沿った設計を行うことが求められます。さらに、プロジェクトの進捗を監視し、必要に応じて設計の修正を指導することもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (227, 16, 20, '土木施工管理技士', '土木施工管理技士は、主に土木工事の現場において施工管理を行う専門職です。この職業は、道路、橋、ダム、トンネルなどの公共事業を中心に、工事の進捗管理、安全管理、品質管理を担当します。施工管理技士は、プロジェクトが計画通りに進むように調整し、必要な資材や人員の手配を行う役割を担います。さらに、施工に関連する技術的な指導や業務の効率化のための提案を行うこともあります。この職業には、現場での実務経験が求められることが多く、適切な資格を取得することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (228, 16, 20, 'とび工', 'とび工（鳶職）は、建設現場で足場を組んだり、鉄骨を組み立てたりする専門職です。高所での作業が多く、安全性が重要視されます。力仕事が多いですが、チームで協力しながら建物の骨組みを作り上げる責任感のある職業です。建設業界の中でも、特に腕力と技術が求められる仕事です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (229, 29, 17, 'モデラー', 'モデラーは、製品、建物、人物などの三次元モデルを設計・作成する専門職です。この職業はさまざまな業界で必要とされており、特にアニメーション、ゲーム開発、映画制作、建築、工業デザインなどで重要な役割を果たしています。モデラーはデジタルツールを駆使して、対象物の形状、質感、動きなどを精密に再現することが求められます。クリエイティブと技術的なスキルが必要で、チームでの効果的なコミュニケーション能力も求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (230, 9, 21, 'ガラス食器製造工', 'ガラス食器製造工は、主にガラスを材料にして、さまざまな食器や家庭用品を製造する職業です。具体的には、ガラスの溶解、成形、装飾、仕上げなどの工程を通じて製品を作り上げます。技術と芸術的なセンスを活かし、デザインや機能性に優れた食器を作成することが求められます。工場での大量生産から、職人的な技術を活かした手作り製品まで、さまざまな製造方法が存在します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (231, 29, 27, '照明デザイナー', '照明デザイナーは、建築物、イベント、舞台、インテリアなどの空間における光の配置と設計を担当する職業です。その目的は、光を使用して空間の美しさ、雰囲気、機能性を向上させることです。具体的には、照明計画の策定、照明器具の選定、視覚効果のデザインなどを行います。環境やテーマに応じた光の色温度や明るさ、陰影などを調整し、空間全体の調和を図ります。技術的知識に加え、創造力や芸術的センスも求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (232, 14, 21, 'NC旋盤工', 'NC旋盤工は、数値制御（NC: Numerical Control）技術を活用して金属や他の材料を加工し、精密部品を製造する職業です。コンピュータ制御の旋盤機を操作し、通常は事前にプログラムされた指示に従いながら、材料を削る、切断する、穴を開けるなどの作業を行います。必要な技能には、NC旋盤の操作技術、加工プログラムの理解、図面の読解力、および製造精度を確保するための品質管理能力が含まれます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (233, 13, 18, '自動車整備士', '自動車整備士は、車両の点検、修理、整備を担当する専門職です。エンジン、トランスミッション、ブレーキ、空調システムなど、車両のメカニカルおよび電気的な部分を診断し、問題を解決します。安全性と性能を確保するために、予防的なメンテナンスも行います。最新の技術とツールを使用し、車両の状態を把握して適切な整備を提供します。整備技術者資格（国家資格）を持っていることが一般的です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (234, 10, 21, '鋳物工', '鋳物工は、金属や合金を溶融し、鋳型に流し込んで固めることで製品を作り出す職業です。仕事内容には、鋳造するための準備、溶解炉の操作、金属を鋳型に流し込む作業、固化後の仕上げ作業などが含まれます。鋳物製品は、機械部品、車両部品、建築用素材など幅広い分野で利用されます。物理的な労力を必要とするほか、高温の金属や機械を扱うため、安全管理が重要です。また、材料や鋳造技術に関する専門知識の理解も求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (235, 12, 21, 'IC生産オペレーター', 'IC（集積回路）生産オペレーターは、半導体工場においてICの製造を担当する職種です。この役割には、製造装置の操作、品質管理、製品の検査、トラブルシューティングなどが含まれます。生産プロセスでは、高度な自動化がなされており、機械操作と製品の正確な管理が求められます。また、クリーンルーム環境での作業が一般的であり、細心の注意が必要です。この職種は、技術と細部に対する強い焦点が要求されるため、技術的なトレーニングや経験が有利に働きます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (236, 16, 27, 'キッチンスペシャリスト', 'キッチンスペシャリストは、キッチン空間のデザイン、計画、アドバイスを行う専門職です。顧客のニーズやライフスタイルに合わせた機能的で美しいキッチンを提案し、設計図面の作成や素材の選定、設備の配置などを手掛けます。また、施工会社や職人との連携を通じて、計画を実際の形にするためのサポートも行います。建築の知識やインテリアデザイン、最新の調理設備についての知識が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (237, 29, 27, '木工工芸家', '木工工芸家は、木材を材料として家具や装飾品、彫刻などの作品を製作する職業です。多くの木工工芸家は、自らデザインを考え、手作業で木材を加工し、独自の技術と芸術性を活かして作品を作り上げます。伝統的な技法を用いることもあれば、現代的な技術や材料を組み合わせることもあります。職人としての専門的なスキルが求められる他、市場のニーズに応じたデザイン性と実用性のある作品作りも重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (238, 16, 20, '造園施工管理技士', '造園施工管理技士は、造園工事の計画、施工、管理を行う専門職です。庭園や公園、都市緑化などの造園プロジェクトにおいて、工事の進行を監督し、品質や安全を確保するための役割を担います。具体的には、施工計画の作成、資材の手配、作業員の管理、建設現場の安全確保、関係者との調整など、多岐にわたる業務を行います。また、国家資格である造園施工管理技士資格を持つことで、一層の信頼性と責任を持った業務が可能になります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (239, 12, 18, 'ホームエレクトロニクス技術者', 'ホームエレクトロニクス技術者は、家庭用電化製品や電子機器の設置、修理、保守を担当する専門職です。具体的には、エアコン、冷蔵庫、洗濯機、電子レンジなどの調整やトラブルシューティング、故障の診断と修理を行います。普通は製造元や専門の修理会社、または家電量販店に勤務し、顧客の自宅へ出向くことが多い職種です。また、新製品のセットアップや旧製品からのデータ移行も担当することがあります。良好なコミュニケーションスキルと、迅速かつ的確な問題解決能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (240, 22, 18, '船舶機関士', '船舶機関士は、船舶のエンジンやその他の機械設備の運転及び保守を担当します。主な仕事には、エンジンの操作、機械設備の点検、保守整備、故障発生時の修理対応などがあります。燃料や油の管理、エンジンの動作監視を行い、安全で効率的な航行をサポートします。通常は海技士の免許が必要で、大型船舶の場合は複数の機関士がチームで作業を行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (241, 10, 21, '溶接工', '溶接工は金属の部品や構造物を溶接機を用いて接合する職業です。溶接は金属部分を強固に結びつけるために必要で、自動車、造船、建設などの多くの産業で重要な役割を果たします。溶接工は、溶接を行うための技術的なスキルと安全基準を守ることが求められます。また、多くの場面で物理的な強さと注意力が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (242, 11, 21, 'マシニングセンタ・オペレーター', 'マシニングセンタ・オペレーターは、コンピュータ制御の工作機械を操作して、金属部品の加工作業を行う専門職です。具体的には、設計図に基づいて機械の設定を行い、金属素材を切削加工して製品を作ります。この作業には、高度な計算能力と技術的な理解が必要です。注意深いチェックと微調整を通じて、高い精度と効率性を持った生産を達成します。安全基準を常に守りながら作業を行うことが求められます。また、メンテナンスやトラブルシューティングの能力も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (243, 5, 21, 'パタンナー', 'パタンナーはファッションデザインの分野で、衣服の製作過程において重要な役割を果たします。デザイナーが作成したスケッチやデザイン図に基づいて、衣服の型紙（パターン）を作成するのが主な仕事です。この職種には、デザインの意図を理解し、正確なサイズや形をパターンに反映させる技術と経験が求められます。また、他のスタッフと協力してサンプル服の作成やフィッティングを通じて、パターンの調整・修正を行うこともあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (244, 18, 8, 'カスタマーエンジニア', 'カスタマーエンジニアとは、顧客に対する技術サポートやサービスを提供する職種です。この職業では、顧客の要望や問題を理解し、製品やサービスの使用方法を説明したり、トラブルシューティングを行って顧客満足度を高める役割を担います。また、新しい技術の導入や設定、保守などを行うこともあります。基本的には、顧客対応が主であり、コミュニケーション能力や技術知識が重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (245, 25, 23, '義肢装具士', '義肢装具士は、事故や病気で手足を失った人や身体の機能が低下した人に対して、義肢や装具を製作・適合させる専門職です。患者一人ひとりの身体の特徴やニーズに合わせてカスタムメイドの製品を提供し、日常生活の質を向上させる支援を行います。医師や理学療法士と連携し、患者のリハビリテーションや社会参加をサポートします。技術力とコミュニケーション能力が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (246, 21, 32, 'フレグランスコーディネーター', 'フレグランスコーディネーターは、お客様に適切な香水や香りを提案する専門職です。主にデパートや香水店、ファッションブランドのショップなどで働きます。顧客の好みや目的に応じて最適なフレグランスを選び、香水に関する豊富な知識を活かしてアドバイスを行います。また、新製品のプロモーションや香りの体験イベントの企画・運営なども行うことがあります。センスやコミュニケーション能力が求められる仕事です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (247, 4, 19, 'フードスペシャリスト', 'フードスペシャリストは食品に関する専門的な知識と技術を持つ職業であり、食品の製造、品質管理、商品開発、栄養相談などを行う。食品に関する幅広い知識を持ち、食品の安全性、栄養価、調理における工夫などのアドバイスを提供する。食品関連業界や健康産業での活躍が期待される職種である。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (248, 5, 27, '染色工', '染色工とは、布や衣類、衣服の素材等を染める専門職です。伝統的な技法を用いて、特定の色や模様を布地に染めつける作業が中心となります。染色工は、自然素材や化学染料を使用し、顧客の要求に応じた色やデザインを実現するための染色技術を駆使します。また、染色の工程における素材の選定や手順の計画、染料の調合、温度管理など、細かな調整が求められる職業です。日本の伝統工芸品の製作や、ファッション業界などで活躍することが多い職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (249, 5, 39, '和裁士', '和裁士は、日本の伝統的な和服を作る職人です。着物や浴衣などの和服を、布の裁断から縫製までを行い、注文者の体型や要望に合わせて仕立てます。多くの場合、手縫いで丁寧に作業を進めるため、高い技術と経験が求められます。また、生地の特性や柄の配置など、デザイン面でもセンスが問われる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (250, 21, 6, '商品バイヤー', '商品バイヤーは、小売業や卸売業において、顧客のニーズを満たすために商品の仕入れを担当する職種です。市場の動向や消費者の嗜好を分析し、適切な商品を適切な価格で調達することで販売戦略をサポートします。取引先との交渉や新商品の開拓、在庫管理なども重要な業務に含まれます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (251, 29, 27, '雑貨デザイナー', '雑貨デザイナーは、日常生活で使用される雑貨やアクセサリー、インテリア用品などの製品をデザインする仕事です。各プロジェクトにおいて、市場のトレンドや顧客の要望を考慮してクリエイティブなアイデアを出し、商品化に向けて具体的なデザインを作成します。プロトタイプの製作、素材選定、生産ラインへの指示など、製造工程にも関わることがあります。美術やデザイン関連のスキル、色彩感覚、商品開発やマーケティングの知識が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (252, 5, 21, 'ソーイングスタッフ', 'ソーイングスタッフは、衣類や布製品を縫製する専門職です。主に工場や縫製会社、アトリエで働くことが多く、デザイン図に基づいて生地を裁断し、ミシンや手縫いで製品を仕上げます。精密な技術と経験が求められる職業であり、新しい技術やファッションの動向も重要です。また、品質管理や納期の管理、他スタッフとのコミュニケーションも大切です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (253, 13, 27, 'カーデザイナー', 'カーデザイナーは、車両の外観やインテリアデザインを担当する職業です。美しいデザインだけでなく、機能性や安全性を考慮しながら、車の形状やスタイルを考えます。市場のトレンドや顧客のニーズを把握しつつ、さまざまなデザインコンセプトを提案し、実現可能な形に落とし込んでいきます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (254, 37, 38, '宇宙飛行士', '宇宙飛行士は、宇宙船に搭乗し、宇宙へ行くための訓練を受けた専門職です。彼らは宇宙での実験や観測を行い、有人ミッションの目的を達成するために働きます。宇宙飛行士は、科学者、パイロット、エンジニアなどのバックグラウンドを持つことが多く、高度な技術知識と身体的・精神的な能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (255, 9, 27, '陶芸家', '陶芸家は、粘土を使って手作業や電動ろくろを用いて器や彫刻を作成する職業です。作品の制作過程には、形を整える成形、暖炉で焼き固める焼成、色合いを加える釉薬の工程が含まれます。創造性と技術が求められる分野であり、伝統的な技巧と現代的なデザインの融合を図ることがしばしばです。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (256, 26, 25, '小学校教員', '小学校教員は、小学生に対して基礎的な教育を行う職業です。主に、算数、国語、理科、社会科などの教科を教える役割を担います。また、クラスの担任として生徒の生活面や成長をサポートし、保護者とのコミュニケーションを図ることも求められます。授業の計画、教材の準備、テストの作成・実施、成績評価などの日々の業務に加え、生徒の多様なニーズに対応しながら、社会性やコミュニケーション能力の育成を目指します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (257, 26, 38, '大学教授', '大学教授は、大学や短期大学で教育と研究を担当する職業です。彼らは専門分野の講義を行い、学生の指導やカウンセリングを行うほか、国際的な学会や論文発表を通じて研究活動を推進します。また、大学や学部の運営に関わることもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (258, 22, 34, '航海士', '航海士は、船舶の安全で効率的な航行を計画、指揮、監督する職業です。彼らは船の航路を設定し、気象情報や海図を使って最適な航行ルートを選択します。また、航行中の監視を行い、船が安全に目的地に到達するための調整を行います。航海士は通常、船長や他の船員と密接に連携し、船舶の運航業務を支援します。必要な資格や訓練を受けた専門職であり、海上での経験が求められることが多いです。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (259, 36, 36, 'ビオトープ管理士', 'ビオトープ管理士は、人間と自然環境とが調和した共生環境の創出と維持を目的に、ビオトープ（生物多様性に富んだ生態系の限られた地域）を計画、設計、管理する専門家です。彼らは自然保護のための調査や、生物多様性の保全活動、そして教育活動なども行います。ビオトープ管理士は、生態学や環境学の知識を活かし、持続可能な環境を維持するための重要な役割を果たします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (260, 25, 23, '理学療法士', '理学療法士は、病気やけが、障害を持つ人々の身体機能の回復を支援する専門職です。患者個々の症状や生活環境を考慮し、リハビリテーションプランを作成・実施します。主な業務には、患者の運動能力評価、運動療法の指導、日常生活動作のサポート、患者やその家族への指導や教育が含まれます。整形外科、神経学、呼吸器科、 geriatrics (高齢者医療) において特に重要な役割を果たします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (261, 13, 21, '自動車組立工', '自動車組立工は、自動車の製造工程において、自動車を組み立てるための作業を行う職種です。具体的な作業には、部品の取り付け、ボルト締め、配線の設置、ドアや窓の装着などが含まれます。この職種は通常、工場のライン作業として行われ、効率性と精度が求められます。自動車の品質に直接影響を与える重要な役割を担っており、手作業と機械の操作を組み合わせて作業を進めます。身体的な強さと手先の器用さが重要なスキルです。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (262, 35, 32, 'ネイリスト', 'ネイリストは、手や足の爪を美しく整えるプロフェッショナルです。一般的な業務には、爪の切りそろえ、ネイルアート、ジェルネイルの施術、マニキュアやペディキュアの提供が含まれます。また、衛生管理や顧客のニーズに応じた提案力も求められます。ネイリストは美容サロン、スパ、または独立して働くことが多いです。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (263, 28, 15, 'DTPオペレーター', 'DTPオペレーター（Desktop Publishing Operator）は、デジタルデスクトップパブリッシング技術を用いて印刷物のレイアウトやデザインを行う職業です。主に、コンピュータソフトウェアを使用して出版物や印刷物の作成、編集、デザインを行います。具体的な業務には、広告、雑誌、新聞、カタログ、ポスターなどの制作が含まれます。クライアントの要求に応じたデザインの調整や、色やフォントの選定、画像の加工なども行います。印刷所や広告代理店、出版会社などで働くことが多く、グラフィックデザインの知識やソフトウェアスキルが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (264, 18, 6, 'セールスエンジニア', 'セールスエンジニアは、技術的な知識と営業のスキルを組み合わせた職種です。製品やサービスに関する専門的な知識を持っており、それを活用して顧客の要望を理解し、最適なソリューションを提供します。主な業務には、クライアントとの技術的な打ち合わせ、製品のデモンストレーション、技術的な疑問に対するサポート、提案書の作成などがあります。また、営業チームと緊密に連携し、特定の顧客のニーズに応じたカスタマイズや提案を行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (265, 7, 22, 'バイオ技術者', 'バイオ技術者は、生物学的プロセスを利用して新しい製品や技術を開発する専門家です。彼らは通常、研究所で働き、医薬品、農業、食品科学、環境保護などの分野で応用される技術の開発や改良に携わります。実験を設計し、データを分析し、研究の成果を実用化につなげる役割を果たします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (266, 35, 1, '管理美容師', '管理美容師は、美容室やヘアサロンにおいて、スタッフの管理やサロンの経営、サービス提供の品質を保障する役割を担います。顧客への施術だけでなく、スタッフのシフト管理、教育、仕入れや在庫管理など、多岐にわたる業務があります。管理職としてのスキルや美容業界の知識が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (267, 33, 1, 'リフォーマー', 'リフォーマーは、組織や制度の改善・改革を主に担当する職業です。具体的には、公共政策の分析、戦略の策定、実施に伴うリスクの評価や解消に取り組みます。政府機関、非営利団体、企業などで働くことが多く、社会的な課題を解決することで組織や地域の持続的な発展を目指します。コミュニケーション能力、分析力、戦略的思考が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (268, 28, 26, 'ルポライター', 'ルポライターとは、事件や社会問題、文化やライフスタイルなど、現実に起きている出来事について現地に赴き、取材を行って記事を書くジャーナリストの一種です。彼らは通常、新聞、雑誌、またはオンラインメディアに記事を寄稿します。現場の情報を読者に伝えるため、正確な情報収集とインタビュー能力が求められます。緊迫した現場や危険な状況での取材が必要な場合もあり、高い危機管理能力と倫理観が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (269, 10, 21, '貴金属宝石細工工', '貴金属宝石細工工は、金、銀、プラチナなどの貴金属やダイヤモンド、ルビー、サファイアといった宝石を用いてジュエリーや装飾品を製作します。この職業では、デザインの考案から材料の選定、加工、組み立てまで多岐にわたる工程を担当します。高度な技術と繊細な手作業が要求され、美術的な感性と職人的なスキルが重要です。また、顧客の要望に応じたオーダーメイドの製品を提供することもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (270, 35, 32, '理容師', '理容師は、男性の髪や髭の手入れを専門とする職業であり、カット、シャンプー、シェービングなどのサービスを提供します。日本では多くの場合、理髪店で働いています。理容師は顧客の希望に応じて髪型を提案し、顔や頭の形に合ったスタイルを提供します。また、衛生管理も重要で、道具の消毒や作業スペースの清潔さを維持することが求められます。理容師になるためには、専門的な訓練を受け、国家資格の取得が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (271, 36, 36, 'グリーンアドバイザー', 'グリーンアドバイザーは、庭園、パーク、屋外空間の緑化や美化に関する専門的な知識とアドバイスを提供する職業です。彼らは植物の選定、植栽計画、環境に優しいガーデニング技術などに関する提案を行い、持続可能な景観設計を促進します。また、地域に適した植生の選定や土壌の改良、植栽のメンテナンス方法に関するアドバイスなども行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (272, 13, 18, 'チューニングエンジニア', 'チューニングエンジニアは、自動車やオートバイのエンジンやサスペンション、排気システムなどを最適化して性能を向上させる専門家です。彼らはお客様のニーズや希望に応じて、車両の設定を調整し、エンジンの出力や燃費効率を高めます。主に自動車関連の業界で働き、スポーツカーやレースカーのパフォーマンスを向上させるためのカスタマイズを行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (273, 33, 9, '経営コンサルタント', '経営コンサルタントは、企業や組織が抱える課題を分析し、解決策を提案する専門職です。経営戦略の立案、業務プロセスの改善、コスト削減、新規事業の開発など、幅広い分野でクライアントを支援します。専門的な知識や分析力が求められるほか、クライアントとのコミュニケーション能力や提案力も重要です。様々な業種に対応できるため、多様な経験を積むことが可能です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (274, 24, 33, 'パティシエ', 'パティシエは、菓子やデザートを専門に作る調理専門職です。主にケーキ、クッキー、チョコレート、タルトなどの製菓製品を開発し、製作します。また、新しいレシピの開発や、食材の選定、デザインを担当することもあります。飲食店、ホテル、ベーカリー、専門店などで働くことが多く、イベントや特別な注文に応じて特別なデザートを提供することもあります。視覚的な美しさと味覚的な満足を提供するために、技術と創造性が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (275, 33, 30, '弁護士', '弁護士は、法的問題に関する専門知識を持ち、法律相談や裁判での代理、契約書の作成・確認、法的紛争の解決などを行う専門職です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (276, 35, 32, '美容師', '美容師は、主に顧客の髪をカット、スタイリング、カラーリングする専門家です。美容師は髪型の提案や美容に関する相談なども行い、顧客の希望に合わせたヘアスタイルを提供します。また、トリートメントやシャンプー、パーマなどの技術も必要とされることが多く、美容に関する最新のトレンドや技術を常に学ぶことが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (277, 6, 21, '家具職人', '家具職人は、木材や金属、布などを用いて家具を制作する職業です。家具職人は、設計図に基づいて材料を切断、成形、組み立てを行い、美しくて機能的な家具を作り出すことを目指します。また、仕上げや装飾も行い、顧客の要望に応えたオーダーメイド家具の制作も行います。創造力と技術力が問われる職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (278, 25, 23, '栄養士', '栄養士は、個人または集団に対して健康的な食事を促進し、健康維持や病気予防のサポートを行う専門職です。食品の選択や調理方法を指導し、特定の健康状態や栄養ニーズに基づいて栄養計画を立てます。学校、病院、福祉施設、企業等、さまざまな場所で活躍しています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (279, 29, 15, '写真・映像処理オペレーター', '写真・映像処理オペレーターは、主に写真や映像の編集・加工を行う職種です。これには、画像の色調整、トリミング、レタッチ、映像のカット編集やエフェクトの追加などが含まれます。デジタルコンテンツを制作する企業や広告代理店、撮影スタジオなどで働くことが多く、Adobe PhotoshopやAdobe Premiere Pro、Final Cut Proなどのソフトウェアを使用するスキルが求められます。クリエイティブなセンスと技術力を兼ね備えた職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (280, 31, 28, '検察事務官', '検察事務官は、検察庁において検察官の補佐業務を行う職員です。主な業務は、訴訟に関する書類作成や管理、証拠の整理、関係者への連絡及び調整、裁判所への書類提出などです。また、事件の捜査や立証のサポートも行い、法務省や他の司法機関との連携を図ります。司法試験合格者ではあるが、検察官任官を希望しない場合や検察事務を主にしたい場合に選ばれる職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (281, 11, 21, 'NC研削盤工', 'NC研削盤工は、数値制御（NC: Numerical Control）技術を用いて研削盤を操作する職業です。研削盤は主に金属やその他の素材を非常に高い精度で削るための設備であり、機械部品や工具を製造する際に重要な役割を果たします。NC研削盤工は、プログラムによって機械の操作を制御し、指定された寸法や形状に仕上げるために、生産計画や仕様書に基づいて研削プロセスを遂行します。また、機械のメンテナンスやトラブルシューティングを行うことも必要です。高い技術力と精度が求められる作業であり、安全に配慮しながら効率よく作業を進めることが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (282, 29, 27, '画家', '画家は、視覚芸術の分野で活動し、絵画を制作する職業です。様々なスタイルや技法を駆使し、キャンバスや紙、壁画などあらゆる表面に絵を描きます。画家は通常、自分の個性やメッセージを作品に込め、展覧会やギャラリーで作品を展示・販売します。また、美術教師や挿絵画家としても活動することがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (283, 16, 20, 'エクステリアデザイナー', 'エクステリアデザイナーは、建物の外装や庭園、外構部分のデザインを専門とする職種です。住宅や商業施設のエクステリアの設計・提案を行い、美観や機能性を高める役割を担います。クライアントの要望を基に、景観や使用する素材、照明等を考慮してプランニングを行い、外観全体の統一感を持たせることを目指します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (284, 35, 27, 'メイクアップアーティスト', 'メイクアップアーティストは、顧客の要求に合わせてメイクを施す専門家です。映画、テレビ、劇場、ファッションショー、ブライダル、特別イベントなど、さまざまな状況で活動します。顔の特徴を引き立てるための技術と、トレンドに応じたスタイルや色彩を提案するセンスが求められます。また、化粧品や美容に関する豊富な知識を持ち、特定のテーマやキャラクターに合わせたメイクをデザインすることもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (285, 28, 15, 'WEBビデオディレクター', 'WEBビデオディレクターは、ウェブプラットフォーム用のビデオコンテンツの企画、制作、編集を担当する職業です。彼らはビデオ制作プロジェクトの全体的なビジョンを設定し、撮影や編集の管理、クリエイティブな発案、制作スケジュールの管理、チームとの調整を行います。また、視聴者のニーズやプラットフォームの特性に応じたコンテンツを制作する能力が求められます。マーケティングチームやクライアントと密接に協力して、ビデオが目的を達成するよう手助けする役割も果たします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (286, 29, 27, 'インテリアプランナー', 'インテリアプランナーは、建物の内部空間を利用者のニーズや好みに応じて設計・デザインする職業です。彼らはレイアウトプラン、色彩計画、生地や家具の選定、照明計画などを担当します。また、クライアントと密にコミュニケーションを取りながら、予算や機能性を考慮しつつ、美しく快適な空間を創造することを目指します。建築やインテリアに関する専門知識とデザインセンスが求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (287, 18, 17, 'ゲームプログラマー', 'ゲームプログラマーは、ビデオゲームの開発においてソフトウェアプログラムを設計、構築、テスト、および維持する専門家です。彼らは通常、ゲームの物理エンジン、AI（人工知能）、ネットワーク機能、グラフィカルインターフェースの開発を担当します。必要なスキルには、C++やUnity、Unreal Engineなどのプログラミング言語やプラットフォームの知識があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (288, 28, 15, 'アートディレクター', 'アートディレクターは、映画、テレビ、広告、雑誌、ウェブサイト、その他のメディアプロジェクトの視覚的スタイルとイメージを開発および監督する責任を持つ職業です。彼らはデザインコンセプトを策定し、プロジェクトの視覚的要素が対象とする観客に最適に伝わるように努めます。通常、デザイナーやイラストレーター、写真家などのチームを指導し、プロジェクトの統一感と美的品質を保つ役割を担います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (289, 18, 10, 'WEBテクニカルディレクター', 'WEBテクニカルディレクターは、主に企業やプロジェクトのインターネット上でのプレゼンスを強化し、技術的な戦略を立案し、プロジェクトの成功に寄与する役職です。彼らは、WEB開発チームをリードし、最新の技術を駆使して高品質のウェブサイトやオンラインプラットフォームを構築します。また、クライアントの要求を理解し、技術仕様に落とし込み、デザイナーやデベロッパーとの連携を図ります。テクノロジーのトレンドに敏感であり、革新的なソリューションを提供するための技術的指導も行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (290, 29, 27, 'インテリアコーディネーター', 'インテリアコーディネーターは、住宅や商業施設の内装を美しく、機能的にデザインする専門職です。クライアントの要望やライフスタイルに合わせて家具、カーテン、照明、色彩などを提案し、空間をトータルコーディネートします。創造性が求められる一方で、日程や予算管理などの実務的なスキルも必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (291, 28, 17, 'CGデザイナー', 'CGデザイナーはコンピュータグラフィックスの設計と制作を行う職業です。主に映画、テレビ、ゲーム、広告などの分野でキャラクターや背景、エフェクトなどをデジタルでデザインし、ビジュアルコンテンツを制作します。デジタルツールやソフトウェアを駆使して、リアルで魅力的なビジュアルを作り出すことが求められます。創造力と技術力が必要で、プロジェクトに合わせたスタイルや表現を追求することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (292, 29, 15, 'WEBイラストレーター', 'WEBイラストレーターは、インターネット上で使われるイラストを専門に描く職業です。主にウェブサイトやソーシャルメディア、オンライン広告におけるビジュアルコンテンツの制作を担当します。仕事内容には、クライアントの要望に合わせたオリジナルイラストのデザインや商品コンセプトに基づくキャラクター作成などが含まれます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (293, 29, 27, 'インダストリアルデザイナー', 'インダストリアルデザイナーは、消費者向け製品や商業用製品のデザインを担当する職業です。美的かつ機能的で使いやすい製品を生み出すため、しばしばデザインとエンジニアリングの橋渡し役を務めます。プロジェクトに応じて市場調査やコンセプト開発、プロトタイピングを行い、最終的な製品の形状、色彩、仕上げを決定します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (294, 16, 20, '建築士', '建築士は、建物の設計や施工管理を行う専門職です。都市計画から住宅、商業施設など、多岐にわたる建造物のデザインを担当します。建築基準法や安全基準を遵守し、美しさと機能性を兼ね備えた建築物を提案する役割を担います。資格取得が必要で、多くは建築学を専攻した後、必要な実務経験を積んで資格試験に合格します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (295, 18, 14, 'WEBデザイナー', 'WEBデザイナーは、ウェブサイトのデザインとレイアウトを作成する職業です。ユーザーエクスペリエンス（UX）やインターフェース（UI）のデザインを考慮し、視覚的に魅力的で使いやすいウェブページを設計します。具体的には、色彩、フォント、画像、グラフィック、レスポンシブデザインなどを用いて、ブランドやクライアントの要求に沿ったデザインを提供します。最新のデザインソフトウェアとツールを使用し、HTMLやCSSの基礎知識も必要とされることがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (296, 28, 26, 'エディター', 'エディターとは、文章や映像、音声などのコンテンツを編集する職業です。文章編集の場合、ライターが書いた原稿の内容をチェックし、誤字脱字や文法ミスを修正するほか、文章の流れや構成を改善します。映像や音声のエディターは、撮影された素材をカットし、音楽や効果音を追加して映像作品や音声作品を完成させます。クリエイティブな側面と緻密な校正能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (297, 25, 23, '診療情報管理士', '診療情報管理士は、医療機関において、患者の診療情報を効果的に管理する専門職です。この職業の主な役割は、診療記録の収集、分析、保管、セキュリティ管理を行うことです。また、電子カルテシステムや医療情報システムの運用、データの統計解析、医療情報のコンプライアンス管理にも関与します。医療の質を向上させるために、診療情報の正確さを保証し、医療チームに情報を提供する重要な役割を担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (298, 12, 18, 'パソコン組立･調整工', 'パソコン組立･調整工は、コンピュータを構成する各部品を選定し、組み立て、動作が正常であることを確認する職業です。この職業では、ハードウェアの知識が求められ、クライアントの要望に応じて最適なパソコンを構築します。具体的には、マザーボード、CPU、メモリ、ストレージ、電源、ケース、冷却システムなどを選び、正確に取り付けます。また、ソフトウェアのインストールやシステムの設定も行います。技術的なトラブルシューティングやサポートもこの職業の重要な役割です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (299, 25, 23, '保健師', '保健師は公衆衛生に関する専門的な知識と技術を持ち、地域や企業などで人々の健康を守るための活動を行う職業です。彼らは健康診断や保健指導を通じて、病気の予防や健康の維持・増進を支援します。また、健康教育や保健計画の策定、健康相談を行うこともあります。保健師になるためには、看護師資格を取得した後、保健師養成課程を修了し、国家試験に合格する必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (300, 21, 6, 'ＯＡ機器販売員', 'OA機器販売員は、オフィスオートメーション（OA）機器、たとえばプリンター、コピー機、ファクシミリ、スキャナーなどのオフィス機器を企業や個人に販売する職業です。顧客のニーズを聞き取り、最適な商品を提案・販売しながら、保守契約などの提案も行うことがあります。また、新製品の紹介や使い方の説明、定期点検なども担当することが多いです。市場調査や販売戦略の立案、営業ノルマの達成など営業的なスキルも求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (301, 23, 32, '通訳ガイド', '通訳ガイドは、外国人観光客に対して観光地を案内し、その地の歴史、文化、観光スポットなどを説明する専門職です。言語能力だけでなく、地元の知識や文化に関する深い理解と共に、コミュニケーション能力が求められます。また、日本では通訳案内士資格を取得することが一般的です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (302, 23, 33, 'ホテルレストランスタッフ', 'ホテルレストランスタッフは、ホテル内のレストランでのサービスを提供する職種です。主な業務には、ゲストの案内、オーダーの受付、食事や飲み物の提供、テーブルの片付けなどが含まれます。ゲストに快適で満足のいく食事体験を提供することが求められます。また、サービス業務だけでなく、時にはレストランの清掃や簡単な調理補助を行うこともあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (303, 17, 31, '土地活用プランナー', '土地活用プランナーとは、土地を有効に活用するための提案や計画を行う専門職です。この職業では、不動産市場の動向や地価の変動、地域の条例などを踏まえて、最適な土地活用を提案します。例えば、賃貸物件を建設すること、自社物件を運用すること、土地を売却すること、あるいは農地転用や駐車場経営など、多岐にわたる選択肢を考慮し、クライアントにとって最も利益を得られる方法を見つけ出します。土地活用プランナーは、不動産会社や建設会社に勤めることが多く、法律や税務の知識も必要とされます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (304, 25, 23, 'オプティシャン', 'オプティシャンは、眼鏡やコンタクトレンズ、その他の視力矯正用具を提供する専門職です。顧客の視力処方箋をもとに、最適な視力矯正器具を選び、調整する役割を担います。視力検査やフレームのフィッティング、レンズの加工などを行い、顧客に最適な視覚補助を提供します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (305, 35, 32, 'リフレクソロジスト', 'リフレクソロジストは、足裏や手のひらにある特定の反射ゾーンをマッサージし、体のバランスを整え、健康を促進しようとする専門職です。この技術は、ストレス軽減やリラクゼーション、痛みの軽減、内臓機能の改善を目指しています。リフレクソロジーの考え方では、特定のゾーンが体の特定の部分や臓器に対応しているとされています。リフレクソロジストは通常、リラクゼーションサロンや健康センターなどで働いています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (306, 34, 37, '神職', '神職とは、神社において神事や祭祀を司り、神々を祀る役割を担う職業です。主に、神事の準備や進行、参拝者への対応、社務所での業務などを行います。神道に関する知識や伝統的な礼儀作法が求められ、文化財や自然の保護にも関わることがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (307, 34, 37, '僧侶', '僧侶は、宗教的・精神的な修行を通じて、仏教の教えを広め、実践する専門職です。彼らは寺院での儀式の主催や、信者への相談や指導、社会福祉活動を行うなど、多岐にわたる役割を担っています。僧侶としての生活は、仏教の戒律に従い、瞑想や勉学を続けることが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (308, 34, 37, '巫女', '巫女とは神社に奉仕する女性のことです。主に神社の儀式や祭祀に関わる仕事をしており、神聖な職務として尊重されています。巫女は神事を行う際の補助や、社殿の清掃、参拝者の案内を担当することが多いです。また、正月や祭礼の際などには、巫女装束を身にまとっての奉仕も行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (309, 35, 24, 'ナニー', 'ナニーは、家庭で子供の世話を専門的に行う職業です。彼らは子供の食事、入浴、遊び、学習のお手伝い、そしてしばしば学校への送り迎えなどを担当します。また、家庭内の簡単な家事や、場合によっては子供の健康管理なども行います。柔軟な労働時間が求められることが多く、家庭ごとに異なるニーズや条件に対応する必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (310, 22, 33, 'キャビンアテンダント', 'キャビンアテンダントは、航空機に搭乗している間、乗客の安全と快適性を確保するために働く職業です。主な業務には、搭乗時の案内や安全指示、飲食物の提供、緊急時の対応が含まれます。また、搭乗員として、乗客の質問に答えたり、特別な配慮が必要な乗客のサポートも行います。対人スキルが求められ、異なる文化やライフスタイルを持つ人々と接する機会が多い職場です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (311, 16, 21, '非破壊検査員', '非破壊検査員は、製品や構造物を破壊することなく、その品質や安全性を評価する専門家です。主に超音波やX線、磁気検査、浸透探査などの技術を用いて、欠陥の有無や物性を調査します。これにより、建築物や機械部品、航空機などの安全性を確保し、事故を未然に防ぐ役割を担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (312, 28, 27, '楽器リペアマン', '楽器リペアマンは、楽器の点検、修理、調整を行う専門職です。これには、楽器のメンテナンスや故障部の診断、必要な修理や部品交換、調整作業が含まれます。主に音楽スタジオや楽器店、個人の音楽家向けにサービスを提供します。様々な楽器に精通しており、古い楽器の復元や調整を行うことも多い職業です。楽器の構造や機能を深く理解しており、音響の知識も必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (313, 21, 32, 'DIY店店員', 'DIY店店員は、お客様が自分で作業を行うための材料や道具を提供し、アドバイスやサポートを行う職業です。店内の商品に詳しく、どのように使用するかについてアドバイスできる能力が求められます。また、商品管理やレジ業務、在庫管理なども担当します。DIYやホームインプローブメントに興味があると役立つでしょう。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (314, 21, 32, '書店店員', '書店店員は、本を販売する店舗で働く職業です。彼らの主な業務には、顧客への接客や本の案内、書籍の在庫管理、店内ディスプレイの設置、レジでの会計業務などが含まれます。顧客の要望に応じて適切な書籍を提案したり、書籍に関する質問に答えることも求められます。また、新刊や販売促進キャンペーンの実施の管理にも携わることがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (315, 35, 27, 'ピアノ調律師', 'ピアノ調律師は、ピアノの音を正しくするための調整を行う専門職です。ピアノ内部の弦やハンマーの位置を調整し、正確な音高を出すようにします。ピアノの音質や音の高さを維持するために、定期的な調律が必要となります。また、調律だけでなく、ピアノの修理やメンテナンスも行うことがあります。音楽の理解と精密な作業が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (316, 32, 35, '警備員', '警備員は、建物や施設、イベント会場などで安全を確保し、犯罪や事故を未然に防止するための職業です。主な業務内容には、巡回や監視カメラのモニタリング、入退室の管理、緊急時の対応などがあります。勤務形態はシフト制が多く、夜間や休日の勤務もあります。冷静な判断力と柔軟な対応力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (317, 7, 23, '薬種商', '薬種商は、医薬品や薬品を販売する専門職である。この職業では、医薬品の有効性や安全性に関する深い知識が求められ、さらに法律に基づく適切な方法で顧客に薬品を提供することが求められる。薬種商は、製薬会社やドラッグストア、薬局に勤務することが多く、顧客への情報提供や相談にも応じる役割を担っている。業務には、医薬品の在庫管理や品質管理なども含まれることがある。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (318, 25, 23, '歯科衛生士', '歯科衛生士は、歯科医師と協力して患者の歯と口腔の健康を維持する専門職です。主な業務には、歯石の除去、歯のクリーニング、フッ素塗布、口腔衛生指導が含まれます。また、歯科医師の診療を補助し、患者のカルテ管理や器具の準備・消毒を行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (319, 35, 24, 'ベビーシッター', 'ベビーシッターは、子供の世話を一時的に引き受ける職業です。親や保護者が不在の際に子供の安全を守り、遊びや世話を行います。仕事の内容には食事の準備、ゲームやアクティビティの計画、宿題の手伝い、そして子供の身の回りの世話などが含まれます。柔軟な勤務時間が多く、家庭や施設で働くことが一般的です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (320, 21, 32, 'シューフィッター', 'シューフィッターは、顧客に対して靴のフィッティングサービスを提供する専門職です。この職業では、顧客の足の測定を行い、そのデータに基づいて最適な靴のサイズやタイプを提案します。シューフィッターは、顧客が快適に靴を履けるよう、適切な靴の選択をサポートする重要な役割を担っています。また、足の形状や健康上の問題を考慮に入れたアドバイスを行うこともあります。特に、整形外科的な問題を抱える顧客に対する対応能力が求められることがあります。この職業は、靴店や専門店、百貨店などで働くことが一般的です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (321, 28, 6, '広告会社営業部員', '広告会社営業部員は、広告代理店や広告会社に務め、クライアント企業との関係を構築し、広告キャンペーンの提案から実施までをサポートする役割を担います。彼らは、クライアントのニーズを理解し、適切な広告戦略を立案し、提案します。また、広告の効果測定やフィードバックを行い、次回のキャンペーンの改善に役立てます。さらに、広告媒体やクリエイティブ部門との調整役としての役割も重要です。営業スキル、コミュニケーション能力、マーケティング知識が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (322, 22, 34, '倉庫スタッフ', '倉庫スタッフは、商品の受け取り、保管、梱包、発送など、倉庫内での様々な作業を担当します。効率的な在庫管理を行い、商品の出荷がスムーズに行われるよう手配します。業務には、重い物の持ち運びやフォークリフトの操作が含まれることもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (323, 22, 18, '鉄道パーサー', '鉄道パーサー（車両検査員）は鉄道業界において、列車の安全運行を確保するために鉄道車両の点検やメンテナンスを行う専門職です。車両のブレーキ、台車、電気系統、連結装置などの各種装置を定期的にチェックし、故障や異常が無いかを確認します。また、車内の検査や清掃を行うことも含まれます。安全基準に基づいた作業を行い、事故防止に努める重要な役割を担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (324, 25, 23, '柔道整復師', '柔道整復師は、伝統的な日本の医療職であり、主に骨折・脱臼・打撲・捻挫といった外傷を非外科的手法で治療する専門家です。柔道整復術を用い、患者の自然治癒力を活かして治療を行います。国家資格試験に合格し、登録を受けることでこの職業に就くことができます。整形外科などの医療機関や整骨院で勤務することが多く、スポーツトレーナーとしての役割を果たすこともあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (325, 25, 23, '助産師', '助産師は、妊娠中の女性への健康指導や、出産の介助、新生児のケアを行う専門職です。女性が安全に出産できるようサポートする上で、産科医と協力しながら重要な役割を果たします。また、母親が自信を持って子育てを始められるよう、授乳指導や育児相談も行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (326, 25, 23, '診療放射線技師', '診療放射線技師は、医療現場でX線、CT、MRI、超音波、核医学などの医用画像機器を使用し、患者の病気や怪我の診断をサポートします。彼らは医師からの指示に基づき、適切な画像を取得するために機器を操作し、安全で効果的な検査を行います。また、患者への説明や検査の準備、後片付けなども担当します。放射線量の管理や機器のメンテナンスも重要な役割を担います。高い専門性と技術力が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (327, 35, 35, '家電修理工', '家電修理工は、壊れた家電製品を診断し、修理する専門職です。テレビ、冷蔵庫、洗濯機、電子レンジなど、さまざまな家電製品に対して技術的な知識とスキルを活かして修理を行います。日常的には、故障の原因を特定し、必要な部品を交換したり、調整を行ったりします。また、お客様に対するアドバイスやメンテナンスの提案も行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (328, 1, 36, '樹木医', '樹木医は、樹木の健康状態を診断し、病害虫の駆除や栄養管理を行う専門職です。自然環境や都市の緑化を守り、樹木の健康と安全を維持する役割を担います。具体的には、土壌分析や樹木の傷の処置、施肥、剪定などの作業を行い、環境保護や景観の維持にも貢献します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (329, 25, 2, '病棟クラーク', '病棟クラークは、病院の病棟で事務作業を担当する職員です。患者の入院受付やカルテ管理、電話応対、医療チームとの連絡・調整などが主な業務です。医療の専門知識は不要ですが、事務処理能力やコミュニケーション能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (330, 35, 35, 'クリーニング師', 'クリーニング師は、衣類や布製品のクリーニングや手入れを専門とする職業です。彼らは、さまざまな素材や汚れに応じた洗浄方法を熟知しており、洗濯や乾燥、アイロンがけ、さらに場合によっては修理や補色まで行います。クリーニング師は、基本的な手作業から高性能なクリーニング機械を扱う技術も必要です。特にデリケートな素材の取り扱いや特殊なシミ抜き技術について、専門的な知識と経験が求められます。また、顧客対応のスキルも重要で、依頼内容を確認し、最適なクリーニング方法を提案することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (331, 21, 32, '眼鏡販売店員', '眼鏡販売店員は、眼鏡やコンタクトレンズの購入を検討している顧客に対し、商品を提案し、適切なフィットを助ける役割を担います。視力検査やフレームの調整を行い、顧客のニーズやライフスタイルに合った選択肢を提供します。また、店内の商品管理や在庫管理、接客も重要な業務の一部です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (332, 26, 25, '幼稚園教諭', '幼稚園教諭は、主に3歳から5歳までの幼児を対象に、基本的な生活習慣や社会性を育む教育を行う職業です。幼児の発達段階に応じた遊びや学びの活動を計画し、実施することで、子どもたちの創造性や協調性を育てます。また、保護者とのコミュニケーションを通じて、子どもの成長を一緒に見守る役割も担います。国家資格である幼稚園教諭免許状が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (333, 35, 32, 'アロマセラピスト', 'アロマセラピストは、アロマテラピーという芳香療法を用いて、クライアントの心身のリラクゼーションや健康増進を促進する専門家です。精油（エッセンシャルオイル）を使って、マッサージや吸入、入浴など様々な方法で施術を行います。クライアントのニーズに合わせてブレンドを調整し、自然治癒力を高めるサポートを提供します。さらに、セラピストは香りの専門知識を活かし、リラクゼーションだけでなく精神的ストレスの軽減や特定の健康問題の改善を図ります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (334, 35, 25, '犬訓練士', '犬訓練士は、犬の行動を訓練し、行動の問題を解決するプロフェッショナルです。主な業務には、犬に基本的なコマンドを教えたり、吠える、咬むといった行動問題を改善するためのトレーニングを行ったりすることが含まれます。また、ペットオーナーへ犬の扱い方やしつけの仕方を指導することも重要な役割の一部です。室内外での訓練プログラムを作成し、犬やペットオーナーと密にコミュニケーションを取りながら進めることが求められます。特に、個々の犬の性格やニーズに合わせたカスタマイズされたトレーニング計画を立てる能力が重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (335, 25, 23, '歯科医師', '歯科医師は、患者の口腔内の健康状態を診断し、治療や予防処置を行います。これには歯のクリーニング、虫歯の治療、歯科矯正、歯周病の管理、抜歯、歯科補綴物の装着などが含まれます。また、患者に対して歯の健康を保つための指導や助言を行うことも重要な役割です。歯科医師になるには歯科大学を卒業し、国家試験に合格する必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (336, 19, 31, '生命保険外交員', '生命保険外交員とは、保険会社に所属し、顧客に対して生命保険商品を提供し、販売する専門職です。この職種では、顧客との信頼関係を築くことが重要であり、ニーズを的確に把握して適切な保険プランを提案する能力が求められます。また、新規顧客の開拓や契約のクロージング、アフターサービスの提供も業務の一環となります。業界の知識とともに、コミュニケーション能力や営業技術も必要とされます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (337, 25, 23, '整体師', '整体師は、身体の歪みや不調を徒手的な技法で調整し、健康を促進する専門職です。筋肉や関節の調整を行い、身体全体のバランスを改善することを目的としています。患者の症状に応じて、様々な手技を用いることがあります。多くの場合、リラクゼーションサロンや整体院で働いています。国家資格は必要ありませんが、関連する技術や知識を学ぶための専門学校や講習会に参加することが一般的です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (338, 13, 35, '二輪自動車整備士', '二輪自動車整備士は、オートバイやスクーターなどの二輪車に関する整備や修理を行う専門職です。具体的には、エンジンの調整、部品の交換、車両の点検、トラブルシューティング、およびそれに伴う診断を行います。安全で快適な走行が可能となるように、車両のあらゆる側面をチェックし、高い技術を用いて問題を解決します。また、新車の組み立てや中古車の整備なども担当することがあります。業務はディーラーや修理工場、自動車教習所などで行われることが多く、顧客への説明やサポートも重要な業務の一部となります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (339, 16, 20, '防水工', '防水工は、建物や構造物の防水工事を行う専門職です。具体的には、屋根や地下室、ベランダ、浴室などの様々な場所に防水材料を適用することで、水浸しや漏水の防止を目的としています。防水工事には、シート防水、塗膜防水、注入式防水など様々な方法があり、材料の種類や建物の構造に応じて適切な方法を選択する必要があります。安全で高品質な仕上がりを確保するため、技術知識と経験が必要です。また、作業は屋外で行われることが多く、天候に影響を受けることもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (340, 25, 24, 'ケースワーカー', 'ケースワーカーは、福祉や社会サービスの分野で働く専門家で、個人や家族が必要とするサポートを提供します。具体的には、生活支援、カウンセリング、リソースの紹介、およびクライアントのニーズに応じたサービス調整を行います。ケースワーカーは、現場でクライアントとの面談や相談業務を行いながら、彼らの生活の質の向上を支援します。また、必要に応じて、行政機関や他の福祉サービスと連携して、適切なサポートを提供しています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (341, 30, 37, 'スポーツインストラクター', 'スポーツインストラクターは、個人またはグループに対して運動やスポーツの指導を行う専門家です。クライアントのフィットネスレベル、目標、健康状態を考慮し、トレーニングプランを作成し、適切な技術やフォームを教えます。また、モチベーションを高めるためのサポートも行います。ジム、フィットネスクラブ、公共施設、または個人宅などで働くことが一般的です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (342, 35, 35, 'ビル清掃員', 'ビル清掃員は、主にオフィスビルや商業施設などで建物の内部と外部を清掃・維持する仕事です。具体的には、床の掃除、ゴミの収集と廃棄、窓ガラスの清掃、トイレや共用スペースの消毒などを行います。また、建物内の衛生環境を保つために、定期的な清掃スケジュールに従って作業をします。業務は早朝や夜間、営業時間外に行われることが多いです。清掃に使用する器具や洗剤の取り扱いについての知識や、健康と安全に関する注意事項を理解していることが求められます。体力を必要とする側面がありますが、多くの人にとっては充実感のある仕事となっています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (343, 17, 31, '不動産鑑定士', '不動産鑑定士は、不動産の価値を公正に評価する専門家です。主に土地や建物の価格を査定し、その結果を基にクライアントに対してアドバイスを行います。不動産取引や相続、資産運用などの場面で重要な役割を果たし、不動産市場の健全な発展に寄与します。法律や経済、建築に関する深い知識が求められ、公的機関や民間企業で活躍することができます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (344, 1, 36, 'ブリーダー', 'ブリーダーは、特定の動物種や品種の繁殖を専門とする職業です。彼らは健康で良質な性格を持つ動物を育て、しばしばそれをペットとして人々に販売します。この職業には、動物の遺伝学や健康管理に関する深い知識が必要で、動物の世話や訓練、繁殖計画の立案と実行が主な業務に含まれます。また、動物の適正な環境管理と一般社会への啓蒙活動も重要な役割を果たします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (345, 30, 37, 'スポーツトレーナー', 'スポーツトレーナーは、アスリートや体育愛好者の体力向上や競技力の向上をサポートする専門職です。個々のニーズに応じたトレーニングプログラムを作成し、正しい運動フォームを指導し、怪我の予防やコンディショニングの管理を行います。さらに、栄養アドバイスや心理的サポートを提供することもあります。プロスポーツチームやフィットネスジム、高校や大学の運動部などで活動することが一般的です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (346, 1, 36, '農業', '農業は、動物の飼育や植物の栽培を通じて食糧や原材料を生産する産業です。作物の育成や収穫、家畜の管理などが主な業務であり、自然環境との密接な関係が求められます。また、農業は地域の経済や文化にも大きな影響を与える重要な役割を担っています。現代では、技術の進歩により効率的で持続可能な方法が模索されています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (347, 24, 33, 'ソムリエ', 'ソムリエは、主にレストランやワインショップにおいて、ワインに関する専門的な知識を持ち、顧客にワインの選定、サービス、および保管などを担当する職業です。ワインの風味や適切な食事との組み合わせを提案し、顧客のワイン体験を豊かにします。また、ワインリストの作成や在庫管理も担当することがあります。高いコミュニケーション能力とワインに関する深い知識が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (348, 7, 6, '医薬情報提供者', '医薬情報提供者（MR、Medical Representative）は、製薬会社に所属し、医薬品に関する情報を医療従事者（医師、薬剤師、看護師など）に提供する専門職です。医薬情報提供者は、製薬会社が製造・販売する医薬品の効能や使用方法、副作用情報などを医療機関に伝える役割を担います。医療現場において、医薬品の正確な使用や新薬の情報提供を通じて、医療の質の向上に寄与します。コミュニケーション能力や専門知識が求められる職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (349, 13, 6, '自動車営業マン', '自動車営業マンは、自動車を購入したい顧客に対して適切な車種やオプションを提案し、販売を行う専門職です。顧客のニーズを正確に把握し、最適な提案をすることで販売を成功させることが求められます。営業スキルに加えて、車に関する知識やマーケット動向を理解していることが重要です。また、販売後のフォローアップや顧客サービスも含まれます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (350, 6, 21, 'プロセス製版オペレーター', 'プロセス製版オペレーターは、印刷物に対する製版作業を行う専門職です。通常、デジタルデータを用いて印刷プレートを作成し、高品質な印刷を実現するために使用されます。具体的には、コンピュータを使ってデザインデータを印刷可能な形式に変換し、そのデータを基にして製版機で印刷プレートを作成します。高い精密度と細心の注意が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (351, 35, 32, 'トリマー', 'トリマーは、犬や猫などの動物の毛をカットし、美しく整える職業です。顧客の要望に合わせてペットの外見を修正し、日常のケアや特別なイベントに向けて準備します。トリミングの技術や動物に対する深い理解・愛情が求められます。また、シャンプーやリンス、耳掃除、爪切りなどの基本的なグルーミング作業も行います。ペットがストレスを感じないように落ち着かせる技術やコミュニケーション能力も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (352, 4, 19, '食品技術者', '食品技術者は、食品の製造プロセスや品質管理、製品開発を担う専門職です。彼らは通常、食品の安全性、栄養価、風味、食感を向上させるために科学的および技術的な方法を用い、食品の製造過程を効率的かつ効果的に改善します。また、新しい食品製品を開発したり、既存の製品を改良したりすることもあります。食品技術者は、食品科学、化学、工学の知識を生かして、食品産業の発展に貢献しています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (353, 21, 32, 'DPEショップ店員', 'DPEショップ店員とは、主に写真現像を専門とする店舗に勤務する職業です。顧客から依頼されたフィルム写真やデジタルデータの現像、印刷、加工を行います。具体的な業務には、写真の受付や現像機器の操作、写真の品質管理、アルバムやフォトブックの制作、また店内の商品販売や接客なども含まれます。最新のデジタル技術を取り入れ、効率的に顧客の要望に応えるスキルが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (354, 1, 36, '森林インストラクター', '森林インストラクターは、自然環境や森林の保護、教育、管理に関連する専門職です。彼らの役割は、学校や一般市民を対象に森林の重要性や生態系について啓発活動を行い、森林の持続可能な利用を推進することです。インストラクターは、森林の中での安全で効果的な活動の指導を行い、自然体験プログラムや野外活動の企画・運営も担当します。また、伐採や植林、森の保全作業の指導も行うことがあります。専門知識を活かし、健康で豊かな自然環境の維持を目指します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (355, 24, 33, 'クッキングアドバイザー', 'クッキングアドバイザーは、料理に関する専門的な知識とスキルを活かして、さまざまな人々に対して食事プランやレシピの提案、調理のアドバイスを行う職業です。レストランやカフェにおけるメニュー開発、健康的な食生活を考えた献立作り、食材の選び方や調理方法についての指導を行います。また、料理教室を開催したり、フードブログやコラムの執筆を通じて料理の楽しさや技術を広める役割もあります。クッキングアドバイザーは、料理が好きで食に関する知識を深めたい方、他者とその情報を共有する意欲がある方に適した職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (356, 23, 7, '観光局スタッフ', '観光局スタッフは、地域の観光資源を活用し、観光地の魅力を広める役割を担っています。具体的な業務には、観光案内業務やイベントの企画・運営、観光データの収集や分析、広報活動、地域住民や観光客との交流促進などが含まれます。また、観光客に快適で安全な旅行体験を提供するための施策提案や実施も行います。外国語スキルが求められることも多く、コミュニケーション能力や地域の知識を活かして活躍する職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (357, 31, 28, '国家公務員Ⅲ種', '国家公務員�V種は、主として一般事務や技術系（例えば土木、電気など）の補助業務を行う職位です。これらの職務は日本の行政機関において行われ、安定した雇用環境と公務員としての社会的信用を得られます。応募資格は高校卒業程度であり、採用試験を通過する必要があります。異動や転勤がある可能性があり、地域を問わず日本全国での勤務が求められることがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (358, 25, 23, 'カイロプラクター', 'カイロプラクターとは、脊椎をはじめとする身体の痛みや違和感に対する徒手療法を提供する専門職です。彼らは薬や手術を使用せずに、背骨や関節の矯正を行い、自然治癒力の向上を図ります。カイロプラクティックの施術は、特に腰痛、首の痛み、頭痛などで悩む患者に対して有効とされています。資格を得るためには、専門の教育機関でのトレーニングおよび資格取得が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (359, 22, 34, '路線バス運転士', '路線バス運転士は、都市部や地方の公共交通機関として、定められた路線を走行し、乗客を安全かつ時間通りに目的地へ運ぶ役割を担う職業です。具体的な業務内容には、運転業務だけでなく、時刻表の確認、乗降客の案内、運行状況の把握、車両の安全点検、事故やトラブルへの対応などがあります。バス運転士は通常、大型自動車第二種運転免許が必要とされており、安全運転への高い意識が求められます。また、地域によっては早朝や深夜の勤務、休日勤務もあるため、柔軟な勤務時間に対応できることが望ましいです。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (360, 16, 18, '電気工事士', '電気工事士は、住宅やビルなどの建物内外で電気設備の設置や保守、改修を行う技術者です。電気配線やコンセント、照明器具の取り付け、配電盤の設置などを担当し、安全かつ効率的な電気供給を確保します。国家資格である電気工事士免許が必要であり、実務の際には安全基準に従った作業が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (361, 21, 32, 'きものアドバイザー', 'きものアドバイザーは、着物に関する専門的な知識を活用して、顧客に最適な着物選びや着付けのアドバイスを行う職業です。主に着物の販売店やレンタルショップ、イベントなどで勤務し、顧客の要望や着用シーンに応じた着物を提案します。また、着物のコーディネートや手入れ方法についても指導することが求められます。伝統的な和装文化を大切にしつつ、現代のライフスタイルにも合わせた提案ができる能力が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (362, 17, 35, '建築物環境衛生管理技術者', '建築物環境衛生管理技術者とは、一般的にはビル管理技術者としても知られ、建物の環境衛生に関する設備や施設の管理を行う専門職です。具体的には、空調設備の管理や水質管理、清掃の監督、害虫駆除、電気設備や給排水設備の維持管理などが含まれます。適切な環境を維持するために法律や基準を遵守し、定期的な点検や改善策を企画・実施します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (363, 17, 31, 'ハウジングアドバイザー', 'ハウジングアドバイザーは、主に住宅や不動産に関するアドバイスを提供する専門職です。顧客のニーズや予算に応じて最適な物件を紹介し、不動産購入や賃貸の手続きをサポートします。また、市場動向や法的手続きに関する情報提供も行います。個人の顧客だけでなく、投資家や法人向けの不動産提案をすることもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (364, 23, 33, 'ドアパーソン', 'ドアパーソンは、ホテル、マンション、オフィスビルなどの出入口で客や訪問者を迎え入れたり見送ったりする仕事です。主な役割は、訪問者に対するドアの開閉、荷物の持ち運びや案内、タクシーの手配、入館者の確認などです。加えて、高級施設では顧客に特別なホスピタリティを提供することも求められます。外見や身だしなみを整え、礼儀正しい態度で接することが重要です。この職業は、よい対人スキルと礼儀、施設や周辺の知識が求められる職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (365, 25, 24, 'ホームヘルパー', 'ホームヘルパーは、高齢者や障がい者など、日常生活におけるサポートが必要な人々に対し、家庭を訪問して支援する職業です。日常の家事手伝いや身体介護、健康管理などを行い、利用者の生活の質を向上させることを目的としています。柔軟な働き方が可能で、仕事を通じて人の役に立つことができる点が魅力です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (366, 25, 23, '臨床心理士', '臨床心理士は、主に病院、学校、企業などで、心理的な問題を抱える人々の相談やカウンセリングを行い、メンタルヘルスの支援をします。彼らは心理療法を通じて、クライアントの心理的問題の解決を図り、精神的健康の維持や向上を目指します。臨床心理士は、心理査定を行い、クライアントの心理状態を診断し、適切な治療計画を立てる役割も担っています。また、他の医療専門職と連携して総合的なケアを提供することもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (367, 25, 24, '介護福祉士', '介護福祉士は、介護が必要な高齢者や障害者の日常生活を支援する専門職です。具体的な業務には、食事や入浴の介助、生活環境の整備、レクリエーションの実施、介護計画の立案などが含まれます。また、利用者の健康状態や生活全般の様々な相談にも対応します。 介護福祉士は、福祉施設、病院、居宅介護サービス事業所など、さまざまな場所で働くことができます。福祉の現場では、心身のサポートを行うことが求められ、コミュニケーション能力や人に寄り添う姿勢が重要視されます。 介護福祉士資格を取得するには、福祉系の専門学校や大学での学びを経て、国家試験に合格する必要があります。また、実務経験を積んでキャリアアップすることも可能で、ケアマネージャーや福祉施設の管理職に進む道もあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (368, 22, 34, '電車運転士', '電車運転士は、鉄道会社に所属し、乗客や貨物を安全に目的地まで輸送するために、電車を運転する職業です。運転ダイヤに従い、定められた時間に電車を発着させることが求められます。また、安全運転のための様々な規則や技術を習得する必要があります。業務の一環として、車両点検や駅での案内放送、非常時の対応なども含まれます。通常、運転士になるためには、一定の訓練と試験をクリアし、運転士の資格を取得する必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (369, 21, 32, 'スポーツ用品販売員', 'スポーツ用品販売員は、スポーツ用品店で働き、顧客に適切なスポーツ用品を提案、販売する職種です。顧客のニーズに基づいて商品を紹介したり、商品に関する知識を提供します。商品在庫の管理、ディスプレイの配置、レジ業務、カスタマーサービスも重要な業務です。新製品の情報を常に把握し、スポーツに関する知識を豊富に持つことで、顧客の信頼を得ることが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (370, 16, 27, 'グリーンコーディネーター', 'グリーンコーディネーターは、主に都市の景観や建物内部の緑化を計画・提案する職業です。環境に配慮した持続可能なデザインや植物配置を企画し、スペースの美観や機能を向上させることを目的としています。具体的には、公共施設やオフィスビル、住宅などの屋上庭園やインドアガーデンのデザイン、植物の選定やメンテナンスの計画を行います。エコロジカルな知識に加え、デザインセンスやプロジェクトマネジメント能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (371, 24, 33, 'バーテンダー', 'バーテンダーは、バーやレストランなどでカクテルやアルコールドリンクを調製し、提供する専門職です。顧客の要望に応じたドリンクを作成し、また新しいレシピを考案することもあります。バーテンダーは、飲料の知識だけでなく、接客スキルやコミュニケーション能力も重要です。さらに、店舗の雰囲気を盛り上げる役割も担い、顧客との良好な関係を築くことが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (372, 34, 24, '国際ボランティア', '国際ボランティアは、国際的な支援が必要な地域や国で活動するボランティアで、教育、医療、環境保護、災害支援など多岐にわたる分野での活動が求められます。目的は、人道支援や文化交流であり、参加者は異文化を学びながら地元の人々と協力して問題解決を図ります。多くの団体がプログラムを提供しており、ボランティアは経験やスキルを活かして活動します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (373, 21, 32, 'ファッションアドバイザー', 'ファッションアドバイザーは、お客様の個性やライフスタイルに合った衣服やアクセサリーを選ぶ手助けをする職業です。トレンド情報の提供やワードローブの整理、購入時のアドバイスなどを通じて、顧客にスタイルや服装の提案を行います。顧客の好みやニーズに基づいてコーディネートを組み立て、自信を持ってファッションを楽しむためのお手伝いをします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (374, 22, 35, '列車清掃員', '列車清掃員は、電車内や駅のプラットフォームなどにおける清掃を担当する職業です。乗客が快適に利用できる環境を整えるため、座席や床、窓、トイレなどを清掃します。作業は限られた時間内で効率よく行う必要があり、業務によっては深夜や早朝の勤務もあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (375, 20, 6, '商社マン', '商社マンは、商社に勤務し、企業間取引を通じてさまざまな商品を輸出入し、販売する職業です。日本企業が主に海外市場で商品や原材料を取引する際の仲介役を担っています。取引先との交渉、マーケティング、物流の手配、財務管理など多岐にわたる業務を行います。グローバルなビジネスシーンで活躍することが求められるため、高いコミュニケーション能力と語学力が必要とされます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (376, 20, 2, '物品購買スタッフ', '物品購買スタッフは、企業や組織で必要な物品や資材を調達する職務を担っています。主要な仕事内容には、供給業者との交渉、価格分析、発注手配、納期管理、品質確認が含まれます。効率的かつコスト効果の高い購入を行うためには、市場調査やサプライチェーン管理の知識が求められます。また、社内部門やベンダーとのコミュニケーション能力も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (377, 23, 32, 'ランドオペレーター', 'ランドオペレーターは旅行業界において、旅行代理店や旅行会社と協力し、現地での観光ツアーやアクティビティ、宿泊施設、交通手段の手配、観光客へのガイドサービスなどを調整・提供する役割を担っている職業です。彼らは通常、特定の観光地や国に精通しており、クライアントの要望に応じて最適な旅行プランを作成することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (378, 19, 31, '証券アナリスト', '証券アナリストは、株式、債券、外国為替など金融資産の分析を専門とする職業です。企業の財務状況や市場の動向を分析し、投資の決断に役立つ情報を提供します。主な業務には、企業の財務データの収集と分析、経済指標の評価、市場トレンドの調査、レポートの作成などが含まれます。投資家やファンドマネージャーに向けてプレゼンテーションを行い、投資助言を行うこともあります。証券アナリストは、金融業界全般に欠かせない役割を担っており、分析力や経済知識が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (379, 25, 24, '点字通訳者', '点字通訳者とは、視覚障害者のために点字を用いて文字情報を提供する職業です。点字翻訳、教育、及び支援業務を担い、具体的には書籍や書類の点字化、点字の指導、視覚障害者がアクセスしやすい情報の提供を行います。点字の知識と、視覚障害者のニーズを理解したコミュニケーション能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (380, 25, 23, '歯科技工士', '歯科技工士は、歯科医師の指示のもとで義歯やクラウン、ブリッジ、矯正装置などの歯科補綴物やデバイスを製作する専門職です。患者の口腔内の状態に合わせたカスタムメイドの歯科技工物を作成し、治療の一環として使用されます。歯科技工士は、精密な技術と細部に対する注意力が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (381, 37, 34, 'マーシャラー', 'マーシャラーとは、航空機が地上を移動する際に、パイロットに対して視覚的なサインを送って誘導する業務に従事する職員のことを指します。滑走路やゲート付近で特に活躍し、航空機の安全な移動と駐機を支援する役割を担います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (382, 30, 32, 'コンパニオン', 'コンパニオンは、イベント、展示会、パーティーなどで参加者をおもてなしし、接客を担当する役割を担います。主に、来場者への案内や商品説明、受付業務などを行います。接客スキルやコミュニケーション能力が求められ、明るく親しみやすい接客態度が重要です。また、イベントの内容や会場によっては特定の知識やスキル、言語能力が必要となる場合もあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (383, 21, 32, 'フラワーショップ店員', 'フラワーショップ店員は、花や植物の販売を行う職業です。顧客の要望に応じて花束を作成したり、店内のディスプレイを管理したりします。花や植物に関する知識が必要で、接客スキルや美的センスも求められます。また、仕入れや在庫管理などの業務も含まれることがあります。花が好きで、人と接するのが得意な人に向いている職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (384, 24, 33, 'ウェイトレス', 'ウェイトレスは、レストランやカフェなど飲食店で接客する役割を担う職業です。主な仕事内容には、顧客の注文を受ける、料理や飲み物を運ぶ、テーブルを片付ける、レジでの会計などが含まれます。コミュニケーション能力や接客スキルが求められ、顧客に対する気配りや迅速なサービス提供が重要です。シフト制の勤務が多く、休日や夜間も働くことが一般的です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (385, 33, 26, '通訳者', '通訳者は、異なる言語を話す人々の間でコミュニケーションを円滑にするために、話されている言語をリアルタイムで別の言語へと口頭で翻訳する専門職です。会議、ビジネスミーティング、法廷、医療現場などさまざまな場面で活躍します。通訳者には、言語能力だけでなく、状況を理解し適切に対応する能力が求められます。また、迅速で正確な通訳能力が重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (386, 25, 23, '作業療法士', '作業療法士は、身体や精神に障害を抱える人々が日常生活を送るための能力を維持・向上させるためのリハビリテーションをサポートする専門職です。具体的には、日常生活動作の訓練や社会復帰支援、趣味や職業活動の導入を通じてフルライフに適応するための援助を行います。病院や福祉施設、学校などで活躍し、患者一人ひとりに合わせたプログラムを提供します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (387, 34, 37, '牧師', '牧師は、キリスト教会の聖職者であり、信徒を導く精神的リーダーとしての役割を果たします。彼らは宗教儀式や礼拝を執り行い、洗礼や結婚式、葬式などの特別なイベントを取り仕切ります。また、信徒に対するカウンセリングや教育を行い、地域社会における奉仕活動にも参加します。牧師は、神学の深い理解と優れたコミュニケーション能力が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (388, 22, 34, 'ディスパッチャー', 'ディスパッチャーは、主に交通機関や物流業界で稼働する職業です。彼らの主な役割は、配車や配送スケジュールの管理・調整を行い、効率的な運営をサポートすることです。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (389, 25, 23, '動物看護師', '動物看護師は、動物病院や動物診療所で獣医師をサポートする役割を担います。彼らの主な仕事は、動物の診療や手術の補助、入院中の動物の世話や観察、飼い主に対する動物のケアに関するアドバイスなどです。また、動物の健康状態の記録管理や、診療室や手術室の清掃・消毒といった衛生管理も重要な業務の一部です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (390, 25, 24, '精神保健福祉士', '精神保健福祉士は、精神的な障害を持つ人々やその家族を支援する専門職です。彼らは、クライアントの生活の質を向上させるために、必要な福祉サービスの提供や、社会復帰、生活訓練を支援します。また、医療機関や福祉施設、地域社会と連携し、適切なサポート体制を構築します。多様な問題に対応するため、カウンセリング技術、法律知識、福祉制度に関する深い理解が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (391, 25, 23, '管理栄養士', '管理栄養士は、栄養の専門職として、個人または集団の健康を維持・改善するための栄養指導や食事計画を行います。主に病院や学校、企業の給食部門で働きますが、スポーツ団体や行政機関などでも活躍の場があります。資格取得には国家試験に合格する必要があります。栄養学に基づいた科学的なアプローチでの食事管理や栄養相談が主な業務です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (392, 20, 6, '清涼飲料ルートセールスマン', '清涼飲料ルートセールスマンは、特定の地域を担当し、スーパーやコンビニエンスストア、小売店などに清涼飲料水を販売・配送する役割を担います。主な業務は、商品の注文受付、在庫管理、納品スケジュールの調整、新商品の紹介、クライアントとの関係構築です。運転免許などが必要な場合もあり、営業スキルやコミュニケーション能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (393, 25, 23, 'セラピスト', 'セラピストは、心身の状態を改善し、リラクゼーションや治療を目的とするさまざまな手法を用いる専門職です。身体的なマッサージや心理的なカウンセリングを通じて、ストレスの軽減や健康の促進を目指します。セラピストは、クライアントの個別のニーズに合わせたケアを提供し、リラクゼーションから痛みの緩和まで、さまざまな目的で働くことがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (394, 36, 34, 'じんかい収集作業員', 'じんかい収集作業員は、一般家庭や企業から出るゴミを回収し、適切な処理施設まで運搬する仕事です。主に運搬車両を使用し、安全かつ効率的にごみを集め、環境衛生を守る役割を担っています。通常、早朝から作業を開始することが多く、体力や集中力が求められます。また、地域ごとのルールや規制を理解し、遵守することも重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (395, 16, 18, 'エレベーター据付工', 'エレベーター据付工は、新しい建物や既存の建物にエレベーターを設置する専門職です。この職業には、エレベーターの機械部品、電気配線、制御システムなどの組み立てと取り付けの作業が含まれます。また、エレベーターが安全かつ効率的に動作するよう、各種テストを行い、調整やメンテナンスを行うことも重要です。作業は高所で行うことが多く、安全管理や精密さが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (396, 35, 37, '着付け', '着付けとは、主に和服や着物を着るための技術や方法を指します。これには、着物や帯の正しい着装法、身だしなみ、礼儀作法の知識が含まれます。着付け師は、顧客の体型や場面に応じて、最適な着付けを提供し、快適に美しく着物を着る手助けをします。この職業は日本の伝統文化を支える重要な役割を果たしており、特に結婚式や成人式、七五三などの式典で需要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (397, 36, 9, '臭気判定士', '臭気判定士は、さまざまな臭気の強さや特性を判定し、臭気に関する法律や規制に基づいて適切な管理を行います。主な業務には、工場や廃棄物処理場などの臭気源の調査、臭気の成分分析、臭気低減のための対策提案などが含まれます。また、臭気に関する苦情対応や環境改善のためのコンサルティングも行います。臭気に敏感で、分析的思考を持つことが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (398, 24, 33, '中華料理料理人', '中華料理料理人は、中華料理を専門に調理する料理人です。様々な中華料理の調理技術を駆使し、顧客に美味しい料理を提供します。中華料理の文化や歴史を理解し、調理に生かすことが求められます。また、食材の選定や管理、調理器具の使い方にも精通している必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (399, 19, 31, '損害保険募集人', '損害保険募集人は、顧客に対して損害保険を提案し、契約を勧誘する役割を担います。損害保険とは、事故や災害などの損害を補償するための保険で、自動車保険や火災保険、地震保険などが含まれます。募集人は、顧客のニーズを把握し、最適な保険商品を選定し、契約手続きやアフターフォローを行います。また、保険商品に関する知識を持ち、法令を遵守した販売が求められます。保険会社や代理店で勤務することが一般的です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (400, 25, 26, '手話通訳士', '手話通訳士は、聴覚障害者と聴者の間で手話と音声言語を相互に翻訳する専門職です。主に、会議や講演、テレビ番組、法廷などで、手話を用いて聴覚障害者が情報を理解できるよう支援します。また、手話通訳士はその場の文脈を理解し、適切なコミュニケーションを促進する役割も果たします。手話に関する高い技能と知識が求められるため、専門の養成過程を経て資格を取得することが必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (401, 25, 24, '医療ソーシャルワーカー', '医療ソーシャルワーカーは、病院や診療所、在宅ケアなどの医療環境で患者やその家族を支援する専門職です。彼らは患者の心理的、社会的問題の評価と対応を行い、必要に応じてリソースや支援を提供します。これには、財政援助の手続き支援や、外部支援機関との連携、退院計画の策定、患者および家族へのカウンセリングが含まれます。医療チームの一員として、患者の全体的なケア向上に貢献し、医療と社会的サポートを統合する役割を果たします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (402, 37, 34, '航空管制官', '航空管制官は、航空機の安全な離着陸と飛行を支援する専門職です。空港や管制塔からパイロットと連携し、航空機の位置や高度、速度を監視しながら、他の航空機や障害物との安全な距離を保つために必要な指示を行います。また、天候や交通情報を提供し、緊急時には速やかな対応を図る役割を担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (403, 36, 22, '環境計量士', '環境計量士とは、環境の測定や分析を専門とする職業で、環境保護や改善に関わるデータの収集、測定、分析を行います。主な業務には、大気、水質、騒音、振動の測定などがあり、様々な環境基準を満たすためのデータを提供します。これにより、環境問題の予防や解決に貢献します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (404, 24, 33, 'すし職人', 'すし職人は、主に日本料理屋やすし屋で働く料理人で、美しい見た目と新鮮な食材を活かしたすしを作る専門家です。彼らは魚やその他のシーフードをさばく技術、日本の米を炊いてからすし飯を作る技術を持っています。また、すしの盛り付け方や味覚バランスを取るための調味技術も重要です。すし職人は料理の質を保つため、食材の選定から調理、提供まで厳格な標準を守ります。さらに、顧客との対話やカウンターでの接客も行うため、コミュニケーションスキルも求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (405, 19, 31, '信用金庫渉外係', '信用金庫の渉外係は、金融機関としての信用金庫において、顧客との窓口業務や相談業務を担当する職種です。主に、個人や法人の顧客に対して金融商品やサービスの提案を行うほか、預金や融資の相談・手続き、口座開設のサポートを行います。顧客と信頼関係を築きながら、最適な金融サービスを提案し、地域社会の経済活動を支える役割を果たします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (406, 23, 32, '観光バスガイド', '観光バスガイドは、観光バスにおいてお客様に観光地の魅力や歴史、背景を解説する役割を担います。ツアーの開始から終了まで、お客様に旅行の楽しさや観光地の情報を提供し、スムーズな移動をサポートすることが求められます。ガイドは地元の歴史や文化に詳しく、多言語での案内が可能な場合もあります。また、緊急時の対応やお客様の安全を確保する役割も含まれます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (407, 25, 23, 'あんまマッサージ指圧師', 'あんまマッサージ指圧師は、身体の特定の部位に圧力を加えることによって筋肉の緊張をほぐし、血行を良くして体の痛みや不調を改善する専門職です。日本では国家資格が必要で、理論知識と技術を備えていることが求められます。患者の体調や状態に応じた適切な施術を提供し、リラクゼーション効果や健康増進を図ります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (408, 24, 33, '板前', '板前とは、日本料理を専門とする料理人の職業です。主に寿司や懐石料理などの日本独自の料理を提供し、食材の選定から調理、盛り付けに至るまでを担当します。繊細で美しい盛り付けや、旬の食材を活かした調理技術が求められ、顧客に対して高品質なサービスと味を提供することが重要です。伝統的な料理技術を守りながら、新しい創作料理を生み出すこともあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (409, 23, 33, 'コンシェルジュ', 'コンシェルジュは、顧客やゲストのさまざまな要望をサポートする職業です。ホテルや高級レジデンス、オフィスビルなどで働くことが一般的で、予約の手配、観光情報の提供、トラブルシューティングなど多岐にわたる業務を行います。顧客とのコミュニケーション能力や問題解決能力が求められる職業です。お客様に優れたサービス体験を提供することを目的としており、高い接客スキルが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (410, 35, 32, 'ビューティアドバイザー', 'ビューティアドバイザーは、美容関連の商品やサービスについての助言を提供する専門職です。化粧品やスキンケア、ヘアケア製品の使用方法、選び方などについて顧客にアドバイスし、最適な製品やケア方法を提案します。販売員という役割も兼ねることが多く、売上目標を掲げつつ顧客の美に対する悩みを解決するサポートをします。また、メーカーや販売業者の代理として新商品のプロモーション活動を行うこともあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (411, 24, 33, 'ウェイター', 'ウェイターは、飲食店でお客様に対してサービスを提供する職業です。具体的な業務には、注文の受け付け、料理や飲み物の提供、テーブルの片付け、会計、顧客対応などがあります。迅速で丁寧なサービスが求められ、お客様とのコミュニケーション能力が重要です。飲食業界の知識や経験が求められることもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (412, 19, 31, '金融ディーラー', '金融ディーラーは、金融市場において自己資金または会社の資金を用いて、株式、債券、通貨、商品などの金融商品を売買する職業です。ディーラーは市場の動向を分析し、最適な売買のタイミングを判断して、利益を最大化することを目指します。また、ディーラーは市場の流動性を提供し、価格発見の役割を果たします。金融市場の変動に敏感であり、迅速な意思決定が求められるため、高度な分析能力とストレス耐性が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (413, 35, 1, '管理理容師', '管理理容師は、理容院でのローカル運営を管理し、顧客にサービスを提供する職位です。主な業務には、スタッフ管理、顧客対応、予約管理、サービス品質の確認、顧客の求めに応じた理容サービスの提供、及び新しいスタイリング技術の導入などが含まれます。また、理容関連の法律や規制を遵守し、クリーニング、衛生管理を確実にする役割も担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (414, 6, 6, '印刷営業マン', '印刷営業マンは、印刷会社に所属し、クライアントのニーズに合わせた印刷物の提案や受注、納品のプロセスを管理する仕事です。彼らは新規顧客の開拓や既存顧客との関係維持、印刷工程のスケジュール管理、品質管理、コスト管理などを行います。市場動向を把握し、効果的な提案を通じて顧客満足度を高め、売上の向上に寄与します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (415, 22, 32, 'グランドスタッフ', 'グランドスタッフは、空港で航空会社の地上業務を担当する職種です。主な仕事内容には、カウンターでのチェックイン業務、搭乗手続き、手荷物の取り扱い、航空機の案内、遅延やキャンセル時の顧客対応などが含まれます。この職業には、チームワーク、顧客サービススキル、問題解決能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (416, 35, 32, 'エステティシャン', 'エステティシャンは、美容とリラクゼーションを目的に、フェイシャルやボディ、脱毛などの施術を行う職業です。肌や身体のケアを通じて、顧客の美容と健康をサポートします。エステサロンやスパで働くことが多く、美容に関する専門知識と技術が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (417, 23, 33, 'フロントクラーク', 'フロントクラークは、主にホテルや宿泊施設の受付業務を担当する職業です。顧客のチェックイン・チェックアウトの手続き、電話応対、予約管理、問い合わせ対応、顧客対応、および料金の支払い処理などを行います。顧客が滞在中に快適に過ごせるようサポート役を果たし、厳しい状況でも冷静かつ丁寧に対応できるコミュニケーション能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (418, 23, 32, '旅行会社カウンタースタッフ', '旅行会社カウンタースタッフは、旅行会社の店舗でお客様に直接対応し、旅行の相談や予約手続きを行います。仕事内容には、顧客の希望に応じた旅行プランの提案、航空券や宿泊施設の手配、ビザ取得の支援、旅行保険の案内などが含まれます。また、旅行中のトラブル対応やアフターサービスも行います。接客スキルとコミュニケーション能力が重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (419, 23, 32, 'ツアーコンダクター', 'ツアーコンダクターとは、旅行会社やツアーオペレーターにおいて、旅行客を旅程に従って案内し、旅行の進行をスムーズにする役割を担います。具体的には、旅行プランの確認、出発前の準備、現地でのスケジュール管理、観光地での案内やサポート、問題が発生した際の対応などが含まれます。多くの場合、リーダーシップとコミュニケーション能力が求められ、旅行先に関する知識や異文化理解も重要です。国際的なツアーでは、複数言語のスキルがあると有利です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (420, 25, 24, '訪問介護員', '訪問介護員は、介護を必要とする高齢者や障害者の家庭を訪問し、日常生活のサポートを行います。具体的には、食事・入浴・排泄などの身体介護や、買い物・掃除・洗濯といった生活援助を提供します。利用者ができるだけ自立した生活を続けられるように支援することが主な役割です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (421, 5, 27, 'テキスタイルデザイナー', 'テキスタイルデザイナーは、布地や繊維製品のデザインを行う職業です。彼らはパターン、色彩、素材感を考慮して新しい生地のデザインを作成します。この仕事には、ファッション、インテリアデザイン、家具、さらには産業用資材など、多岐にわたる製品のデザインが含まれます。テキスタイルデザイナーは、製品の機能性と美観の両方を重視し、コンピュータデザインツールを使用することが一般的です。また、流行のトレンドや市場の需要にも敏感である必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (422, 5, 21, '紡績運転工', '紡績運転工（ぼうせきうんてんこう）は、紡績機械を操作して糸を製造する仕事です。原材料である繊維から糸を紡ぐ工程では、機械の設定や調整、製品の品質管理、製造過程の監視などの作業が含まれます。この職種は機械の動作を適切に管理し、糸が規定の品質を保つように運転する技術とともに、異常が発生した際に迅速に対応する能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (423, 4, 21, '惣菜製造工', '惣菜製造工は、食品工場や小売業者のキッチンで、日常的に消費される総菜を製造する職種です。具体的には材料の準備、調理、味付け、包装、表示などを行い、安全で美味しい食品を提供します。衛生管理や品質管理の知識が求められ、時には大量生産を効率的に行うための技術も必要です。全体として、消費者の食卓に直接関わる重要な役割を担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (424, 4, 21, '水産ねり製品製造工', '水産ねり製品製造工は、魚介類を主な原料としたすり身やかまぼこ、ちくわなどの加工食品を製造する職種です。原料の選別や加工、調味料の配合、製品の成形、包装などの工程を担当します。また、品質管理や衛生管理にも注意を払い、安全で美味しい製品を提供することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (425, 5, 21, '織布運転工', '織布運転工は、主に織物を製造するための機械を操作する仕事です。織機を用いて、糸から布を作る工程を担い、生産効率や品質の管理も行います。技術の進化により自動化が進んでいますが、機械の設定やトラブル対応が必要です。また、製品の検査やメンテナンスも行います。繊維や素材の知識が求められ、注意深く作業を進めることが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (426, 16, 20, '測量士', '測量士は、土地や建物の位置、大きさ、形状など、地形や構造物の情報を正確に測定、記録し、地図や図面に反映させる専門職です。彼らは、経緯度や高さ、距離などのデータを収集し、計算や分析を行い、土地利用や都市計画に必要な情報を提供します。測量士は多くの異なる分野で必要不可欠な役割を果たし、工事現場、公共事業、不動産取引などに関与しています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (427, 10, 21, 'めっき工', 'めっき工は、金属を電気化学的または化学的なプロセスによって他の金属や合金の表面に薄い金属の被覆を施す仕事を行います。これにより、装飾的な効果や防錆効果、さらなる表面特性の向上を狙います。通常、技術者はめっきの条件を調整し、製品の品質を確保するための工程管理を行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (428, 4, 21, '乳製品製造工', '乳製品製造工は、牛乳やヨーグルト、チーズ、アイスクリームなどの乳製品を製造する仕事です。具体的な作業には、牛乳の貯蔵、加熱、加工、発酵、包装などのプロセスが含まれます。また、安全で高品質な製品を提供するために、品質管理や衛生管理も重要な役割を担います。工場での機械操作が主な業務となり、製造過程の効率化やトラブルシューティングも行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (429, 7, 21, '製薬工', '製薬工は、医薬品の製造と関連する業務を担当する職業です。具体的には、医薬品の生産計画の立案、製造工程の管理、品質管理業務、設備の保守・管理などを行います。医薬品の安全性と品質を確保するために、厳密な規制や基準に従って業務が進められます。高い技術力と専門知識が要求され、製薬会社や化学工業、関連研究機関などで働くことが多いです。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (430, 10, 21, '製鋼工', '製鋼工は製鋼所で鉄鋼を製造する職業です。主に、鉄鉱石から鉄を抽出し、鋼に加工する過程を専門としています。作業は高温、高圧の環境で行われることが多く、安全対策が重要になります。また、製品の品質を確保するために、常に機器のメンテナンスや工程の監視が求められます。技術の進展に伴い、最新の装置やプロセスについての知識も求められることがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (431, 16, 20, '鉄筋工', '鉄筋工は、建設作業において鉄筋を使って、構造物の骨組みを組み立てる専門職です。主に、建物や橋などの構造物の耐久性や強度を高めるために必要な鉄筋を、正確に配置し、結束、固定します。この職業は、物理的な作業が多く、重量のある資材を扱うことが求められます。鉄筋工は、高層ビルから住宅まで、さまざまな建設プロジェクトで重要な役割を果たします。適切な測定と技術が要求され、建築基準を遵守し、安全に作業を進める必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (432, 14, 21, '計器組立工', '計器組立工は、さまざまな計器や機器を手作業または機械を使って組み立てる職業です。計器には、温度計、圧力計、速度計、電流計などが含まれ、これらを正確に組み立てることが求められます。作業は工場などの製造現場で行われることが多く、部品の取り付け、調整、検査を担当します。細かい部品を扱うため、精密さや注意力が重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (433, 14, 21, '医療用画像放射線機器組立技士', '医療用画像放射線機器組立技士は、病院や医療施設などで使用される画像診断装置や放射線機器の組立、据付、メンテナンスを行う専門職です。具体的には、CTスキャナー、MRI装置、超音波装置、X線装置などの高度な医療機器を取り扱い、正確に作動するように組み立てたり、設置したりします。また、機器が正常に動作するための定期的な点検や修理も担当します。技術的な知識と医療分野の基礎的理解が要求され、品質と安全性に配慮した作業が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (434, 6, 21, '合板工', '合板工は、主に木材を加工して合板を製造する職人です。合板は薄い木の板を複数枚重ね、接着剤で圧着することによって作られます。この職業には、正確なカット、貼り合わせ、圧着作業が要求されます。また、品質管理や機械の操作、製品の仕上げも重要な役割を担います。安全基準の遵守や労働環境の改善にも取り組む必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (435, 4, 21, '清酒製造工', '清酒製造工は、日本酒の製造に携わる職業です。工程は、米を磨くことから始まり、米を蒸して麹菌を加えて糖化させる工程を経て、アルコール発酵を行います。さらに、発酵したもろみを絞ることで清酒が生成されます。清酒製造工は、これらの工程を通じて高品質な日本酒を製造することを目指します。仕事には、細心の注意を払って温度や湿度を管理し、味や香りに影響を与える微生物の活動を適切にコントロールする技術が求められます。加えて、長時間の立ち仕事や重いものの持ち運びが伴うため、体力も必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (436, 16, 20, '管工事施工管理技士', '管工事施工管理技士は、建築現場における配管工事の計画、実施、監督を行う専門職です。主な業務には、給排水、空調、ガス配管などの施工計画を立て、施工図をもとに工事を進行・管理することが含まれます。品質、安全、工程の管理を徹底し、工期内の工事完了を目指します。また、現場での技術的な問題の解決や、施工チームの指導も行います。この職業には、国家資格である「管工事施工管理技士」の資格が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (437, 5, 21, '縫製工', '縫製工は、布地を裁断し、縫って衣類を作成する職業です。通常、縫製工はミシンや各種縫製機械を使用して作業を行い、デザインに基づいて衣類を仕上げます。職場は縫製工場やアパレル会社の製造部門が一般的です。細かい手作業を必要とし、正確さとスピードが求められます。近年では、オーダーメイドや修繕の需要も高まり、多様なスキルが求められる場合があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (438, 5, 21, '紡織保全工', '紡織保全工は、紡績工場で使用される機械の保守とメンテナンスを行う専門職です。紡績機や織機が効率的に稼働するために、機械の点検、修理、調整を担当します。トラブルシューティング能力と機械工学の基礎知識が求められ、機械のダウンタイムを最小限に抑えることが重要です。また、定期的な点検を通じて予防保全を行い、製造プロセスの円滑な運営を支えます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (439, 16, 20, '建築施工管理技士', '建築施工管理技士は、建設工事において、施工計画の作成や現場の管理・監督を行う専門職です。彼らは、工事が設計図や仕様に従って適切に実施されるように監視し、品質・安全管理、工程管理、コスト管理を担当します。また、工事関係者とのコミュニケーションや調整を行い、プロジェクトを円滑に進める役割も担っています。資格取得には試験があり、合格すると国家資格として認定されます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (440, 8, 21, 'プラスチック製品成形工', 'プラスチック製品成形工は、プラスチック製品の製造工程において、成形機を操作し、製品を形成する職業です。主に射出成形やブロー成形、圧縮成形などの方法を用いて、さまざまな形状のプラスチック製品を作り出します。この職業には、成形機の設定や調整、不良品の検出と修正、品質管理などの業務が含まれます。また、素材の特性を理解し、適切な加熱時間や圧力を設定することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (441, 16, 20, '保温工', '保温工は、建物や設備の断熱作業を担う専門職です。主に配管やタンクの周囲に断熱材を取り付けて、熱損失を防ぎ、省エネ効果を高めます。工場やビル、住宅といった様々な施設において、温度管理が重要な場所での作業が中心です。材料の正確なカッティングと取り付け、環境や施設ごとの異なるニーズに応じた作業が求められます。また、安全対策を徹底しながら業務を行うことが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (442, 16, 20, '配管工', '配管工は、建物や構造物内で水、ガス、排水などの流体を運ぶ管を取り扱う専門職です。彼らは管の設置、修理、保守を担い、漏れや詰まりを防ぐための点検を行うこともあります。住宅や商業施設、工業施設で働くことが多く、しばしば顧客とのコミュニケーションも重要です。技術的なスキルと問題解決能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (443, 16, 20, '土木作業員', '土木作業員は、建設現場で物理的な労働を行う職業です。主な業務としては、土や砂利の掘削、運搬、整地作業や、コンクリートの打設、型枠の設置、鉄筋の組み立てなどがあります。これらは道路や橋梁、トンネル、建物の基礎工事などで必要な作業です。重機を使用する場合もあり、体力が求められる職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (444, 6, 21, '製材工', '製材工は、木材をさまざまな用途に適した形状やサイズに加工する職業です。具体的には、木材の切断、削削、整形、乾燥などの作業を行い、建設材や家具材、紙製品の原材料などを生産します。製材工は、電動工具や機械を操作するための技術と、安全に作業を行うための知識が求められます。また、作業環境として粉塵が発生する場合があるため、適切な防護措置を取ることが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (445, 37, 18, '航空整備士', '航空整備士は航空機の整備、点検、修理を担当する専門職です。航空機の安全な運航に不可欠な職業であり、高い技術と知識が求められます。整備士は定期検査や故障時のトラブルシューティングを行い、機体、エンジン、電子機器などの各部位を詳細に確認し、問題を修正します。また、航空法に基づく厳格な基準を満たすよう、適切な手順で作業を行うことが重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (446, 4, 33, '製パン工', '製パン工は、パンやベーカリー製品を製造する職業です。主に小麦粉、水、イーストなどの基本的な材料を使用し、さまざまな種類のパンやペストリーを作ります。製造の過程には、生地の仕込み、成形、発酵、焼成などがあります。パン職人は手作業と機械を組み合わせて作業を行い、レシピに従って材料を測定し、調理工程を監督します。食品の安全性と衛生管理も重要な要素です。時には新しい製品の開発や、装飾技術の向上に努めることもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (447, 5, 21, '靴製造工', '靴製造工は、様々な種類の靴を製造する職業で、デザイン、材料選択、裁断、製作、仕上げといった工程に従事します。具体的には、靴の型紙を利用して革や布地を裁断し、縫製・接着を通じて靴の形に組み立て、最終的に磨きや仕上げを行うことで、完成品を作り上げます。手作りのプロセスもあれば、機械を使用した大量生産もあります。職業の性質上、手先の器用さやデザインセンス、耐久性のある靴を作るための知識が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (448, 16, 20, '建築板金工', '建築板金工は、建物の屋根や外壁の板金加工を行う職業です。主に金属素材を使用して、風雨から建物を守るためのカバーを取り付けたり修理したりします。この仕事には精密な作業や金属の取り扱い技術が必要で、建物の美観を損なわないデザイン性も求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (449, 16, 20, '建設機械オペレーター', '建設機械オペレーターは、ブルドーザー、ショベルカー、クレーンなどの重機を操作して土木工事や建設プロジェクトを実施する職業です。これらの機械は、建物の基礎工事、地盤整備、土砂の運搬、建物の解体などに使用されます。オペレーターは、安全かつ効率的に機械を操作し、現場の作業を円滑に進める役割を担います。資格認定が求められることが一般的で、建築現場での経験が求められることもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (450, 14, 21, 'カメラ組立工', 'カメラ組立工は、主に工場でデジタルカメラやビデオカメラを製造する過程において、部品の組み立てを担当する職業です。精密なパーツを手作業または機械を使って組み合わせ、製品を完成させます。高い集中力と細かな作業を正確にこなす能力が求められます。また、製品の品質チェックや修理作業を行うこともあります。電子機器や機械装置の基本的な知識があると有利です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (451, 4, 21, '冷凍加工食品製造工', '冷凍加工食品製造工は、冷凍食品の生産・製造に関わる職業です。工場内での食品の解凍、調理、冷凍、包装などの工程を担当し、品質管理や衛生管理に注意を払いながら作業を行います。製造ラインでの作業だけでなく、機械設備の操作やメンテナンスも行うことがあります。また、新商品の開発や既存商品の改良にも関わる場合があります。チームで連携して作業を行うため、コミュニケーション能力も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (452, 16, 20, '型枠大工', '型枠大工は、建設工事においてコンクリート構造物を形成するための型枠を製作、組み立て、解体する作業を行います。型枠は、コンクリートを流し込むための鋳型の役割を果たします。この職業は、精密に型枠を設置し、正確な寸法を確保することが求められるため、細やかな技術力と熟練した作業が重要です。安全管理も重要な役割を果たしており、作業環境の安全性を保持することが必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (453, 6, 21, 'オフセット印刷作業員', 'オフセット印刷作業員は、印刷産業における専門職であり、オフセット印刷機を操作して高品質な印刷物を大量生産する仕事です。作業員は印刷機の設定や調整、インクの管理、用紙の供給、品質の確認を行い、印刷プロセスがスムーズに進むようにします。また、トラブルシューティングや定期的なメンテナンスも担当し、作業の安全性と効率を確保します。精密さと注意力が求められる職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (454, 4, 21, '機内食製造工', '機内食製造工とは、航空会社の提供する機内食を製造する仕事です。具体的には、食材の準備、調理、パッキングを行い、航空会社の要求に応じた安全で美味しい食事を提供することが求められます。また、衛生基準や品質管理を徹底し、食品の安全を確保する役割があります。通常、工場内での作業が主体であり、時間通りに大量の食事を製造する必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (455, 13, 18, 'エンジン設計技術者', 'エンジン設計技術者は、自動車、航空機、船舶、発電機などの内燃機関や、電動モーターの設計と開発に携わる職業です。エンジンのパフォーマンス、燃費、排出ガスの基準を考慮しながら、さまざまなコンポーネントを設計し、最適化することが求められます。また、新技術の研究開発や、既存エンジンの改良も行います。さらに、設計したエンジンのプロトタイプのテストや評価を通じて、実用化に向けた調整を行うことも重要な役割です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (456, 5, 21, '袋物製造工', '袋物製造工は、バッグや手提げ袋などの袋物を専門に製作する職人です。布地、革、合成皮革など様々な素材を裁断、縫製し、持ち手やジッパーの取り付け、仕上げを行います。伝統的な製法から最新の技術まで幅広く対応し、デザイン、機能性、耐久性に優れた製品を作り出します。細やかな手作業や創造力が求められ、トレンドに敏感であることも重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (457, 14, 27, '楽器クラフトマン', '楽器クラフトマンは、楽器の製造、修理、調整、カスタマイズを専門とする職業です。彼らは楽器製造の工程を理解し、高い技術力と細かい作業が要求されます。どの楽器を専門とするかにより、使う技術や知識は異なりますが、木材、金属、その他の素材を加工して、演奏者が最高のパフォーマンスを発揮できるように楽器を仕上げます。また、顧客の要望に応じたカスタムメイドの楽器を製作することもあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (458, 24, 33, '調理師', '調理師は、食品の準備および調理に従事する専門職です。彼らは食材の選定や組み合わせ、調理技術を駆使して、食事を作る役割を担っています。レストランやホテルの厨房、学食や病院など、さまざまな施設で働くことができます。必要に応じて、食品の衛生管理やメニューの開発を行うこともあります。この職業には、創造性や忍耐力、厳格なスケジューリング能力が求められます。日本国内では調理師免許の取得が推奨されます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (459, 22, 34, '小型船舶操縦士', '小型船舶操縦士は、水上の小型船舶を安全に操縦するための資格を持つ職業です。この職は、船舶の運航やメンテナンス、航路の選定、天候の判断、乗客の安全管理などを行います。通常、釣り船や観光船、プレジャーボートなどの操縦に従事することが多く、操縦士としてのライセンス取得が必須です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (460, 31, 29, '救急隊員', '救急隊員は、緊急医療サービスを提供するために訓練された専門家です。彼らは急病や怪我を負った人々に対し、迅速かつ効果的な医療処置を行い、必要に応じて病院へ搬送します。救急現場では、患者の状態を評価し、適切な治療を提供することが求められます。また、CPR（心肺蘇生法）を含む救命技術を駆使して救助活動を行います。救急車や救急医療機器の操作にも精通している必要があります。多忙な環境の中で冷静に判断を下し、チームと協力して働く能力が重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (461, 32, 21, '有害液体汚染防止管理者', '有害液体汚染防止管理者の主な役割は、工場や産業施設において有害液体の漏洩や誤処理を防止することです。これには、有害化学物質の使用、保管、処分の管理が含まれます。安全基準の遵守を確保し、環境や人々への影響を最小限に抑えるためのプランを策定・実施します。また、事故や非常時の迅速な対応策を講じることも重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (462, 18, 34, '無線通信士', '無線通信士は、無線を用いて通信機器による情報の送受信を管理・操作する専門職です。航空機や船舶、気象情報、災害対策、公共交通機関などの分野で活躍します。周波数、機器の状態、通信のクリアさを確保し、正確で迅速な情報伝達を行う責任があります。 無線通信士は、無線機器の操作技術と知識を持ち、国家資格を必要とする場合があります。国内外の法律や規則を遵守し、インシデント防止のための緊急対応スキルも求められます。情報の伝達においては、明快かつ効果的なコミュニケーション技術が重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (463, 16, 35, '潜水士', '潜水士は、水中での業務を安全に遂行するための専門家であり、水中作業に関連する技術や知識を必要とします。主にダイビングによる調査、救助活動、建設作業、製造設備の点検などが含まれます。潜水士は潜水に関する法律に基づき、適切な訓練とライセンスを持つ必要があります。安全管理や潜水計画の策定、さらには緊急時の対応能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (464, 32, 29, '自衛官', '自衛官は、日本の自衛隊に所属し、国の安全と防衛を担う職業です。自衛隊には陸上自衛隊、海上自衛隊、航空自衛隊があり、それぞれ異なる任務を持っています。自衛官は、国際平和協力活動、災害派遣、警備、訓練、国際的な安全保障の維持など、多岐にわたる業務に従事します。また、厳しい訓練を受け、常に高い規律が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (465, 30, 37, 'レーシングドライバー', 'レーシングドライバーは、モーターレースに参加し、車両を運転する競技者です。彼らは通常、高速で走行する車やバイクを制御し、スピードを競うさまざまなレースに参戦します。専門技術、迅速な判断力、リスク管理能力が必要不可欠です。多くの場合、レースの前後にはスポンサーとの関係づくり、メディア対応、体力・技術トレーニングも重要な仕事の一部となります。最高の性能を引き出すためには、メカニックチームと緊密に連携することも求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (466, 22, 34, 'パイロット', 'パイロットは、商業航空機や軍用機を操縦する専門職です。航空会社や民間の航空関係で働くことが多く、航空機の運航、着陸、航路の計画、飛行前の安全確認などの仕事を行います。また、天気情報や飛行計画を分析して最適な航路を策定し、航空機のセーフティを確保する役割を果たします。パイロットになるためには、ライセンスを取得し、厳しい訓練と試験をクリアする必要があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (467, 25, 24, '介護支援専門員', '介護支援専門員（ケアマネジャー）は、介護が必要な高齢者やその家族に対して、適切な介護サービスを受けるための支援を行う職種です。具体的には、相談を受け、利用者に適した介護サービス計画（ケアプラン）を作成し、他の介護職種や施設と連携して、サービスが円滑に提供されるよう調整します。また、利用者や家族が抱える問題についての相談にも応じます。これにより、高齢者が住み慣れた環境で自立した生活を送ることができるように支援します。国家資格である介護支援専門員実務研修受講試験に合格しなければなりません。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (468, 26, 25, 'スクールカウンセラー', 'スクールカウンセラーは、主に学校内で学生の心理的なサポートや相談を受け付ける専門職です。対象となるのは、学生本人、保護者、そして教職員であり、学生の学校生活や家庭環境での困難やストレスに対するサポートを行います。問題解決のためのカウンセリングや、必要に応じて外部専門機関への紹介も行います。教育相談や生徒指導、心理査定など多岐にわたる業務に携わります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (469, 25, 24, 'カウンセラー', 'カウンセラーは、個人やグループが心理的な問題や課題に対処するのを支援する専門職です。カウンセリングの過程で、クライアントの感情や考えを探り、彼らが抱える問題を明確にし、それに対処するための解決策や新たな視点を提供します。主な働く場は、学校、病院、企業の人事部門、地域のメンタルヘルスセンターなどであり、クライアントのニーズに応じた適切なサポートを提供します。カウンセラーは、必要に応じて他の専門職と連携し、クライアントの福祉を向上させるために緊密に協力します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (470, 26, 24, '保育士', '保育士は、幼児から小学校入学前までの子どもたちを対象に、日常生活の世話や教育活動を行う職業です。主に保育園や幼稚園などの施設で働いており、子どもたちの発達段階に応じた教育プログラムの設計と実施、食事や睡眠のサポート、安全を確保する役割を担っています。保護者や他の職員とのコミュニケーションや連携も重要です。必要な資格として、保育士資格が求められ、国家試験を通じて取得します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (471, 26, 25, '体育教師', '体育教師は、学校で生徒に対して身体を使った運動やスポーツ技術の指導を行います。健康的なライフスタイルの促進やチームワークの重要性を教える役割も担っています。教育計画の作成、授業の実施、安全な環境の提供などが主な業務です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (472, 25, 23, '音楽療法士', '音楽療法士は、音楽を使用して患者の心身の健康を改善する専門職です。さまざまな音楽活動を通じて、心理的、感情的、身体的、社会的な治療を行い、患者の生活の質を向上させます。患者のニーズに応じた個別のセッションを提供し、リハビリテーションやストレス管理、認知機能の改善などをサポートする役割です。教育機関や医療施設、福祉施設などで活動しています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (473, 30, 25, 'アウトドアインストラクター', 'アウトドアインストラクターは、自然環境の中でアウトドア活動を指導する職業です。キャンプ、ハイキング、クライミング、カヤックなどのアクティビティで参加者を安全に導き、体験をより豊かにします。また、環境保護や自然の理解を促進する役割も担っており、参加者に対してアウトドアにおけるノウハウやスキルを教えることが求められます。指導には専門的な調整能力とコミュニケーションスキルが必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (474, 25, 24, '社会福祉士', '社会福祉士は、福祉に関する専門的な知識と技術を有し、相談援助を行う専門職です。社会、福祉に関する制度やサービスを活用して、生活困難な状況にある人々やその家族を支援します。具体的には、障害者、高齢者、低所得者、児童家庭などに対して、福祉相談や生活支援、各種権利擁護などの業務を行います。福祉事務所、医療施設、介護施設、教育施設など、さまざまな場面で活躍することができます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (475, 25, 23, '看護師', '看護師は、医療機関や福祉施設などで患者の健康管理やケアを行う医療専門職です。患者の状態を観察し、医師の指示に基づいて治療を補助したり、怪我や病気の予防、健康促進を支援します。また、患者やその家族に対する精神的なサポートも提供します。夜勤や不規則勤務がある場合もありますが、やりがいのある職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (476, 25, 23, '医師', '医師は患者の診察、診断、治療を行う専門職です。医師は、内科、外科、精神科などさまざまな専門分野があり、それぞれに応じた専門的な知識と技能が求められます。病院やクリニックで働くほか、研究や教育を行う医師もいます。また、健康相談や予防医学に貢献する役割も果たします。医師は、医学部を卒業し国家試験に合格することが求められ、継続的な教育と免許更新が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (477, 25, 32, '葬祭ディレクター', '葬祭ディレクターは、葬儀やお葬式の全体的なコーディネートや運営を担当する専門職です。遺族の方々に寄り添い、故人の意向や宗教的な習慣を尊重しながら、葬儀が円滑に行われるようサポートします。具体的な業務には、葬儀の計画、会場の手配、式の進行、参列者への案内、遺族への相談対応などがあります。また、地域や文化、宗教によって異なる葬儀スタイルに合わせたサービスを提供することも重要です。葬祭ディレクターは、細やかな気配りや心配り、冷静な判断力が求められる職種です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (478, 28, 26, 'コピーライター', 'コピーライターは、広告やマーケティング活動において、商品の特性やブランドのメッセージを効果的に伝えるために、魅力的で説得力のある文章を作成する専門家です。彼らは企業のマーケティング戦略に基づき、キャッチコピー、商品説明、キャンペーンのスローガンなどを考案します。また、ターゲットオーディエンスの心理を理解し、その購買意欲を引き出すための言葉を選びます。クリエイティブな発想とマーケティングの知識が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (479, 26, 25, '特別支援学校教諭', '特別支援学校教諭は、身体的、精神的、知的または発達に障害のある児童生徒に対して、個別の教育の支援や指導を行います。具体的には、個々のニーズに応じたカリキュラムの作成、個別指導、学習計画の策定、社会適応や生活技能の習得を促す活動を実施します。また、保護者との連携や、他の専門職との協働も重要な役割です。児童生徒の成長を促し、社会での自立を支援することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (480, 32, 29, '消防士', '消防士は、火災の消火や災害に対する救助活動を行う職業です。日常的には訓練や設備の点検整備を行い、いざという時に迅速に対応できるよう準備を整えています。また、救急搬送の支援や地域の防火指導といった、コミュニティの安全を守るための活動も行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (481, 25, 23, 'はり師・きゅう師', 'はり師（鍼師）とは、鍼を用いて人体の特定の部位を刺激することで、病気の治療や健康の改善を図る職業です。はり治療は東洋医学に基づき、経絡というエネルギーの通り道を整えることを目的としています。 きゅう師とは、灸（きゅう）と呼ばれる道具を用いて皮膚に熱刺激を与え、病気の治療や健康の促進を行う職業です。きゅうは、特に東洋医学で使われる伝統的な療法で、身体の自然治癒力を高めることを目的とします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (482, 25, 23, '臨床検査技師', '臨床検査技師は、病院や診療所で患者の血液、尿、その他のサンプルを分析する専門職です。彼らは、診断や治療のために必要なデータを提供することを目的とし、検査機器を操作し、結果を記録および報告します。医師の指示に基づいて行われるこれらの検査は、患者の健康状態を評価するために重要です。また、品質管理や結果の精度を保つためのプロセスも担当します。通常、臨床検査技師は国家資格を取得し、医療機関に勤務します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (483, 25, 23, '獣医師', '獣医師は、動物の健康維持や病気の診断・治療を行う専門職です。彼らは動物の医療を担当し、また飼い主に適切なケア方法を指導することも多いです。病院やクリニックで働く以外に、動物園、水族館、研究機関、食品関連企業などで活躍することもあります。獣医学の博士号を取得し、国家試験に合格することで資格を得ることができます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (484, 31, 28, '国際公務員', '国際公務員は、国際機関や地域機関において、世界的な課題に対処するために働く職業です。主に国連、世界銀行、国際通貨基金、世界保健機関などの国際的な組織で勤務します。彼らは通常、多文化の環境で、多言語を使用し、国際的な協力を促進する役割を果たします。業務内容は政策立案、プロジェクト管理、調査研究、行政管理など多岐にわたり、各国と協力してグローバルな問題解決を目指します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (485, 31, 2, '裁判所事務官', '裁判所事務官は、裁判所において裁判の記録管理やスケジュールの調整、事件のデータ入力、裁判所の会計業務など、裁判所運営に関する事務的な業務を担当する職業です。法律に関する深い知識を持つ必要はないが、正確で迅速な事務処理能力が求められます。また、裁判官や弁護士、一般の人々と円滑なコミュニケーションを取る能力も重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (486, 31, 28, '入国審査官', '入国審査官は、国の出入国管理を担当する職員です。旅行者や移住者のパスポートやビザを確認し、入国の適否を判断します。安全保障や法律に基づき、危険人物や不正行為を阻止するために重要な役割を担っています。通常、空港や港で勤務し、国境の安全を保つための最前線で働いています。良好な判断力、法律知識、コミュニケーション能力が必要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (487, 26, 25, '職業訓練指導員', '職業訓練指導員は、職業訓練施設や企業で働く人々に対し、職業に必要な知識や技術を教える専門家です。彼らはカリキュラムの開発、教育プログラムの実施、および学習者の評価を行います。また、新しい技術や業界のトレンドに関する情報をアップデートし、それに基づいた指導を行います。職業ごとの要求に合わせた訓練を提供し、社会や企業のニーズに応じた実践的なスキルアップを支援します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (488, 36, 36, 'レンジャー（自然保護官', 'レンジャー（自然保護官）は、自然保護区や国立公園、自然公園などの自然環境を管理・保護する職業です。彼らは動植物の生息地の保護、密猟防止、自然環境の維持、保全活動を行います。また、訪問者に対してのガイドや教育活動も行い、自然の重要性と保護の必要性を啓発します。時には、科学的な調査やデータ収集も行い、環境の変化をモニタリングします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (489, 32, 29, '麻薬取締官', '麻薬取締官は、法律に基づき、麻薬や他の違法薬物の流通や使用を防止するための業務を行います。捜査、逮捕、証拠収集など、麻薬関連犯罪の取り締まりを主とし、他の法執行機関と協力して危険薬物の撲滅を図ります。また、薬物の乱用防止の啓発活動も行うことがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (490, 31, 28, '国会議員政策担当秘書', '国会議員政策担当秘書は、日本の立法機関である国会において、国会議員の政策立案や行政に関する業務を補佐する役割を持つ職種です。具体的には、議会での議論や法案作成の資料作成、政策提言の準備、関係者との調整、議員の日程管理、そして選挙活動のサポートなど、多岐にわたる任務を担います。政策に関する知識と調査能力が求められ、国会議員との密接なコミュニケーションが必須です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (491, 26, 25, '美術教師', '美術教師は、学校や教育機関で学生に対して美術の知識や技術を教える専門家です。絵画、彫刻、デザインなどの多様な美術分野を通して、学生の表現力や創造力を育てます。授業計画の作成、教材の準備、生徒の指導・評価も職務の一部であり、芸術文化の理解を深める手助けをします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (492, 31, 28, '政治家', '政治家は、公的な立場から国や地域社会の政策を策定、決定し、実行する役割を担う職業です。立法府や行政府の一員として法律の制定や行政運営に関わることが一般的です。また、選挙を通じて選出されることが多く、国民や住民の声を政治に反映することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (493, 31, 30, '裁判官', '裁判官は、司法制度の中での重要な役割を果たす職業であり、法廷において法律を適用し、案件を公平かつ公正に解決する役割を担っています。裁判官は、民事事件や刑事事件、行政事件を含むさまざまな法的紛争に関する判決を下し、法の支配と正義の実現に寄与します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (494, 1, 36, '林業技士', '林業技士は、森林の管理・保全、木材の伐採・搬出、森林環境の保全活動などを行う職業です。彼らは、持続可能な森林管理を実施するために、植生の管理、土壌の保護、炭素の貯蔵、森林の病害虫対策などを行います。また、林業技士は地域社会と協力し、エコツーリズムや森林に関連する教育プログラムの運営にも関与することがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (495, 32, 29, '刑務官', '刑務官は、刑務所や拘置所などの矯正施設で働く職員であり、受刑者の管理や監督を行う。主な業務として、受刑者の日常生活の監視、施設内での安全確保、規律の維持、教育・更生プログラムの実施が含まれる。受刑者とのコミュニケーションを通じて更生をサポートすることも重要な役割である。勤務は交代制で、昼夜を問わず対応することが求められる場面も多い。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (496, 32, 29, '入国警備官', '入国警備官は、日本の法務省に属し、主に出入国管理や国境警備に従事する職業です。主な業務には、不法滞在者の取り締まり、出入国審査、外国人の在留管理、難民の保護などがあります。入国管理局や空港、港湾などで働くことが一般的です。また、国内外で発生する様々な事案に対して迅速に対応することが求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (497, 36, 21, '公害防止管理者', '公害防止管理者は、企業や工場で発生する大気汚染、水質汚濁、騒音、振動などの公害を防止するための専門家です。この役職は、環境関連法規を遵守し、適切な公害対策を講じることで、周辺環境や住民の健康を守る役割を担います。具体的には、公害の原因となる施設や設備の監視・管理、データの収集・分析、公害防止に関する教育や指導を行います。また、行政との連携や報告業務も重要な業務の一部です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (498, 26, 25, '中学校教諭', '中学校教諭は、主に中学生を対象に学問の指導を行う教育専門職です。担当科目に基づき、カリキュラムを策定し、教室での授業を通じて生徒に知識を伝える役割を担います。また、生徒の学習の進捗を評価し、必要に応じて補習や個別指導を行います。さらに、クラブ活動や行事の指導、生活指導、生徒の悩み相談の受け付けなど、多岐にわたる業務を通じて生徒の成長を支援します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (499, 31, 28, '国税専門官', '国税専門官は、国の税金の適正な課税と徴収を担当する国家公務員です。税務調査を行って不正行為を防止し、法律に基づき正確な課税を実施することを目的としています。業務内容には、税務調査、申告内容の確認、税金の滞納に対する対応などが含まれます。高い法律知識と倫理観が求められる職業であり、日本全国で勤務する可能性があります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (500, 31, 28, '国連スタッフ', '国連スタッフは、国際連合（UN）で働く職員を指します。彼らは、国際的な平和と安全の維持、人道的支援、開発促進、人権保護など、多岐にわたる目的を達成するために様々な役割を担います。国連は世界の異なる場所にオフィスを持っており、スタッフは様々な国籍の人々と共に多文化環境で働く機会があります。ポジションによって職務内容は異なり、行政、技術、専門職、フィールドワークなど多岐にわたるキャリアが存在します。国連スタッフになるためには、一般的に高い専門性や関連する分野の学位、豊富な職務経験、そして多言語能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (501, 36, 22, '環境アセスメント調査員', '環境アセスメント調査員は、開発プロジェクトが環境に及ぼす影響を評価する専門家です。彼らは、通常、環境影響評価（EIA）を行い、様々な環境要因（空気、水、土壌、生物多様性など）を分析します。また、調査結果に基づいて改善策や緩和策を提案し、持続可能な開発をサポートする役割を果たします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (502, 31, 28, '国家公務員Ⅱ種', '国家公務員�U種は、多くの場合、中央政府の各省庁や地方出先機関での業務を担当します。一般的に、法律、経済、行政だけでなく、特定の技術分野に関する専門的な知識を活用し、政策の企画・立案、法律の運用、行政手続きの実施などが含まれます。国家の政策を支える中間的なポジションとして、制度運営や行政管理を担当します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (503, 31, 28, '大使館スタッフ', '大使館スタッフは、外交機関である大使館に勤務し、日本と駐在国との外交関係をサポートする人々です。具体的な職務としては、ビザやパスポートの発行手続き、文化交流イベントの企画運営、安全情報の提供、書類作成や通訳、翻訳業務など多岐にわたります。国際的な環境で働くため、高いコミュニケーション能力や文化的な理解が求められます。この職業は外交官を補佐する役割も含まれ、国際関係の専門知識や語学力が非常に重要です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (504, 31, 28, '外務公務員', '外務公務員は、国の外交関係を担当する公務員で、主に外務省に所属します。彼らの主な職務は、日本と他国との関係を円滑に保つための外交交渉、国際会議の準備と出席、海外での国益の守護、日本人の保護などを含みます。また、外国との情報交換、報告書の作成、言語を活用した通訳業務も行います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (505, 33, 30, '社会保険労務士', '社会保険労務士は、労働法や社会保険に関する専門家として、企業や個人事業主に対して法律の適用や労務管理、社会保険手続きの代行を行います。具体的には、就業規則の作成・変更、労働保険や社会保険の手続き、給与計算、人事制度の構築・改善に関するコンサルティングを行います。また、労働基準監督署や年金事務所との調整役としての役割も担い、労働環境の改善や法令遵守のために貢献します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (506, 17, 31, '宅地建物取引士', '宅地建物取引士（たくちたてものとりひきし）は、不動産取引に関する専門的な資格を有するプロフェッショナルです。この職業は、不動産の売買や賃貸の仲介、契約に関する重要事項の説明を行い、顧客が安心して不動産取引を進められるようサポートします。業務では法律知識や交渉力が求められるため、資格取得には宅地建物取引士試験に合格する必要があります。宅地建物取引士は不動産業界での信頼性と専門性を高める役割を担っています。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (507, 16, 20, 'サッシ工', 'サッシ工とは、建物の窓枠やドア枠を製造、設置する専門職です。主にアルミニウムやスチールを使用したサッシ製品を取り扱い、正確な計測や切断、加工を行い、最終的に建築現場での取り付けも担当します。また、気密性や耐久性を考慮し、最適な製品を提供する必要があります。職場は工場内の作業場から施工現場まで多岐にわたり、手先の器用さや細部への注意力が求められる仕事です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (508, 16, 20, 'ガーデンデザイナー', 'ガーデンデザイナーは、庭園や公園、プライベートガーデンスペースなどの外部景観をデザインする職業です。顧客の要望や環境に合わせて、植物の選定や配置、造園におけるテーマの設定、さらには歩道や家具などのハードスケープの設計も行います。創造性と実用性を兼ね備え、エコロジカルな要素も考慮しながら、装飾的で機能的な庭園空間を創り出します。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (509, 24, 16, 'フードコーディネーター', 'フードコーディネーターは、料理や食事に関するプロジェクトを企画し、料理の彩りや形、プレゼンテーションをデザインする専門職です。栄養価や味覚、見た目だけでなく、食のトレンドやマーケットニーズを考慮して、新しいメニューや食のスタイルを提案する役割を担います。レストランやカフェのメニュー開発、食品や飲料の商品開発、食品イベントの企画など、多岐に渡る分野で活動します。美的センスや企画力、コミュニケーション能力が求められる職業です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (510, 25, 21, '放射線取扱主任者', '放射線取扱主任者は、放射線を扱う施設や機関において、放射線の安全管理や取扱に関する指導、助言を行う役割を果たします。主に、放射線業務従事者の安全の確保、放射線防護のための適切な措置の実施、関連法令の遵守を監督することが求められます。これには、放射線の測定、放射線の遮蔽の確認、施設内における放射線防護教育や訓練の実施も含まれます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (511, 35, 27, 'スタイリスト', 'スタイリストは、ファッションや美容分野で活躍し、顧客の見た目や印象を向上させる仕事です。スタイリストには、ファッションスタイリストとヘアスタイリストなどがあり、それぞれが衣装選びやヘアスタイル作りを専門としています。彼らはトレンドを把握し、個別のニーズや要望に合わせたスタイリングを提供します。顧客の魅力を引き出し、望むイメージを具現化する役割を担います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (512, 2, 36, '海女／海士', '海女（あま）は、主に漁を行うために海に潜る女性たちのことを指し、海士（あま）は男性の海中漁師を指すこともある。彼らは長い歴史を持つ日本の伝統的な漁業者で、特に貝類や海藻、時には海産物を素潜りで採取します。海女は、通常、ウエットスーツを着用せず、または軽装で水中に潜り、特別な装備なしで呼吸を調整しつつ海中で作業を行うのが特徴です。彼らは、特に日本の伊勢志摩地方や三重県、能登半島などで活動しており、文化的・歴史的にも重要な存在です。海女／海士の仕事は、技術的なスキルと高い身体能力、海の知識が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (513, 1, 36, '酪農家', '酪農家は牛乳を生産するために乳牛を飼育し、運営する農家の職業です。主に牛乳の生産・加工、乳牛の健康管理、餌やり、牧場の維持管理を行います。酪農家は農業技術と動物飼育のスキルが必要で、自然との触れ合いが多く、体力を使う仕事です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (514, 1, 36, '家畜人工受精士', '家畜人工受精士は、主に牛や豚などの家畜の繁殖をサポートするために、人工受精技術を用いて受精を実施する専門職です。牛や豚の繁殖計画を立て、生産性向上のために最適な時期を判断し、適切な精液を選び交配を行います。この職業は、家畜の健康管理や生産性の向上に寄与し、畜産業において重要な役割を果たします。また、この仕事には生物学、家畜の病気についての知識が必要であり、正確で慎重な作業が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (515, 26, 25, 'ピアノ講師', 'ピアノ講師は、生徒に対してピアノ演奏の技術や音楽理論を教える職業です。個別またはグループレッスンを通じて、生徒が演奏スキルを向上させ、音楽に対する理解を深めることを目指します。専門的な音楽教育を受けている場合が多く、教える生徒のレベルに応じて指導方法を工夫します。音楽教室や自宅、オンラインなど多様な場所でレッスンを行うことが可能です。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (516, 26, 25, '音楽教師', '音楽教師は、学校や個別指導などの教育機関で音楽を教える専門職です。彼らは、学生に楽器の演奏、音楽理論、声楽、作曲などを指導し、音楽に対する興味と理解を育む役割を果たします。音楽プログラムの企画やコンサートの指導、イベントの運営なども行うことがあります。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (517, 26, 25, '専門学校教員', '専門学校教員は、専門学校において特定の専門分野に関する教育を行う職業です。一般的に、実践的な技能や知識を学生に伝えることで、彼らの即戦力となるスキルセットを育成します。また、カリキュラムの作成や教育内容の改善、学生指導や成績評価なども業務の一部に含まれます。教育方法は座学だけに限らず、実技やグループ活動、プロジェクトベースの学習など多岐にわたり、学生の成長をサポートします。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (518, 19, 31, 'ファンドマネジャー', 'ファンドマネジャーは、投資ファンドの管理を担当する職業です。投資戦略を立て、資産を選別し、投資ポートフォリオを構築・管理します。主な目的は、投資家に対して高いリターンを提供することです。市場動向や経済状況を分析し、リスク管理を行いつつ最適な投資判断を下す役割を担います。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (519, 19, 31, 'テラー', 'テラーは、銀行や金融機関の窓口業務を担当する職業です。顧客の口座開設や振込、預金、現金引き出しなど、直接顧客と対面して行う業務が主な役割です。正確さや顧客対応能力が求められます。');
INSERT INTO jobs (job_id, industry_id, category_id, name, description) VALUES (520, 19, 31, 'ファイナンシャルプランナー', 'ファイナンシャルプランナー（FP）は、個人や企業に対して資産管理、投資、保険、年金、税金などに関する総合的なアドバイスを行う専門職です。クライアントのライフスタイルや将来の目標に応じた資金計画を立て、適切な金融商品やサービスの提案を行います。FPは金融や経済、法律の知識が求められ、資格の取得が必要です。');
